def _encode_part(value: Any) -> bytes:
    if isinstance(value, bytes):
        return value
    if isinstance(value, str):
        return value.encode("utf-8")
    if isinstance(value, int):
        return str(value).encode("ascii")
    return json.dumps(value, sort_keys=True, separators=(",", ":")).encode("utf-8")


def domain_hash(domain: str, *parts: Any, out_len: int = 32) -> str:
    """Domain-separated SHAKE256 hash used for devnet transcripts."""

    shake = hashlib.shake_256()
    shake.update(b"NEBULA-L2-DEVNET\x00")
    shake.update(_encode_part(domain))
    shake.update(b"\x00")
    for part in parts:
        encoded = _encode_part(part)
        shake.update(len(encoded).to_bytes(8, "big"))
        shake.update(encoded)
    return shake.hexdigest(out_len)


def paymaster_caller_commitment(caller_label: str) -> str:
    return domain_hash("PAYMASTER-CALLER", caller_label)


def paymaster_relayer_commitment(relayer_label: str) -> str:
    return domain_hash("PAYMASTER-REFILL-RELAYER", relayer_label)


def paymaster_reward_quote_reporter_commitment(reporter_label: str) -> str:
    return domain_hash("PAYMASTER-REWARD-QUOTE-REPORTER", reporter_label)


def relay_path_policy(relay_path: str) -> str:
    normalized = str(relay_path or "").strip().lower()
    if not normalized or normalized in {"direct", "none"}:
        return "direct"
    if "forced" in normalized:
        return "forced-inclusion"
    if "dandelion" in normalized:
        return "dandelion"
    if "i2p" in normalized:
        return "i2p"
    if "tor" in normalized:
        return "tor"
    if "mix" in normalized:
        return "mixnet"
    return "private-relay"


def relay_path_hop_count(relay_path: str) -> int:
    normalized = str(relay_path or "").strip()
    if not normalized:
        return 0
    compact = (
        normalized
        .replace("->", "-")
        .replace("/", "-")
        .replace(",", "-")
        .replace(":", "-")
    )
    hops = [part for part in compact.split("-") if part.strip()]
    return max(1, len(hops))


def relay_path_commitment(relay_path: str) -> str:
    return domain_hash(
        "RELAY-PATH-COMMITMENT",
        CHAIN_ID,
        relay_path_policy(relay_path),
        relay_path_hop_count(relay_path),
        relay_path,
    )


def relay_path_public_metadata(relay_path: str) -> Dict[str, Any]:
    return {
        "relay_path_policy": relay_path_policy(relay_path),
        "relay_path_hop_count": relay_path_hop_count(relay_path),
        "relay_path_commitment": relay_path_commitment(relay_path),
    }


def prefixed_relay_path_public_metadata(
    relay_path: str,
    field_prefix: str,
) -> Dict[str, Any]:
    return {
        f"{field_prefix}_policy": relay_path_policy(relay_path),
        f"{field_prefix}_hop_count": relay_path_hop_count(relay_path),
        f"{field_prefix}_commitment": relay_path_commitment(relay_path),
    }


def merkle_root(domain: str, leaves: Iterable[Any]) -> str:
    level = [domain_hash(domain + ":leaf", leaf) for leaf in leaves]
    if not level:
        return domain_hash(domain + ":empty")

    while len(level) > 1:
        next_level: List[str] = []
        iterator = iter(level)
        for left in iterator:
            right = next(iterator, left)
            next_level.append(domain_hash(domain + ":node", left, right))
        level = next_level
    return level[0]


def json_size(value: Any) -> int:
    return len(json.dumps(value, sort_keys=True, separators=(",", ":")).encode("utf-8"))


def ceil_div(numerator: int, denominator: int) -> int:
    return (numerator + denominator - 1) // denominator


def crypto_policy_suites() -> List[Dict[str, str]]:
    return [dict(suite) for suite in CRYPTO_POLICY_SUITES]


def crypto_policy_root() -> str:
    return merkle_root(
        "CRYPTO-POLICY",
        [
            {
                "policy_id": CRYPTO_POLICY_ID,
                "policy_version": CRYPTO_POLICY_VERSION,
                "suite": suite,
            }
            for suite in CRYPTO_POLICY_SUITES
        ],
    )


def crypto_test_vectors() -> List[Dict[str, Any]]:
    account_payload = {
        "chain_id": CHAIN_ID,
        "purpose": "account authorization test vector",
        "nonce": 1,
    }
    recovery_payload = {
        "chain_id": CHAIN_ID,
        "purpose": "recovery authorization test vector",
        "nonce": 1,
    }
    committee_keys = (
        account_record("vector-validator-a")["network_public_key"],
        account_record("vector-validator-b")["network_public_key"],
    )
    committee_key_id = merkle_root(
        "MEMPOOL-ML-KEM-COMMITTEE",
        [
            {
                "validator_id": domain_hash("VALIDATOR-ID", key),
                "network_public_key": key,
            }
            for key in committee_keys
        ],
    )
    encrypted_payload_hash = domain_hash(
        "MEMPOOL-ENCRYPTED-PAYLOAD",
        {"kind": "crypto-policy-vector", "amount_commitment": domain_hash("VECTOR-AMOUNT", 1)},
    )
    kem_ciphertext_hash = domain_hash(
        "MEMPOOL-ML-KEM-CIPHERTEXT",
        committee_key_id,
        encrypted_payload_hash,
        "dandelion-stem-fluff",
        0,
    )
    return [
        {
            "name": "account_authorization",
            "domain": "crypto_policy_account_vector",
            "payload": account_payload,
            **sign_authorization(
                "vector-account",
                "crypto_policy_account_vector",
                account_payload,
            ),
        },
        {
            "name": "recovery_authorization",
            "domain": "crypto_policy_recovery_vector",
            "payload": recovery_payload,
            **sign_recovery_authorization(
                "vector-account",
                "crypto_policy_recovery_vector",
                recovery_payload,
            ),
        },
        {
            "name": "ml_kem_mempool_ciphertext",
            "committee_key_id": committee_key_id,
            "encrypted_payload_hash": encrypted_payload_hash,
            "kem_ciphertext_hash": kem_ciphertext_hash,
            **relay_path_public_metadata("dandelion-stem-fluff"),
        },
    ]


def crypto_policy_record(include_test_vectors: bool = True) -> Dict[str, Any]:
    record: Dict[str, Any] = {
        "policy_id": CRYPTO_POLICY_ID,
        "policy_version": CRYPTO_POLICY_VERSION,
        "chain_id": CHAIN_ID,
        "crypto_suite": dict(CRYPTO_SUITE),
        "crypto_policy_root": crypto_policy_root(),
        "suites": crypto_policy_suites(),
    }
    if include_test_vectors:
        record["test_vectors"] = crypto_test_vectors()
    return record


def verify_crypto_policy_state(record: Dict[str, Any]) -> None:
    if "crypto_suite" in record:
        for role, scheme in record["crypto_suite"].items():
            if CRYPTO_SUITE.get(role) != scheme:
                raise ValueError("unsupported crypto suite")
    if "crypto_policy_root" in record and record["crypto_policy_root"] != crypto_policy_root():
        raise ValueError("unsupported crypto policy root")
    if "crypto_policy" in record:
        policy = record["crypto_policy"]
        if policy.get("policy_id") != CRYPTO_POLICY_ID:
            raise ValueError("unsupported crypto policy id")
        if int(policy.get("policy_version", 0)) != CRYPTO_POLICY_VERSION:
            raise ValueError("unsupported crypto policy version")
        if policy.get("crypto_policy_root") != crypto_policy_root():
            raise ValueError("unsupported crypto policy root")


def account_record(label: str) -> Dict[str, str]:
    """Return deterministic devnet account material for a wallet label.

    This is not production key generation. It creates stable mock key material
    so the devnet can enforce signed authorization transcripts without pulling
    in an unaudited PQ signature dependency.
    """

    secret_seed = domain_hash("ACCOUNT-SECRET-SEED", label, out_len=64)
    return {
        "label": label,
        "account_id": domain_hash("ACCOUNT-ID", label),
        "spend_public_key": domain_hash("ACCOUNT-SPEND-PUBLIC", secret_seed, out_len=64),
        "recovery_public_key": domain_hash("ACCOUNT-RECOVERY-PUBLIC", secret_seed, out_len=64),
        "network_public_key": domain_hash("ACCOUNT-NETWORK-PUBLIC", secret_seed, out_len=64),
        "auth_scheme": ACCOUNT_SIGNATURE_SCHEME,
        "auth_implementation": "devnet-mock-not-production-crypto",
        "crypto_policy_root": crypto_policy_root(),
        "crypto_policy_version": str(CRYPTO_POLICY_VERSION),
    }


def _account_secret(label: str) -> str:
    return domain_hash("ACCOUNT-SECRET-SEED", label, out_len=64)


def auth_transcript_hash(domain: str, payload: Dict[str, Any]) -> str:
    return domain_hash(
        "AUTH-TRANSCRIPT",
        CHAIN_ID,
        domain,
        payload,
    )


def sign_authorization(label: str, domain: str, payload: Dict[str, Any]) -> Dict[str, str]:
    transcript_hash = auth_transcript_hash(domain, payload)
    signature = domain_hash(
        "DEVNET-ML-DSA-65-SIGNATURE",
        _account_secret(label),
        transcript_hash,
        out_len=64,
    )
    return {
        "signer_label": label,
        "auth_scheme": ACCOUNT_SIGNATURE_SCHEME,
        "auth_public_key": account_record(label)["spend_public_key"],
        "auth_transcript_hash": transcript_hash,
        "auth_signature": signature,
    }


def verify_authorization(
    label: str,
    domain: str,
    payload: Dict[str, Any],
    auth_scheme: str,
    auth_public_key: str,
    auth_transcript_hash_value: str,
    auth_signature: str,
) -> bool:
    expected = sign_authorization(label, domain, payload)
    return (
        hmac.compare_digest(auth_scheme, expected["auth_scheme"])
        and hmac.compare_digest(auth_public_key, expected["auth_public_key"])
        and hmac.compare_digest(auth_transcript_hash_value, expected["auth_transcript_hash"])
        and hmac.compare_digest(auth_signature, expected["auth_signature"])
    )


def sign_recovery_authorization(
    label: str,
    domain: str,
    payload: Dict[str, Any],
) -> Dict[str, str]:
    transcript_hash = auth_transcript_hash(domain, payload)
    signature = domain_hash(
        "DEVNET-SLH-DSA-SHAKE-128S-SIGNATURE",
        _account_secret(label),
        transcript_hash,
        out_len=64,
    )
    return {
        "recovery_label": label,
        "recovery_scheme": RECOVERY_SIGNATURE_SCHEME,
        "recovery_public_key": account_record(label)["recovery_public_key"],
        "recovery_transcript_hash": transcript_hash,
        "recovery_signature": signature,
    }


def verify_recovery_authorization(
    label: str,
    domain: str,
    payload: Dict[str, Any],
    recovery_scheme: str,
    recovery_public_key: str,
    recovery_transcript_hash: str,
    recovery_signature: str,
) -> bool:
    expected = sign_recovery_authorization(label, domain, payload)
    return (
        hmac.compare_digest(recovery_scheme, expected["recovery_scheme"])
        and hmac.compare_digest(recovery_public_key, expected["recovery_public_key"])
        and hmac.compare_digest(
            recovery_transcript_hash,
            expected["recovery_transcript_hash"],
        )
        and hmac.compare_digest(recovery_signature, expected["recovery_signature"])
    )


@dataclass(frozen=True)
class Asset:
    asset_id: str
    symbol: str
    issuer_policy: str
    supply_policy: str
    privacy_class: str
    metadata_hash: str
    max_supply: int = 0

    def public_record(self) -> Dict[str, Any]:
        return {
            "asset_id": self.asset_id,
            "symbol": self.symbol,
            "issuer_policy": self.issuer_policy,
            "supply_policy": self.supply_policy,
            "privacy_class": self.privacy_class,
            "metadata_hash": self.metadata_hash,
            "max_supply": self.max_supply,
        }

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "Asset":
        return cls(
            asset_id=record["asset_id"],
            symbol=record["symbol"],
            issuer_policy=record["issuer_policy"],
            supply_policy=record["supply_policy"],
            privacy_class=record["privacy_class"],
            metadata_hash=record["metadata_hash"],
            max_supply=int(record.get("max_supply", 0)),
        )


@dataclass(frozen=True)
class AssetSupply:
    asset_id: str
    minted_amount: int = 0
    burned_amount: int = 0

    @property
    def circulating_amount(self) -> int:
        return self.minted_amount - self.burned_amount

    def public_record(self) -> Dict[str, Any]:
        return {
            "asset_id": self.asset_id,
            "minted_amount": self.minted_amount,
            "burned_amount": self.burned_amount,
            "circulating_amount": self.circulating_amount,
        }

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "AssetSupply":
        return cls(
            asset_id=record["asset_id"],
            minted_amount=int(record.get("minted_amount", 0)),
            burned_amount=int(record.get("burned_amount", 0)),
        )


@dataclass(frozen=True)
class Note:
    note_id: str
    owner_view_key: str
    asset_id: str
    amount: int
    blinding: str
    commitment: str

    @classmethod
    def create(cls, owner_view_key: str, asset_id: str, amount: int, nonce: int) -> "Note":
        if amount < 0:
            raise ValueError("note amount must be non-negative")

        blinding = domain_hash("NOTE-BLINDING", owner_view_key, asset_id, amount, nonce)
        commitment = domain_hash(
            "NOTE-COMMITMENT",
            domain_hash("OWNER-COMMITMENT", owner_view_key),
            domain_hash("ASSET-COMMITMENT", asset_id),
            domain_hash("AMOUNT-COMMITMENT", amount, blinding),
        )
        note_id = domain_hash("NOTE-ID", commitment, nonce)
        return cls(
            note_id=note_id,
            owner_view_key=owner_view_key,
            asset_id=asset_id,
            amount=amount,
            blinding=blinding,
            commitment=commitment,
        )

    def wallet_record(self) -> Dict[str, Any]:
        return {
            "note_id": self.note_id,
            "asset_id": self.asset_id,
            "amount": self.amount,
            "commitment": self.commitment,
        }

    def state_record(self) -> Dict[str, Any]:
        return {
            "note_id": self.note_id,
            "owner_view_key": self.owner_view_key,
            "asset_id": self.asset_id,
            "amount": self.amount,
            "blinding": self.blinding,
            "commitment": self.commitment,
        }

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "Note":
        return cls(
            note_id=record["note_id"],
            owner_view_key=record["owner_view_key"],
            asset_id=record["asset_id"],
            amount=int(record["amount"]),
            blinding=record["blinding"],
            commitment=record["commitment"],
        )


@dataclass(frozen=True)
class ViewKeyDisclosure:
    disclosure_id: str
    audience_label: str
    owner_commitment: str
    asset_id: str
    disclosed_at_height: int
    expires_at_height: int
    note_count: int
    note_commitment_root: str
    asset_totals: Dict[str, int]
    notes: Sequence[Dict[str, Any]]
    auth_scheme: str = ACCOUNT_SIGNATURE_SCHEME
    auth_public_key: str = ""
    auth_transcript_hash: str = ""
    auth_signature: str = ""

    def unsigned_record(self) -> Dict[str, Any]:
        return {
            "disclosure_id": self.disclosure_id,
            "audience_label": self.audience_label,
            "owner_commitment": self.owner_commitment,
            "asset_id": self.asset_id,
            "disclosed_at_height": self.disclosed_at_height,
            "expires_at_height": self.expires_at_height,
            "note_count": self.note_count,
            "note_commitment_root": self.note_commitment_root,
            "asset_totals": dict(sorted(self.asset_totals.items())),
        }

    def public_record(self) -> Dict[str, Any]:
        record = self.unsigned_record()
        record.update({
            "auth_scheme": self.auth_scheme,
            "auth_public_key": self.auth_public_key,
            "auth_transcript_hash": self.auth_transcript_hash,
            "auth_signature": self.auth_signature,
        })
        return record

    def audit_record(self, disclosed_view_key: str) -> Dict[str, Any]:
        record = self.public_record()
        record.update({
            "disclosed_view_key": disclosed_view_key,
            "notes": list(self.notes),
        })
        return record

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "ViewKeyDisclosure":
        notes = tuple(
            {
                "note_id": item["note_id"],
                "asset_id": item["asset_id"],
                "amount": int(item["amount"]),
                "commitment": item["commitment"],
            }
            for item in record.get("notes", [])
        )
        return cls(
            disclosure_id=record["disclosure_id"],
            audience_label=record["audience_label"],
            owner_commitment=record["owner_commitment"],
            asset_id=record.get("asset_id", ""),
            disclosed_at_height=int(record["disclosed_at_height"]),
            expires_at_height=int(record["expires_at_height"]),
            note_count=int(record["note_count"]),
            note_commitment_root=record["note_commitment_root"],
            asset_totals={
                str(asset_id): int(amount)
                for asset_id, amount in record.get("asset_totals", {}).items()
            },
            notes=notes,
            auth_scheme=record.get("auth_scheme", ACCOUNT_SIGNATURE_SCHEME),
            auth_public_key=record.get("auth_public_key", ""),
            auth_transcript_hash=record.get("auth_transcript_hash", ""),
            auth_signature=record.get("auth_signature", ""),
        )


