@dataclass(frozen=True)
class PrivacyProof:
    proof_system: str
    public_input_hash: str
    private_witness_hash: str
    proof_root: str

    def public_record(self) -> Dict[str, Any]:
        return {
            "proof_system": self.proof_system,
            "public_input_hash": self.public_input_hash,
            "proof_root": self.proof_root,
        }

    def state_record(self) -> Dict[str, Any]:
        return {
            "proof_system": self.proof_system,
            "public_input_hash": self.public_input_hash,
            "private_witness_hash": self.private_witness_hash,
            "proof_root": self.proof_root,
        }

    @classmethod
    def from_record(cls, record: Dict[str, Any] | None) -> "PrivacyProof | None":
        if record is None:
            return None
        return cls(
            proof_system=record["proof_system"],
            public_input_hash=record["public_input_hash"],
            private_witness_hash=record["private_witness_hash"],
            proof_root=record["proof_root"],
        )


def build_privacy_proof(
    proof_system: str,
    public_inputs: Dict[str, Any],
    private_witnesses: Dict[str, Any],
) -> PrivacyProof:
    public_input_hash = domain_hash("PRIVACY-PUBLIC-INPUTS", public_inputs)
    private_witness_hash = domain_hash("PRIVACY-PRIVATE-WITNESSES", private_witnesses)
    proof_root = domain_hash(
        "PRIVACY-PROOF",
        proof_system,
        public_input_hash,
        private_witness_hash,
    )
    return PrivacyProof(
        proof_system=proof_system,
        public_input_hash=public_input_hash,
        private_witness_hash=private_witness_hash,
        proof_root=proof_root,
    )


def verify_privacy_proof(
    proof: PrivacyProof,
    proof_system: str,
    public_inputs: Dict[str, Any],
    private_witnesses: Dict[str, Any],
) -> bool:
    expected = build_privacy_proof(proof_system, public_inputs, private_witnesses)
    return (
        hmac.compare_digest(proof.proof_system, expected.proof_system)
        and hmac.compare_digest(proof.public_input_hash, expected.public_input_hash)
        and hmac.compare_digest(proof.private_witness_hash, expected.private_witness_hash)
        and hmac.compare_digest(proof.proof_root, expected.proof_root)
    )


