    asset_b_id: str
    lp_asset_id: str
    reserve_a: int
    reserve_b: int
    total_lp: int
    fee_bps: int
    curve: str = "constant_product"

    def public_record(self) -> Dict[str, Any]:
        return {
            "pool_id": self.pool_id,
            "asset_a_id": self.asset_a_id,
            "asset_b_id": self.asset_b_id,
            "lp_asset_id": self.lp_asset_id,
            "reserve_a": self.reserve_a,
            "reserve_b": self.reserve_b,
            "total_lp": self.total_lp,
            "fee_bps": self.fee_bps,
            "curve": self.curve,
        }

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "AmmPool":
        curve = str(record.get("curve", "constant_product")).strip().lower().replace("-", "_")
        if curve not in {"constant_product", "stable"}:
            raise ValueError("unsupported AMM curve")
        return cls(
            pool_id=record["pool_id"],
            asset_a_id=record["asset_a_id"],
            asset_b_id=record["asset_b_id"],
            lp_asset_id=record["lp_asset_id"],
            reserve_a=int(record["reserve_a"]),
            reserve_b=int(record["reserve_b"]),
            total_lp=int(record["total_lp"]),
            fee_bps=int(record["fee_bps"]),
            curve=curve,
        )


