@dataclass(frozen=True)
class AmmRouteSwap:
    pool_ids: Sequence[str]
    spent_note_id: str
    nullifier: str
    asset_path: Sequence[str]
    hop_amounts: Sequence[int]
    amount_in: int
    amount_out: int
    output_notes: Sequence[Note]
    network_fee: int
    encrypted_payload_hash: str
    signer_label: str = ""
    auth_public_key: str = ""
    auth_transcript_hash: str = ""
    auth_signature: str = ""
    auth_scheme: str = ACCOUNT_SIGNATURE_SCHEME
    proof_system: str = "devnet-mock-amm-route-swap-proof"
    privacy_proof: PrivacyProof | None = None

    def auth_domain(self) -> str:
        return "amm_route_swap"

    @property
    def asset_in_id(self) -> str:
        return self.asset_path[0] if self.asset_path else ""

    @property
    def asset_out_id(self) -> str:
        return self.asset_path[-1] if self.asset_path else ""

    def route_root(self) -> str:
        return merkle_root(
            "AMM-ROUTE-HOP",
            [
                {
                    "pool_id": pool_id,
                    "asset_in_id": asset_in_id,
                    "asset_out_id": asset_out_id,
                    "amount_out": amount_out,
                }
                for pool_id, asset_in_id, asset_out_id, amount_out in zip(
                    self.pool_ids,
                    self.asset_path[:-1],
                    self.asset_path[1:],
                    self.hop_amounts,
                )
            ],
        )

    def unsigned_record(self) -> Dict[str, Any]:
        return {
            "kind": "amm_route_swap",
            "pool_ids": list(self.pool_ids),
            "route_hop_count": len(self.pool_ids),
            "route_root": self.route_root(),
            "spent_note_id": self.spent_note_id,
            "nullifier": self.nullifier,
            "asset_path": list(self.asset_path),
            "hop_amounts": list(self.hop_amounts),
            "asset_in_id": self.asset_in_id,
            "asset_out_id": self.asset_out_id,
            "amount_in": self.amount_in,
            "amount_out": self.amount_out,
            "output_commitments": [note.commitment for note in self.output_notes],
            "network_fee": self.network_fee,
            "encrypted_payload_hash": self.encrypted_payload_hash,
            "proof_system": self.proof_system,
            "proof_bundle": self.privacy_proof.public_record() if self.privacy_proof else None,
        }

    def public_record(self) -> Dict[str, Any]:
        record = self.unsigned_record()
        record.pop("spent_note_id")
        record.update({
            "auth_scheme": self.auth_scheme,
            "auth_public_key": self.auth_public_key,
            "auth_transcript_hash": self.auth_transcript_hash,
            "auth_signature": self.auth_signature,
        })
        return record

    def state_record(self) -> Dict[str, Any]:
        return {
            "kind": "amm_route_swap",
            "pool_ids": list(self.pool_ids),
            "spent_note_id": self.spent_note_id,
            "nullifier": self.nullifier,
            "asset_path": list(self.asset_path),
            "hop_amounts": list(self.hop_amounts),
            "amount_in": self.amount_in,
            "amount_out": self.amount_out,
            "output_notes": [note.state_record() for note in self.output_notes],
            "network_fee": self.network_fee,
            "encrypted_payload_hash": self.encrypted_payload_hash,
            "signer_label": self.signer_label,
            "auth_public_key": self.auth_public_key,
            "auth_transcript_hash": self.auth_transcript_hash,
            "auth_signature": self.auth_signature,
            "auth_scheme": self.auth_scheme,
            "proof_system": self.proof_system,
            "proof_bundle": self.privacy_proof.state_record() if self.privacy_proof else None,
        }

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "AmmRouteSwap":
        return cls(
            pool_ids=tuple(record["pool_ids"]),
            spent_note_id=record["spent_note_id"],
            nullifier=record["nullifier"],
            asset_path=tuple(record["asset_path"]),
            hop_amounts=tuple(int(amount) for amount in record["hop_amounts"]),
            amount_in=int(record["amount_in"]),
            amount_out=int(record["amount_out"]),
            output_notes=tuple(Note.from_record(note) for note in record["output_notes"]),
            network_fee=int(record["network_fee"]),
            encrypted_payload_hash=record["encrypted_payload_hash"],
            signer_label=record.get("signer_label", ""),
            auth_public_key=record.get("auth_public_key", ""),
            auth_transcript_hash=record.get("auth_transcript_hash", ""),
            auth_signature=record.get("auth_signature", ""),
            auth_scheme=record.get("auth_scheme", ACCOUNT_SIGNATURE_SCHEME),
            proof_system=record.get("proof_system", "devnet-mock-amm-route-swap-proof"),
            privacy_proof=PrivacyProof.from_record(record.get("proof_bundle")),
        )


