@dataclass(frozen=True)
class AmmSealedBatchSwap:
    pool_id: str
    fills: Sequence[SealedSwapFill]
    asset_in_id: str
    asset_out_id: str
    total_amount_in: int
    total_amount_out: int
    network_fee_total: int
    encrypted_payload_hash: str
    commitment_ids: Sequence[str] = ()
    commitment_reveal_secrets: Sequence[str] = ()
    solver_bid_id: str = ""
    solver_label: str = "sealed-swap-solver"
    proof_system: str = "devnet-mock-sealed-amm-batch-swap-proof"
    privacy_proof: PrivacyProof | None = None

    def intent_root(self) -> str:
        return merkle_root(
            "SEALED-AMM-SWAP-INTENT",
            [fill.intent.public_record() for fill in self.fills],
        )

    def commitment_root(self) -> str:
        return merkle_root("SEALED-SWAP-COMMITMENT-ID", list(self.commitment_ids))

    def output_notes(self) -> tuple[Note, ...]:
        notes: List[Note] = []
        for fill in self.fills:
            notes.append(fill.output_note)
            if fill.change_note:
                notes.append(fill.change_note)
        return tuple(notes)

    def unsigned_record(self) -> Dict[str, Any]:
        return {
            "kind": "sealed_amm_batch_swap",
            "pool_id": self.pool_id,
            "intent_count": len(self.fills),
            "intent_root": self.intent_root(),
            "nullifiers": [fill.intent.nullifier for fill in self.fills],
            "asset_in_id": self.asset_in_id,
            "asset_out_id": self.asset_out_id,
            "total_amount_in": self.total_amount_in,
            "total_amount_out": self.total_amount_out,
            "network_fee_total": self.network_fee_total,
            "commitment_count": len(self.commitment_ids),
            "commitment_root": self.commitment_root(),
            "solver_bid_id": self.solver_bid_id,
            "output_commitments": [note.commitment for note in self.output_notes()],
            "encrypted_payload_hash": self.encrypted_payload_hash,
            "solver_commitment": domain_hash(
                "SEALED-SWAP-SOLVER",
                self.solver_label,
            ),
            "proof_system": self.proof_system,
            "proof_bundle": self.privacy_proof.public_record() if self.privacy_proof else None,
        }

    def public_record(self) -> Dict[str, Any]:
        return self.unsigned_record()

    def state_record(self) -> Dict[str, Any]:
        record = self.unsigned_record()
        record["fills"] = [fill.state_record() for fill in self.fills]
        record["commitment_ids"] = list(self.commitment_ids)
        record["commitment_reveal_secrets"] = list(self.commitment_reveal_secrets)
        record["solver_bid_id"] = self.solver_bid_id
        record["solver_label"] = self.solver_label
        record["proof_bundle"] = (
            self.privacy_proof.state_record() if self.privacy_proof else None
        )
        return record

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "AmmSealedBatchSwap":
        return cls(
            pool_id=record["pool_id"],
            fills=tuple(SealedSwapFill.from_record(fill) for fill in record["fills"]),
            asset_in_id=record["asset_in_id"],
            asset_out_id=record["asset_out_id"],
            total_amount_in=int(record["total_amount_in"]),
            total_amount_out=int(record["total_amount_out"]),
            network_fee_total=int(record["network_fee_total"]),
            encrypted_payload_hash=record["encrypted_payload_hash"],
            commitment_ids=tuple(record.get("commitment_ids", ())),
            commitment_reveal_secrets=tuple(
                record.get("commitment_reveal_secrets", ())
            ),
            solver_bid_id=record.get("solver_bid_id", ""),
            solver_label=record.get("solver_label", "sealed-swap-solver"),
            proof_system=record.get(
                "proof_system",
                "devnet-mock-sealed-amm-batch-swap-proof",
            ),
            privacy_proof=PrivacyProof.from_record(record.get("proof_bundle")),
        )


