@dataclass(frozen=True)
class Contract:
    contract_id: str
    template: str
    code_hash: str
    owner_label: str
    storage: Dict[str, Any]
    fuel_limit: int
    version: int = 1
    asset_balances: Dict[str, int] | None = None
    private_storage: bool = False

    def storage_root(self) -> str:
        return domain_hash("CONTRACT-STORAGE", self.storage)

    def asset_balance_root(self) -> str:
        return domain_hash("CONTRACT-ASSET-BALANCES", self.asset_balances or {})

    def public_record(self) -> Dict[str, Any]:
        record = {
            "contract_id": self.contract_id,
            "template": self.template,
            "code_hash": self.code_hash,
            "owner_label": self.owner_label,
            "private_storage": self.private_storage,
            "storage_root": self.storage_root(),
            "storage_commitment": self.storage_root(),
            "asset_balances": dict(sorted((self.asset_balances or {}).items())),
            "asset_balance_root": self.asset_balance_root(),
            "fuel_limit": self.fuel_limit,
            "version": self.version,
        }
        if not self.private_storage:
            record["storage"] = self.storage
        return record

    def state_record(self) -> Dict[str, Any]:
        record = self.public_record()
        record["storage"] = self.storage
        return record

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "Contract":
        return cls(
            contract_id=record["contract_id"],
            template=record["template"],
            code_hash=record["code_hash"],
            owner_label=record["owner_label"],
            storage=dict(record.get("storage", {})),
            fuel_limit=int(record["fuel_limit"]),
            version=int(record.get("version", 1)),
            asset_balances={
                str(asset_id): int(amount)
                for asset_id, amount in record.get("asset_balances", {}).items()
            },
            private_storage=bool(record.get("private_storage", False)),
        )


