    def public_record(self) -> Dict[str, Any]:
        record = self.unsigned_record()
        record.update({
            "auth_scheme": self.auth_scheme,
            "auth_public_key": self.auth_public_key,
            "auth_transcript_hash": self.auth_transcript_hash,
            "auth_signature": self.auth_signature,
        })
        return record

    def state_record(self) -> Dict[str, Any]:
        record = self.public_record()
        record["relayer_label"] = self.relayer_label
        return record

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "PaymasterRelayerRewardClaimBundle":
        reward_ids = tuple(str(item) for item in record.get("reward_ids", ()))
        default_estimates = NebulaL2Devnet._paymaster_relayer_reward_claim_bundle_estimates(
            len(reward_ids) or 1,
        )
        bundle = cls(
            bundle_id=record["bundle_id"],
            bundle_nonce=int(record["bundle_nonce"]),
            relayer_label=record.get("relayer_label", ""),
            relayer_commitment=record["relayer_commitment"],
            fee_asset_id=record["fee_asset_id"],
            reward_ids=reward_ids,
            claim_note_commitments=tuple(
                str(item) for item in record.get("claim_note_commitments", ())
            ),
            total_claimed_amount=int(record["total_claimed_amount"]),
            claimed_at_height=int(record["claimed_at_height"]),
            expires_at_height=int(record.get("expires_at_height", record["claimed_at_height"])),
            inclusion_deadline_height=int(
                record.get(
                    "inclusion_deadline_height",
                    record.get("expires_at_height", record["claimed_at_height"]),
                )
            ),
            requote_after_height=int(
                record.get("requote_after_height", record["claimed_at_height"])
            ),
            requote_backoff_blocks=int(record.get("requote_backoff_blocks", 0)),
            requote_backoff_score=int(record.get("requote_backoff_score", 0)),
            claimed_at_ms=int(record["claimed_at_ms"]),
            max_bundle_size=int(
                record.get(
                    "max_bundle_size",
                    PAYMASTER_RELAYER_REWARD_CLAIM_BUNDLE_MAX_ITEMS,
                )
            ),
            estimated_fee_units=int(
                record.get("estimated_fee_units", default_estimates["estimated_fee_units"])
            ),
            estimated_proof_bytes=int(
                record.get("estimated_proof_bytes", default_estimates["estimated_proof_bytes"])
            ),
            estimated_da_bytes=int(
                record.get("estimated_da_bytes", default_estimates["estimated_da_bytes"])
            ),
            quote_root=record.get("quote_root", ""),
            bundle_proof_root=record.get("bundle_proof_root", ""),
            auth_scheme=record.get("auth_scheme", ACCOUNT_SIGNATURE_SCHEME),
            auth_public_key=record.get("auth_public_key", ""),
            auth_transcript_hash=record.get("auth_transcript_hash", ""),
            auth_signature=record.get("auth_signature", ""),
        )
        if not bundle.quote_root:
            bundle = replace(bundle, quote_root=bundle.expected_quote_root())
        if not bundle.bundle_proof_root:
            bundle = replace(
                bundle,
                bundle_proof_root=bundle.expected_bundle_proof_root(),
            )
        return bundle


