    quote_asset_id: str
    price_numerator: int
    price_denominator: int
    confidence_bps: int
    round_id: int
    published_at_height: int
    attestations: Sequence[OraclePriceAttestation]

    def unsigned_record(self) -> Dict[str, Any]:
        return {
            "feed_id": self.feed_id,
            "base_asset_id": self.base_asset_id,
            "quote_asset_id": self.quote_asset_id,
            "price_numerator": self.price_numerator,
            "price_denominator": self.price_denominator,
            "confidence_bps": self.confidence_bps,
            "round_id": self.round_id,
            "published_at_height": self.published_at_height,
        }

    def attestation_root(self) -> str:
        return merkle_root(
            "ORACLE-PRICE-ATTESTATION",
            [attestation.public_record() for attestation in self.attestations],
        )

    def public_record(self) -> Dict[str, Any]:
        record = self.unsigned_record()
        record.update({
            "attestation_root": self.attestation_root(),
            "attestation_count": len(self.attestations),
            "attestations": [
                attestation.public_record() for attestation in self.attestations
            ],
        })
        return record

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "OraclePriceFeed":
        return cls(
            feed_id=record["feed_id"],
            base_asset_id=record["base_asset_id"],
            quote_asset_id=record["quote_asset_id"],
            price_numerator=int(record["price_numerator"]),
            price_denominator=int(record["price_denominator"]),
            confidence_bps=int(record.get("confidence_bps", 0)),
            round_id=int(record["round_id"]),
            published_at_height=int(record["published_at_height"]),
            attestations=tuple(
                OraclePriceAttestation.from_record(item)
                for item in record.get("attestations", [])
            ),
        )


