DevnetTransaction = AssetMint | AssetBurn | PrivateTransfer | PrivateTransferBatch | AmmLiquidityAdd | AmmSwap | AmmBatchSwap | AmmRouteSwap | DarkPoolSwap | AmmSealedBatchSwap | BridgeMint | BridgeWithdraw | PaymasterDeposit | ContractCall | ContractCallBatch | ContractDeposit | ContractWithdraw | LendingBorrow | LendingRepay | LendingLiquidation | AccountRotation


def transaction_from_record(record: Dict[str, Any]) -> DevnetTransaction:
    kind = record.get("kind")
    if kind == "asset_mint":
        return AssetMint.from_record(record)
    if kind == "asset_burn":
        return AssetBurn.from_record(record)
    if kind == "private_transfer":
        return PrivateTransfer.from_record(record)
    if kind == "private_transfer_batch":
        return PrivateTransferBatch.from_record(record)
    if kind == "amm_liquidity_add":
        return AmmLiquidityAdd.from_record(record)
    if kind == "amm_swap":
        return AmmSwap.from_record(record)
    if kind == "amm_batch_swap":
        return AmmBatchSwap.from_record(record)
    if kind == "amm_route_swap":
        return AmmRouteSwap.from_record(record)
    if kind == "dark_pool_swap":
        return DarkPoolSwap.from_record(record)
    if kind == "sealed_amm_batch_swap":
        return AmmSealedBatchSwap.from_record(record)
    if kind == "bridge_mint":
        return BridgeMint.from_record(record)
    if kind == "bridge_withdraw":
        return BridgeWithdraw.from_record(record)
    if kind == "paymaster_deposit":
        return PaymasterDeposit.from_record(record)
    if kind == "contract_call":
        return ContractCall.from_record(record)
    if kind == "contract_call_batch":
        return ContractCallBatch.from_record(record)
    if kind == "contract_deposit":
        return ContractDeposit.from_record(record)
    if kind == "contract_withdraw":
        return ContractWithdraw.from_record(record)
    if kind == "lending_borrow":
        return LendingBorrow.from_record(record)
    if kind == "lending_repay":
        return LendingRepay.from_record(record)
    if kind == "lending_liquidation":
        return LendingLiquidation.from_record(record)
    if kind == "account_rotation":
        return AccountRotation.from_record(record)
    raise ValueError(f"unsupported transaction kind: {kind}")


