@dataclass(frozen=True)
class DataAvailabilityRecord:
    block_height: int
    tx_root: str
    payload_hash: str
    shard_size: int
    original_shard_count: int
    parity_shard_count: int
    original_bytes: int
    encoded_bytes: int
    shards: Sequence[DataAvailabilityShard]
    attestations: Sequence[DataAvailabilityAttestation]

    def shard_root(self) -> str:
        return merkle_root(
            "DA-SHARD",
            [shard.public_record() for shard in self.shards],
        )

    def attestation_root(self) -> str:
        return merkle_root(
            "DA-ATTESTATION",
            [attestation.public_record() for attestation in self.attestations],
        )

    def da_root(self) -> str:
        return domain_hash(
            "DA",
            CHAIN_ID,
            self.block_height,
            self.tx_root,
            self.payload_hash,
            self.shard_root(),
            self.attestation_root(),
            self.original_bytes,
            self.encoded_bytes,
        )

    def public_record(self) -> Dict[str, Any]:
        return {
            "block_height": self.block_height,
            "tx_root": self.tx_root,
            "payload_hash": self.payload_hash,
            "da_root": self.da_root(),
            "shard_root": self.shard_root(),
            "attestation_root": self.attestation_root(),
            "shard_size": self.shard_size,
            "original_shard_count": self.original_shard_count,
            "parity_shard_count": self.parity_shard_count,
            "shard_count": len(self.shards),
            "original_bytes": self.original_bytes,
            "encoded_bytes": self.encoded_bytes,
            "attestation_count": len(self.attestations),
            "validator_stake_weight": sum(
                attestation.validator_stake for attestation in self.attestations
            ),
            "shards": [shard.public_record() for shard in self.shards],
            "attestations": [
                attestation.public_record() for attestation in self.attestations
            ],
        }

    def state_record(self) -> Dict[str, Any]:
        record = self.public_record()
        record["shards"] = [shard.state_record() for shard in self.shards]
        return record

    @classmethod
    def from_record(cls, record: Dict[str, Any]) -> "DataAvailabilityRecord":
        return cls(
            block_height=int(record["block_height"]),
            tx_root=record["tx_root"],
            payload_hash=record["payload_hash"],
            shard_size=int(record["shard_size"]),
            original_shard_count=int(record["original_shard_count"]),
            parity_shard_count=int(record["parity_shard_count"]),
            original_bytes=int(record["original_bytes"]),
            encoded_bytes=int(record["encoded_bytes"]),
            shards=tuple(
                DataAvailabilityShard.from_record(shard)
                for shard in record.get("shards", [])
            ),
            attestations=tuple(
                DataAvailabilityAttestation.from_record(attestation)
                for attestation in record.get("attestations", [])
            ),
        )


