class NebulaL2Devnet:
    """In-memory note ledger for fast L2 protocol experiments."""

    def __init__(self, epoch_size: int = 10) -> None:
        if epoch_size <= 0:
            raise ValueError("epoch_size must be positive")
        self.epoch_size = epoch_size
        self.assets: Dict[str, Asset] = {}
        self.asset_supplies: Dict[str, AssetSupply] = {}
        self.notes: Dict[str, Note] = {}
        self.pools: Dict[str, AmmPool] = {}
        self.sealed_swap_settlement_receipts: Dict[str, SealedSwapSettlementReceipt] = {}
        self.sealed_swap_order_commitments: Dict[str, SealedSwapOrderCommitment] = {}
        self.sealed_swap_solver_bids: Dict[str, SealedSwapSolverBid] = {}
        self.lending_markets: Dict[str, LendingMarket] = {}
        self.lending_positions: Dict[str, LendingPosition] = {}
        self.oracle_prices: Dict[str, OraclePriceFeed] = {}
        self.contracts: Dict[str, Contract] = {}
        self.contract_upgrade_proposals: Dict[str, ContractUpgradeProposal] = {}
        self.contract_events: Dict[str, ContractEvent] = {}
        self.contract_execution_receipts: Dict[str, ContractExecutionReceipt] = {}
        self.paymasters: Dict[str, Paymaster] = {}
        self.paymaster_governance_actions: Dict[str, PaymasterGovernanceAction] = {}
        self.paymaster_refill_authorizations: Dict[str, PaymasterRefillAuthorization] = {}
        self.paymaster_refill_failures: Dict[str, PaymasterRefillFailureReceipt] = {}
        self.paymaster_refill_challenges: Dict[str, PaymasterRefillFailureChallenge] = {}
        self.paymaster_relayer_slashing_hooks: Dict[str, PaymasterRelayerSlashingHook] = {}
        self.paymaster_relayer_bonds: Dict[str, PaymasterRelayerBond] = {}
        self.paymaster_relayer_slash_settlements: Dict[
            str,
            PaymasterRelayerSlashSettlement,
        ] = {}
        self.paymaster_relayer_unbond_requests: Dict[
            str,
            PaymasterRelayerUnbondRequest,
        ] = {}
        self.paymaster_relayer_reward_receipts: Dict[
            str,
            PaymasterRelayerRewardReceipt,
        ] = {}
        self.paymaster_relayer_reward_claim_bundles: Dict[
            str,
            PaymasterRelayerRewardClaimBundle,
        ] = {}
        self.paymaster_relayer_reward_quote_invalidations: Dict[
            str,
            PaymasterRelayerRewardQuoteInvalidationReport,
        ] = {}
        self.accounts: Dict[str, AccountState] = {}
        self.wallet_sessions: Dict[str, WalletSession] = {}
        self.retired_account_labels: set[str] = set()
        self.wrapped_xmr_asset_id: str | None = None
        self.bridge_deposit_addresses: Dict[str, BridgeDepositAddress] = {}
        self.bridge_observations: Dict[str, BridgeDepositObservation] = {}
        self.bridge_withdrawals: Dict[str, BridgeWithdrawalRecord] = {}
        self.bridge_withdrawal_challenges: Dict[str, BridgeWithdrawalChallenge] = {}
        self.bridge_signer_sets: Dict[str, BridgeSignerSet] = {}
        self.active_bridge_signer_set_id: str = ""
        self.bridge_reserve_reports: Dict[str, BridgeReserveReport] = {}
        self.bridge_emergency_actions: Dict[str, BridgeEmergencyAction] = {}
        self.bridge_paused: bool = False
        self.bridge_pause_reason_hash: str = ""
        self.bridge_pause_action_id: str = ""
        self.anchor_submissions: Dict[str, AnchorSubmission] = {}
        self.da_records: Dict[int, DataAvailabilityRecord] = {}
        self.privacy_proof_aggregates: Dict[int, BlockPrivacyProofAggregate] = {}
        self.validity_certificates: Dict[int, BlockValidityCertificate] = {}
        self.block_audit_reports: Dict[str, BlockWatchtowerAuditReport] = {}
        self.block_challenge_reports: Dict[str, BlockChallengeReport] = {}
        self.validators: Dict[str, Validator] = {}
        self.spent_nullifiers: set[str] = set()
        self.pending: List[DevnetTransaction] = []
        self.pending_admissions: List[MempoolAdmission] = []
        self.mempool_preconfirmations: Dict[str, MempoolPreconfirmation] = {}
        self.mempool_preconfirmation_misses: Dict[str, MempoolPreconfirmationMissEvidence] = {}
        self.mempool_omission_evidence: Dict[str, MempoolOmissionEvidence] = {}
        self.mempool_forced_inclusions: Dict[str, MempoolForcedInclusion] = {}
        self.mempool_omission_recovery_txs: Dict[str, DevnetTransaction] = {}
        self.blocks: List[L2Block] = []
        self.performance_benchmarks: Dict[str, PerformanceBenchmarkRun] = {}
        self.performance_calibrations: Dict[str, PerformanceCalibrationRecord] = {}
        self.fees_collected: Dict[str, int] = {}
        self._nonce = 0
        self.register_validator("devnet-proposer", stake=1_000)
        self.rotate_bridge_signer_set(
            signer_labels=DEFAULT_BRIDGE_SIGNER_LABELS,
            threshold=2,
            operator_label="bridge-guardian",
        )

    def _next_nonce(self) -> int:
        self._nonce += 1
        return self._nonce

    def _note_nullifier(self, note: Note) -> str:
        return domain_hash("NULLIFIER", note.note_id, note.owner_view_key)

    def _transaction_public_hash(self, tx: DevnetTransaction) -> str:
        return domain_hash("TX-PUBLIC", tx.public_record())

    def _mempool_transaction_public_hash(self, tx: DevnetTransaction) -> str:
        return domain_hash("MEMPOOL-TX-PUBLIC", tx.public_record())

    def _mempool_committee_key_id(self) -> str:
        return merkle_root(
            "MEMPOOL-ML-KEM-COMMITTEE",
            [
                {
                    "validator_id": validator.validator_id,
                    "network_public_key": validator.network_public_key,
                }
                for validator in self._active_validators()
            ],
        )

    def _mempool_admission_unsigned_record(
        self,
        tx: DevnetTransaction,
        mempool_sequence: int,
        relay_path: str,
        admitted_at_height: int,
        expires_at_height: int,
        sequencer_label: str,
        committee_key_id: Optional[str] = None,
    ) -> Dict[str, Any]:
        tx_public_hash = domain_hash("MEMPOOL-TX-PUBLIC", tx.public_record())
        encrypted_payload_hash = domain_hash("MEMPOOL-ENCRYPTED-PAYLOAD", tx.state_record())
        committee_key_id = committee_key_id or self._mempool_committee_key_id()
        kem_ciphertext_hash = domain_hash(
            "MEMPOOL-ML-KEM-CIPHERTEXT",
            committee_key_id,
            encrypted_payload_hash,
            relay_path,
            mempool_sequence,
        )
        admission_id = domain_hash(
            "MEMPOOL-ADMISSION-ID",
            CHAIN_ID,
            tx_public_hash,
            kem_ciphertext_hash,
            admitted_at_height,
            mempool_sequence,
        )
        record = {
            "admission_id": admission_id,
            "mempool_sequence": mempool_sequence,
            "tx_public_hash": tx_public_hash,
            "encrypted_payload_hash": encrypted_payload_hash,
            "committee_key_id": committee_key_id,
            "kem_ciphertext_hash": kem_ciphertext_hash,
            "admitted_at_height": admitted_at_height,
            "expires_at_height": expires_at_height,
            "sequencer_label": sequencer_label,
        }
        record.update(relay_path_public_metadata(relay_path))
        return record

    def _build_mempool_admission(
        self,
        tx: DevnetTransaction,
        mempool_sequence: int,
        relay_path: str = "dandelion-stem-fluff",
        sequencer_label: str = "devnet-proposer",
    ) -> MempoolAdmission:
        admitted_at_height = len(self.blocks)
        expires_at_height = admitted_at_height + max(2, self.epoch_size)
        unsigned = self._mempool_admission_unsigned_record(
            tx,
            mempool_sequence=mempool_sequence,
            relay_path=relay_path,
            admitted_at_height=admitted_at_height,
            expires_at_height=expires_at_height,
            sequencer_label=sequencer_label,
        )
        auth = sign_authorization(sequencer_label, "mempool_admission", unsigned)
        return MempoolAdmission(
            admission_id=unsigned["admission_id"],
            mempool_sequence=unsigned["mempool_sequence"],
            tx_public_hash=unsigned["tx_public_hash"],
            encrypted_payload_hash=unsigned["encrypted_payload_hash"],
            committee_key_id=unsigned["committee_key_id"],
            kem_ciphertext_hash=unsigned["kem_ciphertext_hash"],
            relay_path=relay_path,
            admitted_at_height=unsigned["admitted_at_height"],
            expires_at_height=unsigned["expires_at_height"],
            sequencer_label=unsigned["sequencer_label"],
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )

    def _build_mempool_preconfirmation(
        self,
        admission: MempoolAdmission,
    ) -> MempoolPreconfirmation:
        preconfirmed_at_height = len(self.blocks)
        target_height = preconfirmed_at_height
        promised_mempool_root = self.mempool_admission_root()
        preconfirmation_id = domain_hash(
            "MEMPOOL-PRECONFIRMATION-ID",
            CHAIN_ID,
            admission.admission_id,
            admission.tx_public_hash,
            target_height,
            promised_mempool_root,
        )
        unsigned = MempoolPreconfirmation(
            preconfirmation_id=preconfirmation_id,
            admission_id=admission.admission_id,
            tx_public_hash=admission.tx_public_hash,
            encrypted_payload_hash=admission.encrypted_payload_hash,
            target_height=target_height,
            expires_at_height=admission.expires_at_height,
            preconfirmed_at_height=preconfirmed_at_height,
            sequencer_label=admission.sequencer_label,
            promised_mempool_root=promised_mempool_root,
            promised_pending_tx_count=len(self.pending),
            local_fee_market_root=self.pending_execution_profile().local_fee_market_root,
        )
        auth = sign_authorization(
            admission.sequencer_label,
            "mempool_preconfirmation",
            unsigned.unsigned_record(),
        )
        return replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )

    def _verify_mempool_admission(
        self,
        tx: DevnetTransaction,
        admission: MempoolAdmission,
        allow_expired: bool = False,
    ) -> None:
        if not allow_expired and len(self.blocks) > admission.expires_at_height:
            raise ValueError("mempool admission expired")
        expected = self._mempool_admission_unsigned_record(
            tx,
            mempool_sequence=admission.mempool_sequence,
            relay_path=admission.relay_path,
            admitted_at_height=admission.admitted_at_height,
            expires_at_height=admission.expires_at_height,
            sequencer_label=admission.sequencer_label,
            committee_key_id=admission.committee_key_id,
        )
        if expected != admission.unsigned_record():
            raise ValueError("mempool admission does not match transaction")
        if not verify_authorization(
            admission.sequencer_label,
            "mempool_admission",
            admission.unsigned_record(),
            admission.auth_scheme,
            admission.auth_public_key,
            admission.auth_transcript_hash,
            admission.auth_signature,
        ):
            raise ValueError("invalid mempool admission authorization")

    def _verify_mempool_preconfirmation(
        self,
        preconfirmation: MempoolPreconfirmation,
    ) -> None:
        if preconfirmation.target_height < preconfirmation.preconfirmed_at_height:
            raise ValueError("mempool preconfirmation target is before receipt height")
        if preconfirmation.expires_at_height < preconfirmation.target_height:
            raise ValueError("mempool preconfirmation target exceeds admission expiry")
        if not verify_authorization(
            preconfirmation.sequencer_label,
            "mempool_preconfirmation",
            preconfirmation.unsigned_record(),
            preconfirmation.auth_scheme,
            preconfirmation.auth_public_key,
            preconfirmation.auth_transcript_hash,
            preconfirmation.auth_signature,
        ):
            raise ValueError("invalid mempool preconfirmation authorization")

    def _verify_mempool_preconfirmation_miss(
        self,
        evidence: MempoolPreconfirmationMissEvidence,
    ) -> None:
        if evidence.missed_block_count <= 0:
            raise ValueError("mempool preconfirmation miss count must be positive")
        if evidence.penalty_units <= 0:
            raise ValueError("mempool preconfirmation miss penalty must be positive")
        if not verify_authorization(
            evidence.reporter_label,
            "mempool_preconfirmation_miss_evidence",
            evidence.unsigned_record(),
            evidence.auth_scheme,
            evidence.auth_public_key,
            evidence.auth_transcript_hash,
            evidence.auth_signature,
        ):
            raise ValueError("invalid mempool preconfirmation miss authorization")

    def _verify_pending_mempool_admissions(
        self,
        txs: Sequence[DevnetTransaction],
    ) -> None:
        if len(txs) != len(self.pending_admissions):
            raise ValueError("pending mempool admission count mismatch")
        for tx, admission in zip(txs, self.pending_admissions):
            self._verify_mempool_admission(tx, admission)

    def _queue_transaction(
        self,
        tx: DevnetTransaction,
        relay_path: str = "dandelion-stem-fluff",
        sequencer_label: str = "devnet-proposer",
    ) -> DevnetTransaction:
        if isinstance(tx, AmmSealedBatchSwap) and tx.commitment_ids:
            already_pending = self._pending_sealed_swap_commitment_ids()
            duplicate_ids = already_pending.intersection(tx.commitment_ids)
            if duplicate_ids:
                raise ValueError("sealed swap commitment already pending reveal")
        if len(self.pending_admissions) > len(self.pending):
            self.pending_admissions = self.pending_admissions[:len(self.pending)]
        self.pending.append(tx)
        admission = self._build_mempool_admission(
            tx,
            len(self.pending_admissions),
            relay_path=relay_path,
            sequencer_label=sequencer_label,
        )
        self.pending_admissions.append(admission)
        preconfirmation = self._build_mempool_preconfirmation(admission)
        self._verify_mempool_preconfirmation(preconfirmation)
        self.mempool_preconfirmations[
            preconfirmation.preconfirmation_id
        ] = preconfirmation
        return tx

    def mempool_admission_root(self) -> str:
        return merkle_root(
            "MEMPOOL-ADMISSION",
            [admission.public_record() for admission in self.pending_admissions],
        )

    def mempool_preconfirmation_root(self) -> str:
        return merkle_root(
            "MEMPOOL-PRECONFIRMATION",
            [
                preconfirmation.public_record()
                for preconfirmation in sorted(
                    self.mempool_preconfirmations.values(),
                    key=lambda item: item.preconfirmation_id,
                )
            ],
        )

    def mempool_preconfirmation_miss_root(self) -> str:
        return merkle_root(
            "MEMPOOL-PRECONFIRMATION-MISS-EVIDENCE",
            [
                evidence.public_record()
                for evidence in sorted(
                    self.mempool_preconfirmation_misses.values(),
                    key=lambda item: item.evidence_id,
                )
            ],
        )

    def mempool_omission_evidence_root(self) -> str:
        return merkle_root(
            "MEMPOOL-OMISSION-EVIDENCE",
            [
                evidence.public_record()
                for evidence in sorted(
                    self.mempool_omission_evidence.values(),
                    key=lambda item: item.evidence_id,
                )
            ],
        )

    def mempool_forced_inclusion_root(self) -> str:
        return merkle_root(
            "MEMPOOL-FORCED-INCLUSION",
            [
                forced.public_record()
                for forced in sorted(
                    self.mempool_forced_inclusions.values(),
                    key=lambda item: item.forced_inclusion_id,
                )
            ],
        )

    def _forced_inclusions_for_admission(
        self,
        admission_id: str,
    ) -> Tuple[MempoolForcedInclusion, ...]:
        return tuple(
            sorted(
                (
                    item
                    for item in self.mempool_forced_inclusions.values()
                    if item.admission_id == admission_id
                ),
                key=lambda item: item.forced_inclusion_id,
            )
        )

    def _verify_mempool_forced_inclusion(
        self,
        forced: MempoolForcedInclusion,
    ) -> None:
        if forced.evidence_id not in self.mempool_omission_evidence:
            raise ValueError("forced inclusion references unknown omission evidence")
        evidence = self.mempool_omission_evidence[forced.evidence_id]
        if forced.admission_id != evidence.admission_id:
            raise ValueError("forced inclusion admission mismatch")
        if forced.tx_public_hash != evidence.tx_public_hash:
            raise ValueError("forced inclusion tx hash mismatch")
        if forced.old_encrypted_payload_hash != evidence.encrypted_payload_hash:
            raise ValueError("forced inclusion old payload hash mismatch")
        if not forced.new_relay_path:
            raise ValueError("forced inclusion relay path is required")
        expected_id = domain_hash(
            "MEMPOOL-FORCED-INCLUSION-ID",
            CHAIN_ID,
            forced.evidence_id,
            forced.admission_id,
            forced.new_admission_id,
            forced.forced_at_height,
            forced.sequencer_label,
        )
        if forced.forced_inclusion_id != expected_id:
            raise ValueError("forced inclusion id mismatch")
        if not verify_authorization(
            forced.sequencer_label,
            "mempool_forced_inclusion",
            forced.unsigned_record(),
            forced.auth_scheme,
            forced.auth_public_key,
            forced.auth_transcript_hash,
            forced.auth_signature,
        ):
            raise ValueError("invalid forced inclusion authorization")

    def _decode_data_availability_payload(
        self,
        record: DataAvailabilityRecord,
    ) -> Dict[str, Any]:
        payload = "".join(
            shard.data
            for shard in sorted(record.shards, key=lambda item: item.shard_index)
            if shard.shard_kind == "data"
        )
        if not hmac.compare_digest(
            domain_hash("DA-PAYLOAD", payload),
            record.payload_hash,
        ):
            raise ValueError("DA payload hash mismatch")
        return json.loads(payload)

    def _admission_inclusion_height(self, admission_id: str) -> int | None:
        for record in sorted(self.da_records.values(), key=lambda item: item.block_height):
            payload = self._decode_data_availability_payload(record)
            if any(
                admission.get("admission_id") == admission_id
                for admission in payload.get("mempool_admissions", [])
            ):
                return record.block_height
        return None

    def _preconfirmations_for_admission(
        self,
        admission_id: str,
    ) -> Tuple[MempoolPreconfirmation, ...]:
        return tuple(
            sorted(
                (
                    item
                    for item in self.mempool_preconfirmations.values()
                    if item.admission_id == admission_id
                ),
                key=lambda item: item.preconfirmation_id,
            )
        )

    def _preconfirmation_misses_for_admission(
        self,
        admission_id: str,
    ) -> Tuple[MempoolPreconfirmationMissEvidence, ...]:
        return tuple(
            sorted(
                (
                    item
                    for item in self.mempool_preconfirmation_misses.values()
                    if item.admission_id == admission_id
                ),
                key=lambda item: item.evidence_id,
            )
        )

    def _preconfirmation_status_record(
        self,
        preconfirmation: MempoolPreconfirmation,
        inclusion_height: int | None,
    ) -> Dict[str, Any]:
        current_height = len(self.blocks)
        misses = [
            evidence.public_record()
            for evidence in sorted(
                self.mempool_preconfirmation_misses.values(),
                key=lambda item: item.evidence_id,
            )
            if evidence.preconfirmation_id == preconfirmation.preconfirmation_id
        ]
        if inclusion_height is not None:
            status = (
                "fulfilled"
                if inclusion_height <= preconfirmation.target_height
                else "missed_included_late"
            )
        elif misses:
            status = "miss_reported"
        elif current_height > preconfirmation.target_height:
            status = "target_missed"
        else:
            status = "preconfirmed"
        return {
            "status": status,
            "current_height": current_height,
            "inclusion_height": inclusion_height,
            "blocks_until_target": max(0, preconfirmation.target_height - current_height + 1),
            "preconfirmation": preconfirmation.public_record(),
            "miss_evidence": misses,
        }

    def mempool_admission_status(self, admission_id: str) -> Dict[str, Any]:
        if not admission_id:
            raise ValueError("admission_id is required")
        current_height = len(self.blocks)
        inclusion_height = self._admission_inclusion_height(admission_id)
        for admission in self.pending_admissions:
            if admission.admission_id == admission_id:
                preconfirmations = [
                    self._preconfirmation_status_record(item, inclusion_height)
                    for item in self._preconfirmations_for_admission(admission_id)
                ]
                return {
                    "status": "pending",
                    "admission_id": admission_id,
                    "current_height": current_height,
                    "admitted_at_height": admission.admitted_at_height,
                    "expires_at_height": admission.expires_at_height,
                    "blocks_until_expiry": max(
                        0,
                        admission.expires_at_height - current_height + 1,
                    ),
                    "admission": admission.public_record(),
                    "preconfirmations": preconfirmations,
                    "mempool_preconfirmation_root": self.mempool_preconfirmation_root(),
                    "mempool_preconfirmation_miss_root": self.mempool_preconfirmation_miss_root(),
                    "mempool_admission_root": self.mempool_admission_root(),
                    "mempool_omission_evidence_root": self.mempool_omission_evidence_root(),
                    "mempool_forced_inclusion_root": self.mempool_forced_inclusion_root(),
                }

        for evidence in sorted(
            self.mempool_omission_evidence.values(),
            key=lambda item: item.evidence_id,
        ):
            if evidence.admission_id == admission_id:
                preconfirmations = [
                    self._preconfirmation_status_record(item, inclusion_height)
                    for item in self._preconfirmations_for_admission(admission_id)
                ]
                return {
                    "status": "omitted",
                    "admission_id": admission_id,
                    "current_height": current_height,
                    "evidence_status": evidence.status,
                    "evidence": evidence.public_record(),
                    "forced_inclusion_count": len(
                        self._forced_inclusions_for_admission(admission_id)
                    ),
                    "forced_inclusions": [
                        item.public_record()
                        for item in self._forced_inclusions_for_admission(admission_id)
                    ],
                    "preconfirmations": preconfirmations,
                    "preconfirmation_miss_evidence": [
                        item.public_record()
                        for item in self._preconfirmation_misses_for_admission(admission_id)
                    ],
                    "mempool_preconfirmation_root": self.mempool_preconfirmation_root(),
                    "mempool_preconfirmation_miss_root": self.mempool_preconfirmation_miss_root(),
                    "mempool_omission_evidence_root": self.mempool_omission_evidence_root(),
                    "mempool_forced_inclusion_root": self.mempool_forced_inclusion_root(),
                }

        for record in sorted(self.da_records.values(), key=lambda item: item.block_height):
            payload = self._decode_data_availability_payload(record)
            for admission in payload.get("mempool_admissions", []):
                if admission.get("admission_id") == admission_id:
                    preconfirmations = [
                        self._preconfirmation_status_record(item, record.block_height)
                        for item in self._preconfirmations_for_admission(admission_id)
                    ]
                    block_hash = (
                        self.blocks[record.block_height].header.block_hash()
                        if record.block_height < len(self.blocks)
                        else ""
                    )
                    return {
                        "status": "included",
                        "admission_id": admission_id,
                        "current_height": current_height,
                        "block_height": record.block_height,
                        "block_hash": block_hash,
                        "tx_root": record.tx_root,
                        "da_root": record.da_root(),
                        "payload_hash": record.payload_hash,
                        "mempool_admission_root": payload["mempool_admission_root"],
                        "mempool_admission_count": payload["mempool_admission_count"],
                        "admission": admission,
                        "preconfirmations": preconfirmations,
                        "preconfirmation_miss_evidence": [
                            item.public_record()
                            for item in self._preconfirmation_misses_for_admission(admission_id)
                        ],
                        "mempool_preconfirmation_root": self.mempool_preconfirmation_root(),
                        "mempool_preconfirmation_miss_root": self.mempool_preconfirmation_miss_root(),
                        "mempool_forced_inclusion_root": self.mempool_forced_inclusion_root(),
                        "settlement": self.settlement_status(record.block_height),
                    }

        raise ValueError("unknown mempool admission")

    def transaction_status(self, tx_hash: str) -> Dict[str, Any]:
        if not tx_hash:
            raise ValueError("tx_hash is required")
        current_height = len(self.blocks)

        for pending_index, tx in enumerate(self.pending):
            public_record = tx.public_record()
            tx_public_hash = self._transaction_public_hash(tx)
            mempool_tx_public_hash = self._mempool_transaction_public_hash(tx)
            if tx_hash not in {tx_public_hash, mempool_tx_public_hash}:
                continue
            admission = None
            if pending_index < len(self.pending_admissions):
                candidate = self.pending_admissions[pending_index]
                if candidate.tx_public_hash == mempool_tx_public_hash:
                    admission = candidate
            preconfirmations = (
                [
                    self._preconfirmation_status_record(item, None)
                    for item in self._preconfirmations_for_admission(admission.admission_id)
                ]
                if admission
                else []
            )
            return {
                "status": "pending",
                "inclusion_status": "pending",
                "current_height": current_height,
                "pending_index": pending_index,
                "tx_public_hash": tx_public_hash,
                "mempool_tx_public_hash": mempool_tx_public_hash,
                "tx_kind": public_record.get("kind", ""),
                "transaction": public_record,
                "mempool_admission": admission.public_record() if admission else None,
                "preconfirmations": preconfirmations,
                "mempool_admission_root": self.mempool_admission_root(),
                "mempool_preconfirmation_root": self.mempool_preconfirmation_root(),
                "settlement": None,
            }

        for block in self.blocks:
            for tx_index, tx in enumerate(block.transactions):
                public_record = tx.public_record()
                tx_public_hash = self._transaction_public_hash(tx)
                mempool_tx_public_hash = self._mempool_transaction_public_hash(tx)
                if tx_hash not in {tx_public_hash, mempool_tx_public_hash}:
                    continue
                height = block.header.height
                settlement = self.settlement_status(height)
                certificate = self.validity_certificates.get(height)
                aggregate = self.privacy_proof_aggregates.get(height)
                proof_item = None
                if aggregate:
                    proof_item = next(
                        (
                            item
                            for item in aggregate.proof_items
                            if int(item.get("tx_index", -1)) == tx_index
                        ),
                        None,
                    )
                return {
                    "status": settlement["status"],
                    "inclusion_status": "included",
                    "current_height": current_height,
                    "block_height": height,
                    "tx_index": tx_index,
                    "tx_public_hash": tx_public_hash,
                    "mempool_tx_public_hash": mempool_tx_public_hash,
                    "tx_kind": public_record.get("kind", ""),
                    "transaction": public_record,
                    "block_hash": block.header.block_hash(),
                    "tx_root": block.header.tx_root,
                    "state_root": block.header.state_root,
                    "da_root": block.header.da_root,
                    "validity_certificate_root": (
                        certificate.certificate_root() if certificate else ""
                    ),
                    "privacy_proof_aggregate_root": (
                        aggregate.aggregate_root() if aggregate else ""
                    ),
                    "privacy_proof_item": proof_item,
                    "settlement": settlement,
                }

        raise ValueError("unknown transaction")

    def report_mempool_omission(
        self,
        admission_id: str,
        reporter_label: str = "watchtower",
    ) -> MempoolOmissionEvidence:
        if not reporter_label:
            raise ValueError("reporter label is required")
        evidence_index = next(
            (
                index
                for index, admission in enumerate(self.pending_admissions)
                if admission.admission_id == admission_id
            ),
            None,
        )
        if evidence_index is None:
            raise ValueError("unknown mempool admission")
        admission = self.pending_admissions[evidence_index]
        tx = self.pending[evidence_index]
        self._verify_mempool_admission(tx, admission, allow_expired=True)
        if len(self.blocks) <= admission.expires_at_height:
            raise ValueError("mempool admission has not expired")

        missed_block_count = len(self.blocks) - admission.expires_at_height
        penalty_units = max(1, missed_block_count)
        slashed_validator = next(
            (
                validator
                for validator in self.validators.values()
                if validator.label == admission.sequencer_label
            ),
            None,
        )
        slashed_validator_id = ""
        slashed_amount = 0
        validator_stake_after = 0
        evidence_status = "unbonded_sequencer"
        if slashed_validator is not None:
            slashed_validator_id = slashed_validator.validator_id
            slashed_amount = min(slashed_validator.stake, penalty_units)
            validator_stake_after = slashed_validator.stake - slashed_amount
            self.validators[slashed_validator.validator_id] = replace(
                slashed_validator,
                stake=validator_stake_after,
                slashed_stake=slashed_validator.slashed_stake + slashed_amount,
                omission_count=slashed_validator.omission_count + 1,
                status=(
                    "active"
                    if validator_stake_after > 0
                    else "slashed"
                ),
            )
            evidence_status = "slashed" if slashed_amount else "reported"
        evidence_id = domain_hash(
            "MEMPOOL-OMISSION-EVIDENCE-ID",
            CHAIN_ID,
            admission.admission_id,
            admission.expires_at_height,
            len(self.blocks),
            reporter_label,
        )
        unsigned = MempoolOmissionEvidence(
            evidence_id=evidence_id,
            admission_id=admission.admission_id,
            tx_public_hash=admission.tx_public_hash,
            encrypted_payload_hash=admission.encrypted_payload_hash,
            committee_key_id=admission.committee_key_id,
            kem_ciphertext_hash=admission.kem_ciphertext_hash,
            relay_path=admission.relay_path,
            admitted_at_height=admission.admitted_at_height,
            expires_at_height=admission.expires_at_height,
            reported_at_height=len(self.blocks),
            sequencer_label=admission.sequencer_label,
            reporter_label=reporter_label,
            missed_block_count=missed_block_count,
            penalty_units=penalty_units,
            admission_auth_transcript_hash=admission.auth_transcript_hash,
            admission_auth_signature=admission.auth_signature,
            slashed_validator_id=slashed_validator_id,
            slashed_amount=slashed_amount,
            validator_stake_after=validator_stake_after,
            status=evidence_status,
        )
        auth = sign_authorization(
            reporter_label,
            "mempool_omission_evidence",
            unsigned.unsigned_record(),
        )
        evidence = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self.mempool_omission_evidence[evidence.evidence_id] = evidence
        self.mempool_omission_recovery_txs[evidence.evidence_id] = tx
        del self.pending[evidence_index]
        del self.pending_admissions[evidence_index]
        return evidence

    def force_include_omitted_admission(
        self,
        evidence_id: str,
        sequencer_label: str = "devnet-proposer",
    ) -> MempoolForcedInclusion:
        if evidence_id not in self.mempool_omission_evidence:
            raise ValueError("unknown mempool omission evidence")
        if any(
            forced.evidence_id == evidence_id
            for forced in self.mempool_forced_inclusions.values()
        ):
            raise ValueError("mempool omission already has forced inclusion")
        if evidence_id not in self.mempool_omission_recovery_txs:
            raise ValueError("omitted transaction payload unavailable")
        if not sequencer_label:
            raise ValueError("sequencer label is required")
        self._require_validator_label(sequencer_label)
        evidence = self.mempool_omission_evidence[evidence_id]
        tx = self.mempool_omission_recovery_txs[evidence_id]
        tx_public_hash = domain_hash("MEMPOOL-TX-PUBLIC", tx.public_record())
        if tx_public_hash != evidence.tx_public_hash:
            raise ValueError("omitted transaction payload hash mismatch")
        self._verify_transaction_auth(tx)
        self._queue_transaction(
            tx,
            relay_path="forced-inclusion",
            sequencer_label=sequencer_label,
        )
        admission = self.pending_admissions[-1]
        if admission.tx_public_hash != evidence.tx_public_hash:
            raise ValueError("forced inclusion admission tx hash mismatch")
        forced_id = domain_hash(
            "MEMPOOL-FORCED-INCLUSION-ID",
            CHAIN_ID,
            evidence.evidence_id,
            evidence.admission_id,
            admission.admission_id,
            len(self.blocks),
            sequencer_label,
        )
        unsigned = MempoolForcedInclusion(
            forced_inclusion_id=forced_id,
            evidence_id=evidence.evidence_id,
            admission_id=evidence.admission_id,
            tx_public_hash=evidence.tx_public_hash,
            old_encrypted_payload_hash=evidence.encrypted_payload_hash,
            new_admission_id=admission.admission_id,
            new_encrypted_payload_hash=admission.encrypted_payload_hash,
            new_committee_key_id=admission.committee_key_id,
            new_kem_ciphertext_hash=admission.kem_ciphertext_hash,
            new_relay_path=admission.relay_path,
            forced_at_height=len(self.blocks),
            sequencer_label=sequencer_label,
            reporter_label=evidence.reporter_label,
        )
        auth = sign_authorization(
            sequencer_label,
            "mempool_forced_inclusion",
            unsigned.unsigned_record(),
        )
        forced = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_mempool_forced_inclusion(forced)
        self.mempool_forced_inclusions[forced.forced_inclusion_id] = forced
        del self.mempool_omission_recovery_txs[evidence_id]
        return forced

    def report_mempool_preconfirmation_miss(
        self,
        preconfirmation_id: str,
        reporter_label: str = "watchtower",
    ) -> MempoolPreconfirmationMissEvidence:
        if not reporter_label:
            raise ValueError("reporter label is required")
        if preconfirmation_id not in self.mempool_preconfirmations:
            raise ValueError("unknown mempool preconfirmation")
        if any(
            evidence.preconfirmation_id == preconfirmation_id
            for evidence in self.mempool_preconfirmation_misses.values()
        ):
            raise ValueError("mempool preconfirmation miss already reported")
        preconfirmation = self.mempool_preconfirmations[preconfirmation_id]
        inclusion_height = self._admission_inclusion_height(preconfirmation.admission_id)
        if inclusion_height is not None and inclusion_height <= preconfirmation.target_height:
            raise ValueError("mempool preconfirmation was fulfilled")
        if len(self.blocks) <= preconfirmation.target_height:
            raise ValueError("mempool preconfirmation target has not passed")

        missed_block_count = len(self.blocks) - preconfirmation.target_height
        penalty_units = max(1, missed_block_count)
        slashed_validator = next(
            (
                validator
                for validator in self.validators.values()
                if validator.label == preconfirmation.sequencer_label
            ),
            None,
        )
        slashed_validator_id = ""
        slashed_amount = 0
        validator_stake_after = 0
        evidence_status = "unbonded_sequencer"
        if slashed_validator is not None:
            slashed_validator_id = slashed_validator.validator_id
            slashed_amount = min(slashed_validator.stake, penalty_units)
            validator_stake_after = slashed_validator.stake - slashed_amount
            self.validators[slashed_validator.validator_id] = replace(
                slashed_validator,
                stake=validator_stake_after,
                slashed_stake=slashed_validator.slashed_stake + slashed_amount,
                preconfirmation_miss_count=(
                    slashed_validator.preconfirmation_miss_count + 1
                ),
                status=(
                    "active"
                    if validator_stake_after > 0
                    else "slashed"
                ),
            )
            evidence_status = "slashed" if slashed_amount else "reported"

        evidence_id = domain_hash(
            "MEMPOOL-PRECONFIRMATION-MISS-EVIDENCE-ID",
            CHAIN_ID,
            preconfirmation.preconfirmation_id,
            preconfirmation.target_height,
            len(self.blocks),
            reporter_label,
        )
        unsigned = MempoolPreconfirmationMissEvidence(
            evidence_id=evidence_id,
            preconfirmation_id=preconfirmation.preconfirmation_id,
            admission_id=preconfirmation.admission_id,
            tx_public_hash=preconfirmation.tx_public_hash,
            encrypted_payload_hash=preconfirmation.encrypted_payload_hash,
            target_height=preconfirmation.target_height,
            reported_at_height=len(self.blocks),
            sequencer_label=preconfirmation.sequencer_label,
            reporter_label=reporter_label,
            missed_block_count=missed_block_count,
            penalty_units=penalty_units,
            preconfirmation_auth_transcript_hash=preconfirmation.auth_transcript_hash,
            preconfirmation_auth_signature=preconfirmation.auth_signature,
            slashed_validator_id=slashed_validator_id,
            slashed_amount=slashed_amount,
            validator_stake_after=validator_stake_after,
            status=evidence_status,
        )
        auth = sign_authorization(
            reporter_label,
            "mempool_preconfirmation_miss_evidence",
            unsigned.unsigned_record(),
        )
        evidence = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self.mempool_preconfirmation_misses[evidence.evidence_id] = evidence
        return evidence

    def _pending_nullifiers(self) -> set[str]:
        pending: set[str] = set()
        for tx in self.pending:
            if isinstance(tx, AssetBurn):
                pending.add(tx.nullifier)
            elif isinstance(tx, PrivateTransfer):
                pending.add(tx.nullifier)
            elif isinstance(tx, PrivateTransferBatch):
                pending.update(tx.nullifiers)
            elif isinstance(tx, AmmLiquidityAdd):
                pending.add(tx.nullifier_a)
                pending.add(tx.nullifier_b)
            elif isinstance(tx, AmmSwap):
                pending.add(tx.nullifier)
            elif isinstance(tx, AmmBatchSwap):
                pending.update(tx.nullifiers)
            elif isinstance(tx, AmmRouteSwap):
                pending.add(tx.nullifier)
            elif isinstance(tx, DarkPoolSwap):
                pending.add(tx.nullifier_a)
                pending.add(tx.nullifier_b)
            elif isinstance(tx, AmmSealedBatchSwap):
                pending.update(fill.intent.nullifier for fill in tx.fills)
            elif isinstance(tx, BridgeWithdraw):
                pending.add(tx.nullifier)
            elif isinstance(tx, PaymasterDeposit):
                pending.add(tx.nullifier)
            elif isinstance(tx, (ContractCall, ContractCallBatch)) and tx.fee_nullifier:
                pending.add(tx.fee_nullifier)
            elif isinstance(tx, ContractDeposit):
                pending.add(tx.nullifier)
            elif isinstance(tx, LendingBorrow):
                pending.add(tx.nullifier)
            elif isinstance(tx, LendingRepay):
                pending.add(tx.nullifier)
            elif isinstance(tx, LendingLiquidation):
                pending.add(tx.nullifier)
        return pending

    def _check_nullifier_available(self, *nullifiers: str) -> None:
        pending = self._pending_nullifiers()
        seen: set[str] = set()
        for nullifier in nullifiers:
            if nullifier in seen:
                raise ValueError("duplicate nullifier in transaction")
            if nullifier in self.spent_nullifiers or nullifier in pending:
                raise ValueError("duplicate nullifier")
            seen.add(nullifier)

    def register_account(self, label: str) -> AccountState:
        account = AccountState.from_label(label)
        if account.account_id in self.accounts:
            raise ValueError("account already registered")
        if label in self.retired_account_labels:
            raise ValueError("account label has been retired")
        self.accounts[account.account_id] = account
        return account

