    def open_wallet_session(
        self,
        account_id: str,
        signer_label: str,
        relay_path: str = "dandelion-stem-fluff",
        expires_in_blocks: int = 100,
    ) -> WalletSession:
        if account_id not in self.accounts:
            raise ValueError("unknown account")
        if expires_in_blocks <= 0:
            raise ValueError("expires_in_blocks must be positive")
        if not relay_path:
            raise ValueError("relay_path is required")
        account = self.accounts[account_id]
        if account.current_label != signer_label:
            raise ValueError("wallet session signer must match current account label")
        if account.status != "active":
            raise ValueError("wallet session account must be active")
        opened_at_height = len(self.blocks)
        expires_at_height = opened_at_height + expires_in_blocks
        node_committee_key_id = self._mempool_committee_key_id()
        node_network_root = self._node_network_root()
        kem_ciphertext_hash = domain_hash(
            "WALLET-SESSION-ML-KEM-CIPHERTEXT",
            CHAIN_ID,
            account.account_id,
            account.network_public_key,
            node_committee_key_id,
            node_network_root,
            relay_path,
            opened_at_height,
            expires_at_height,
            account.rotation_nonce,
        )
        session_transcript_hash = domain_hash(
            "WALLET-SESSION-TRANSCRIPT",
            CHAIN_ID,
            account.account_id,
            account.network_public_key,
            node_committee_key_id,
            kem_ciphertext_hash,
            relay_path,
            opened_at_height,
            expires_at_height,
        )
        session_id = domain_hash(
            "WALLET-SESSION-ID",
            CHAIN_ID,
            account.account_id,
            session_transcript_hash,
            len(self.wallet_sessions),
        )
        unsigned = WalletSession(
            session_id=session_id,
            account_id=account.account_id,
            wallet_network_public_key=account.network_public_key,
            node_committee_key_id=node_committee_key_id,
            node_network_root=node_network_root,
            relay_path=relay_path,
            opened_at_height=opened_at_height,
            expires_at_height=expires_at_height,
            account_rotation_nonce=account.rotation_nonce,
            kem_ciphertext_hash=kem_ciphertext_hash,
            session_transcript_hash=session_transcript_hash,
            signer_label=signer_label,
        )
        auth = sign_authorization(
            signer_label,
            "wallet_session_open",
            unsigned.unsigned_record(),
        )
        session = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_wallet_session(session)
        self.wallet_sessions[session.session_id] = session
        return session

    def _verify_wallet_session(self, session: WalletSession) -> None:
        if session.status not in {"active", "revoked"}:
            raise ValueError("invalid wallet session status")
        if session.opened_at_height < 0:
            raise ValueError("wallet session opened height must be non-negative")
        if session.expires_at_height <= session.opened_at_height:
            raise ValueError("wallet session expiry must be after open height")
        if session.account_id not in self.accounts:
            raise ValueError("wallet session references unknown account")
        if not session.signer_label:
            raise ValueError("wallet session signer label is required in state")
        expected_account = account_record(session.signer_label)
        if expected_account["account_id"] != session.account_id:
            raise ValueError("wallet session signer account mismatch")
        if expected_account["network_public_key"] != session.wallet_network_public_key:
            raise ValueError("wallet session network key mismatch")
        if session.status == "active":
            account = self.accounts[session.account_id]
            if account.current_label != session.signer_label:
                raise ValueError("active wallet session signer is not current")
            if account.rotation_nonce != session.account_rotation_nonce:
                raise ValueError("active wallet session rotation nonce mismatch")
            if account.network_public_key != session.wallet_network_public_key:
                raise ValueError("active wallet session network key mismatch")
        expected_kem = domain_hash(
            "WALLET-SESSION-ML-KEM-CIPHERTEXT",
            CHAIN_ID,
            session.account_id,
            session.wallet_network_public_key,
            session.node_committee_key_id,
            session.node_network_root,
            session.relay_path,
            session.opened_at_height,
            session.expires_at_height,
            session.account_rotation_nonce,
        )
        if session.kem_ciphertext_hash != expected_kem:
            raise ValueError("wallet session KEM ciphertext mismatch")
        expected_transcript = domain_hash(
            "WALLET-SESSION-TRANSCRIPT",
            CHAIN_ID,
            session.account_id,
            session.wallet_network_public_key,
            session.node_committee_key_id,
            session.kem_ciphertext_hash,
            session.relay_path,
            session.opened_at_height,
            session.expires_at_height,
        )
        if session.session_transcript_hash != expected_transcript:
            raise ValueError("wallet session transcript mismatch")
        if not verify_authorization(
            session.signer_label,
            "wallet_session_open",
            session.unsigned_record(),
            session.auth_scheme,
            session.auth_public_key,
            session.auth_transcript_hash,
            session.auth_signature,
        ):
            raise ValueError("invalid wallet session authorization")

    def wallet_session_status(self, session_id: str) -> Dict[str, Any]:
        if session_id not in self.wallet_sessions:
            raise ValueError("unknown wallet session")
        session = self.wallet_sessions[session_id]
        current_height = len(self.blocks)
        expired = current_height > session.expires_at_height
        stale_network = (
            session.status == "active"
            and not expired
            and session.node_network_root != self._node_network_root()
        )
        active = session.status == "active" and not expired and not stale_network
        status = (
            "active"
            if active
            else ("expired" if expired else ("stale_network" if stale_network else session.status))
        )
        return {
            "status": status,
            "current_height": current_height,
            "blocks_until_expiry": max(0, session.expires_at_height - current_height + 1),
            "session": session.public_record(),
            "wallet_session_root": self.wallet_session_root(),
            "account_root": self.account_root(),
            "node_network_root": self._node_network_root(),
        }

    def _asset_supply(self, asset_id: str) -> AssetSupply:
        if asset_id not in self.asset_supplies:
            self.asset_supplies[asset_id] = AssetSupply(asset_id=asset_id)
        return self.asset_supplies[asset_id]

    def _update_asset_supply(
        self,
        asset_id: str,
        minted_delta: int = 0,
        burned_delta: int = 0,
    ) -> None:
        if minted_delta < 0 or burned_delta < 0:
            raise ValueError("asset supply deltas must be non-negative")
        supply = self._asset_supply(asset_id)
        self.asset_supplies[asset_id] = replace(
            supply,
            minted_amount=supply.minted_amount + minted_delta,
            burned_amount=supply.burned_amount + burned_delta,
        )

