    def submit_amm_liquidity_add(
        self,
        pool_id: str,
        note_a_id: str,
        note_b_id: str,
        amount_a: int,
        amount_b: int,
        owner_view_key: str,
        network_fee: int = 1,
        signer_label: str | None = None,
    ) -> AmmLiquidityAdd:
        if amount_a <= 0 or amount_b <= 0:
            raise ValueError("liquidity amounts must be positive")
        if network_fee < 0:
            raise ValueError("network_fee must be non-negative")
        pool = self._require_pool(pool_id)
        if note_a_id not in self.notes or note_b_id not in self.notes:
            raise ValueError("unknown or already spent liquidity note")
        note_a = self.notes[note_a_id]
        note_b = self.notes[note_b_id]
        signer_label = signer_label or note_a.owner_view_key
        if signer_label != note_a.owner_view_key or signer_label != note_b.owner_view_key:
            raise ValueError("signer must own both liquidity notes")
        if note_a.asset_id != pool.asset_a_id or note_b.asset_id != pool.asset_b_id:
            raise ValueError("liquidity notes do not match pool assets")
        if note_a.amount < amount_a + network_fee:
            raise ValueError("asset A note cannot cover amount plus network fee")
        if note_b.amount < amount_b:
            raise ValueError("asset B note cannot cover amount")

        nullifier_a = self._note_nullifier(note_a)
        nullifier_b = self._note_nullifier(note_b)
        self._check_nullifier_available(nullifier_a, nullifier_b)

        lp_minted = self._amm_lp_minted(pool, amount_a, amount_b)
        if lp_minted <= 0:
            raise ValueError("liquidity deposit mints zero LP notes")

        outputs: List[Note] = [
            Note.create(owner_view_key, pool.lp_asset_id, lp_minted, self._next_nonce())
        ]
        change_a = note_a.amount - amount_a - network_fee
        change_b = note_b.amount - amount_b
        if change_a:
            outputs.append(Note.create(note_a.owner_view_key, note_a.asset_id, change_a, self._next_nonce()))
        if change_b:
            outputs.append(Note.create(note_b.owner_view_key, note_b.asset_id, change_b, self._next_nonce()))

        encrypted_payload_hash = domain_hash(
            "AMM-LIQUIDITY-PAYLOAD",
            pool_id,
            note_a_id,
            note_b_id,
            amount_a,
            amount_b,
            lp_minted,
            network_fee,
            [note.commitment for note in outputs],
        )
        unsigned_tx = AmmLiquidityAdd(
            pool_id=pool_id,
            spent_note_a_id=note_a_id,
            spent_note_b_id=note_b_id,
            nullifier_a=nullifier_a,
            nullifier_b=nullifier_b,
            amount_a=amount_a,
            amount_b=amount_b,
            lp_minted=lp_minted,
            output_notes=tuple(outputs),
            network_fee=network_fee,
            encrypted_payload_hash=encrypted_payload_hash,
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        tx = self._authorize_transaction(proved_tx, signer_label)
        self._verify_transaction_auth(tx)
        self._queue_transaction(tx)
        return tx

    def submit_amm_swap(
        self,
        pool_id: str,
        note_in_id: str,
        amount_in: int,
        min_amount_out: int,
        recipient_view_key: str,
        network_fee: int = 1,
        signer_label: str | None = None,
    ) -> AmmSwap:
        if amount_in <= 0:
            raise ValueError("swap amount_in must be positive")
        if min_amount_out < 0:
            raise ValueError("min_amount_out must be non-negative")
        if network_fee < 0:
            raise ValueError("network_fee must be non-negative")
        pool = self._require_pool(pool_id)
        if note_in_id not in self.notes:
            raise ValueError("unknown or already spent swap note")
        note_in = self.notes[note_in_id]
        signer_label = signer_label or note_in.owner_view_key
        if signer_label != note_in.owner_view_key:
            raise ValueError("signer does not own the swap note")
        if note_in.asset_id == pool.asset_a_id:
            reserve_in = pool.reserve_a
            reserve_out = pool.reserve_b
            asset_out_id = pool.asset_b_id
        elif note_in.asset_id == pool.asset_b_id:
            reserve_in = pool.reserve_b
            reserve_out = pool.reserve_a
            asset_out_id = pool.asset_a_id
        else:
            raise ValueError("swap note does not match pool assets")
        if reserve_in <= 0 or reserve_out <= 0:
            raise ValueError("pool has no liquidity")
        if note_in.amount < amount_in + network_fee:
            raise ValueError("swap note cannot cover amount plus network fee")

        amount_out = self._amm_output_amount(pool, reserve_in, reserve_out, amount_in)
        if amount_out <= 0:
            raise ValueError("swap outputs zero")
        if amount_out < min_amount_out:
            raise ValueError("swap output below minimum")

        nullifier = self._note_nullifier(note_in)
        self._check_nullifier_available(nullifier)

        outputs: List[Note] = [
            Note.create(recipient_view_key, asset_out_id, amount_out, self._next_nonce())
        ]
        change = note_in.amount - amount_in - network_fee
        if change:
            outputs.append(
                Note.create(note_in.owner_view_key, note_in.asset_id, change, self._next_nonce())
            )

        encrypted_payload_hash = domain_hash(
            "AMM-SWAP-PAYLOAD",
            pool_id,
            note_in_id,
            note_in.asset_id,
            asset_out_id,
            amount_in,
            amount_out,
            network_fee,
            [note.commitment for note in outputs],
        )
        unsigned_tx = AmmSwap(
            pool_id=pool_id,
            spent_note_id=note_in_id,
            nullifier=nullifier,
            asset_in_id=note_in.asset_id,
            asset_out_id=asset_out_id,
            amount_in=amount_in,
            amount_out=amount_out,
            output_notes=tuple(outputs),
            network_fee=network_fee,
            encrypted_payload_hash=encrypted_payload_hash,
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        tx = self._authorize_transaction(proved_tx, signer_label)
        self._verify_transaction_auth(tx)
        self._queue_transaction(tx)
        return tx

    def submit_amm_batch_swap(
        self,
        pool_id: str,
        note_in_ids: Sequence[str],
        amount_ins: Sequence[int],
        min_total_amount_out: int,
        recipient_view_key: str,
        network_fee: int = 1,
        signer_label: str | None = None,
    ) -> AmmBatchSwap:
        if not note_in_ids:
            raise ValueError("batch swap requires input notes")
        if len(note_in_ids) != len(amount_ins):
            raise ValueError("batch swap note and amount counts differ")
        if len(set(note_in_ids)) != len(note_in_ids):
            raise ValueError("batch swap notes must be distinct")
        if any(amount <= 0 for amount in amount_ins):
            raise ValueError("batch swap amounts must be positive")
        if min_total_amount_out < 0:
            raise ValueError("min_total_amount_out must be non-negative")
        if network_fee < 0:
            raise ValueError("network_fee must be non-negative")
        pool = self._require_pool(pool_id)
        if any(note_id not in self.notes for note_id in note_in_ids):
            raise ValueError("unknown or already spent batch swap note")

        input_notes = [self.notes[note_id] for note_id in note_in_ids]
        signer_label = signer_label or input_notes[0].owner_view_key
        if any(note.owner_view_key != signer_label for note in input_notes):
            raise ValueError("signer must own all batch swap notes")
        asset_in_id = input_notes[0].asset_id
        if any(note.asset_id != asset_in_id for note in input_notes):
            raise ValueError("batch swap input notes must share one asset")
        if asset_in_id == pool.asset_a_id:
            reserve_in = pool.reserve_a
            reserve_out = pool.reserve_b
            asset_out_id = pool.asset_b_id
        elif asset_in_id == pool.asset_b_id:
            reserve_in = pool.reserve_b
            reserve_out = pool.reserve_a
            asset_out_id = pool.asset_a_id
        else:
            raise ValueError("batch swap notes do not match pool assets")
        if reserve_in <= 0 or reserve_out <= 0:
            raise ValueError("pool has no liquidity")

        total_amount_in = sum(amount_ins)
        total_available = sum(note.amount for note in input_notes)
        if any(note.amount < amount for note, amount in zip(input_notes, amount_ins)):
            raise ValueError("batch swap note cannot cover amount")
        if total_available < total_amount_in + network_fee:
            raise ValueError("batch swap notes cannot cover amount plus network fee")
        total_amount_out = self._amm_output_amount(
            pool,
            reserve_in,
            reserve_out,
            total_amount_in,
        )
        if total_amount_out <= 0:
            raise ValueError("batch swap outputs zero")
        if total_amount_out < min_total_amount_out:
            raise ValueError("batch swap output below minimum")

        nullifiers = tuple(self._note_nullifier(note) for note in input_notes)
        self._check_nullifier_available(*nullifiers)

        outputs: List[Note] = [
            Note.create(recipient_view_key, asset_out_id, total_amount_out, self._next_nonce())
        ]
        remaining_fee = network_fee
        for note, amount_in in zip(input_notes, amount_ins):
            fee_from_note = min(remaining_fee, note.amount - amount_in)
            remaining_fee -= fee_from_note
            change = note.amount - amount_in - fee_from_note
            if change:
                outputs.append(
                    Note.create(note.owner_view_key, note.asset_id, change, self._next_nonce())
                )
        if remaining_fee:
            raise ValueError("batch swap notes cannot cover network fee")

        encrypted_payload_hash = domain_hash(
            "AMM-BATCH-SWAP-PAYLOAD",
            pool_id,
            list(note_in_ids),
            asset_in_id,
            asset_out_id,
            list(amount_ins),
            total_amount_in,
            total_amount_out,
            network_fee,
            [note.commitment for note in outputs],
        )
        unsigned_tx = AmmBatchSwap(
            pool_id=pool_id,
            spent_note_ids=tuple(note_in_ids),
            nullifiers=nullifiers,
            asset_in_id=asset_in_id,
            asset_out_id=asset_out_id,
            amount_ins=tuple(amount_ins),
            total_amount_in=total_amount_in,
            total_amount_out=total_amount_out,
            output_notes=tuple(outputs),
            network_fee=network_fee,
            encrypted_payload_hash=encrypted_payload_hash,
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        tx = self._authorize_transaction(proved_tx, signer_label)
        self._verify_transaction_auth(tx)
        self._queue_transaction(tx)
        return tx

    def submit_amm_route_swap(
        self,
        pool_ids: Sequence[str],
        note_in_id: str,
        amount_in: int,
        min_amount_out: int,
        recipient_view_key: str,
        network_fee: int = 1,
        signer_label: str | None = None,
    ) -> AmmRouteSwap:
        if not pool_ids:
            raise ValueError("route swap requires at least one pool")
        if amount_in <= 0:
            raise ValueError("route swap amount_in must be positive")
        if min_amount_out < 0:
            raise ValueError("min_amount_out must be non-negative")
        if network_fee < 0:
            raise ValueError("network_fee must be non-negative")
        if note_in_id not in self.notes:
            raise ValueError("unknown or already spent route swap note")
        note_in = self.notes[note_in_id]
        signer_label = signer_label or note_in.owner_view_key
        if signer_label != note_in.owner_view_key:
            raise ValueError("signer does not own the route swap note")
        if note_in.amount < amount_in + network_fee:
            raise ValueError("route swap note cannot cover amount plus network fee")

        simulation = self._simulate_amm_route(pool_ids, note_in.asset_id, amount_in)
        amount_out = int(simulation["amount_out"])
        if amount_out < min_amount_out:
            raise ValueError("route swap output below minimum")

        nullifier = self._note_nullifier(note_in)
        self._check_nullifier_available(nullifier)
        asset_path = tuple(simulation["asset_path"])
        hop_amounts = tuple(simulation["hop_amounts"])
        outputs: List[Note] = [
            Note.create(recipient_view_key, asset_path[-1], amount_out, self._next_nonce())
        ]
        change = note_in.amount - amount_in - network_fee
        if change:
            outputs.append(
                Note.create(note_in.owner_view_key, note_in.asset_id, change, self._next_nonce())
            )

        encrypted_payload_hash = domain_hash(
            "AMM-ROUTE-SWAP-PAYLOAD",
            list(pool_ids),
            note_in_id,
            list(asset_path),
            list(hop_amounts),
            amount_in,
            amount_out,
            network_fee,
            [note.commitment for note in outputs],
        )
        unsigned_tx = AmmRouteSwap(
            pool_ids=tuple(pool_ids),
            spent_note_id=note_in_id,
            nullifier=nullifier,
            asset_path=asset_path,
            hop_amounts=hop_amounts,
            amount_in=amount_in,
            amount_out=amount_out,
            output_notes=tuple(outputs),
            network_fee=network_fee,
            encrypted_payload_hash=encrypted_payload_hash,
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        tx = self._authorize_transaction(proved_tx, signer_label)
        self._verify_transaction_auth(tx)
        self._queue_transaction(tx)
        return tx

    def submit_dark_pool_swap(
        self,
        note_a_id: str,
        note_b_id: str,
        amount_a: int,
        amount_b: int,
        recipient_a_view_key: str,
        recipient_b_view_key: str,
        network_fee_a: int = 0,
        network_fee_b: int = 0,
        signer_a_label: str | None = None,
        signer_b_label: str | None = None,
        match_salt: str | None = None,
    ) -> DarkPoolSwap:
        if note_a_id == note_b_id:
            raise ValueError("dark pool swap notes must be distinct")
        if amount_a <= 0 or amount_b <= 0:
            raise ValueError("dark pool swap amounts must be positive")
        if network_fee_a < 0 or network_fee_b < 0:
            raise ValueError("dark pool swap fees must be non-negative")
        if note_a_id not in self.notes or note_b_id not in self.notes:
            raise ValueError("unknown or already spent dark pool note")
        note_a = self.notes[note_a_id]
        note_b = self.notes[note_b_id]
        signer_a_label = signer_a_label or note_a.owner_view_key
        signer_b_label = signer_b_label or note_b.owner_view_key
        if signer_a_label != note_a.owner_view_key:
            raise ValueError("signer A does not own the dark pool note")
        if signer_b_label != note_b.owner_view_key:
            raise ValueError("signer B does not own the dark pool note")
        if note_a.asset_id == note_b.asset_id:
            raise ValueError("dark pool swap assets must be distinct")
        if note_a.amount < amount_a + network_fee_a:
            raise ValueError("dark pool leg A cannot cover amount plus fee")
        if note_b.amount < amount_b + network_fee_b:
            raise ValueError("dark pool leg B cannot cover amount plus fee")
        nullifier_a = self._note_nullifier(note_a)
        nullifier_b = self._note_nullifier(note_b)
        self._check_nullifier_available(nullifier_a, nullifier_b)

        output_notes: List[Note] = [
            Note.create(recipient_b_view_key, note_a.asset_id, amount_a, self._next_nonce()),
            Note.create(recipient_a_view_key, note_b.asset_id, amount_b, self._next_nonce()),
        ]
        change_a = note_a.amount - amount_a - network_fee_a
        change_b = note_b.amount - amount_b - network_fee_b
        if change_a:
            output_notes.append(
                Note.create(note_a.owner_view_key, note_a.asset_id, change_a, self._next_nonce())
            )
        if change_b:
            output_notes.append(
                Note.create(note_b.owner_view_key, note_b.asset_id, change_b, self._next_nonce())
            )
        salt = match_salt or domain_hash("DARK-POOL-MATCH-SALT", self._next_nonce())
        encrypted_payload_hash = domain_hash(
            "DARK-POOL-SWAP-PAYLOAD",
            note_a_id,
            note_b_id,
            note_a.asset_id,
            note_b.asset_id,
            amount_a,
            amount_b,
            network_fee_a,
            network_fee_b,
            domain_hash("DARK-POOL-RECIPIENT-A", recipient_a_view_key),
            domain_hash("DARK-POOL-RECIPIENT-B", recipient_b_view_key),
            salt,
            [note.commitment for note in output_notes],
        )
        unsigned_tx = DarkPoolSwap(
            spent_note_a_id=note_a_id,
            spent_note_b_id=note_b_id,
            nullifier_a=nullifier_a,
            nullifier_b=nullifier_b,
            asset_a_id=note_a.asset_id,
            asset_b_id=note_b.asset_id,
            amount_a=amount_a,
            amount_b=amount_b,
            recipient_a_view_key=recipient_a_view_key,
            recipient_b_view_key=recipient_b_view_key,
            network_fee_a=network_fee_a,
            network_fee_b=network_fee_b,
            match_salt=salt,
            output_notes=tuple(output_notes),
            encrypted_payload_hash=encrypted_payload_hash,
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        auth_a = sign_authorization(
            signer_a_label,
            proved_tx.auth_domain(),
            proved_tx.leg_authorization_payload("a"),
        )
        auth_b = sign_authorization(
            signer_b_label,
            proved_tx.auth_domain(),
            proved_tx.leg_authorization_payload("b"),
        )
        tx = replace(
            proved_tx,
            signer_a_label=auth_a["signer_label"],
            signer_b_label=auth_b["signer_label"],
            auth_a_scheme=auth_a["auth_scheme"],
            auth_a_public_key=auth_a["auth_public_key"],
            auth_a_transcript_hash=auth_a["auth_transcript_hash"],
            auth_a_signature=auth_a["auth_signature"],
            auth_b_scheme=auth_b["auth_scheme"],
            auth_b_public_key=auth_b["auth_public_key"],
            auth_b_transcript_hash=auth_b["auth_transcript_hash"],
            auth_b_signature=auth_b["auth_signature"],
        )
        self._verify_transaction_auth(tx)
        self._queue_transaction(tx)
        return tx

    def _sealed_swap_output_asset(self, pool: AmmPool, asset_in_id: str) -> str:
        if asset_in_id == pool.asset_a_id:
            return pool.asset_b_id
        if asset_in_id == pool.asset_b_id:
            return pool.asset_a_id
        raise ValueError("sealed swap note does not match pool assets")

    def _sealed_swap_order_commitment(
        self,
        pool_id: str,
        spent_note_id: str,
        nullifier: str,
        asset_in_id: str,
        asset_out_id: str,
        amount_in: int,
        min_amount_out: int,
        recipient_view_key: str,
        network_fee: int,
        reveal_secret: str,
    ) -> str:
        if not reveal_secret:
            raise ValueError("sealed swap reveal secret is required")
        return domain_hash(
            "SEALED-SWAP-ORDER-COMMITMENT",
            CHAIN_ID,
            pool_id,
            spent_note_id,
            nullifier,
            asset_in_id,
            asset_out_id,
            amount_in,
            min_amount_out,
            domain_hash("SEALED-SWAP-RECIPIENT", recipient_view_key),
            network_fee,
            reveal_secret,
        )

    def _sealed_swap_intent_order_commitment(
        self,
        intent: SealedSwapIntent,
        reveal_secret: str,
    ) -> str:
        return self._sealed_swap_order_commitment(
            intent.pool_id,
            intent.spent_note_id,
            intent.nullifier,
            intent.asset_in_id,
            intent.asset_out_id,
            intent.amount_in,
            intent.min_amount_out,
            intent.recipient_view_key,
            intent.network_fee,
            reveal_secret,
        )

    def submit_sealed_swap_order_commitment(
        self,
        pool_id: str,
        note_in_id: str,
        amount_in: int,
        min_amount_out: int,
        recipient_view_key: str,
        reveal_secret: str,
        network_fee: int = 1,
        ttl_blocks: int = 10,
        min_reveal_height: int | None = None,
        signer_label: str | None = None,
    ) -> SealedSwapOrderCommitment:
        if amount_in <= 0:
            raise ValueError("sealed swap commitment amount_in must be positive")
        if min_amount_out < 0:
            raise ValueError("sealed swap commitment minimum must be non-negative")
        if network_fee < 0:
            raise ValueError("sealed swap commitment network fee must be non-negative")
        if ttl_blocks <= 0:
            raise ValueError("sealed swap commitment ttl must be positive")
        if not reveal_secret:
            raise ValueError("sealed swap reveal secret is required")
        pool = self._require_pool(pool_id)
        if note_in_id not in self.notes:
            raise ValueError("unknown sealed swap commitment note")
        note = self.notes[note_in_id]
        signer_label = signer_label or note.owner_view_key
        if signer_label != note.owner_view_key:
            raise ValueError("sealed swap commitment signer does not own note")
        if note.amount < amount_in + network_fee:
            raise ValueError("sealed swap commitment note cannot cover amount plus fee")
        asset_out_id = self._sealed_swap_output_asset(pool, note.asset_id)
        nullifier = self._note_nullifier(note)
        self._check_nullifier_available(nullifier)
        min_reveal = (
            len(self.blocks) + 1
            if min_reveal_height is None
            else int(min_reveal_height)
        )
        if min_reveal < len(self.blocks):
            raise ValueError("sealed swap commitment reveal height is in the past")
        expires_height = min_reveal + ttl_blocks
        order_commitment = self._sealed_swap_order_commitment(
            pool_id,
            note.note_id,
            nullifier,
            note.asset_id,
            asset_out_id,
            amount_in,
            min_amount_out,
            recipient_view_key,
            network_fee,
            reveal_secret,
        )
        owner_commitment = domain_hash("SEALED-SWAP-COMMITTER", signer_label)
        commitment_id = domain_hash(
            "SEALED-SWAP-ORDER-COMMITMENT-ID",
            CHAIN_ID,
            pool_id,
            note.asset_id,
            asset_out_id,
            owner_commitment,
            order_commitment,
            min_reveal,
            expires_height,
        )
        if commitment_id in self.sealed_swap_order_commitments:
            raise ValueError("sealed swap commitment already exists")
        unsigned = SealedSwapOrderCommitment(
            commitment_id=commitment_id,
            pool_id=pool_id,
            asset_in_id=note.asset_id,
            asset_out_id=asset_out_id,
            order_commitment=order_commitment,
            owner_commitment=owner_commitment,
            min_reveal_height=min_reveal,
            expires_height=expires_height,
        )
        auth = sign_authorization(
            signer_label,
            "sealed_swap_order_commitment",
            unsigned.unsigned_record(),
        )
        commitment = replace(
            unsigned,
            signer_label=auth["signer_label"],
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_sealed_swap_order_commitment(commitment)
        self.sealed_swap_order_commitments[commitment.commitment_id] = commitment
        return commitment

    def _verify_sealed_swap_order_commitment(
        self,
        commitment: SealedSwapOrderCommitment,
    ) -> None:
        if commitment.min_reveal_height < 0:
            raise ValueError("sealed swap commitment reveal height is invalid")
        if commitment.expires_height <= commitment.min_reveal_height:
            raise ValueError("sealed swap commitment expiry is invalid")
        if commitment.status not in {"active", "revealed", "expired"}:
            raise ValueError("sealed swap commitment status is invalid")
        if not commitment.signer_label:
            raise ValueError("sealed swap commitment is missing signer label")
        expected_owner = domain_hash("SEALED-SWAP-COMMITTER", commitment.signer_label)
        if commitment.owner_commitment != expected_owner:
            raise ValueError("sealed swap commitment owner mismatch")
        expected_id = domain_hash(
            "SEALED-SWAP-ORDER-COMMITMENT-ID",
            CHAIN_ID,
            commitment.pool_id,
            commitment.asset_in_id,
            commitment.asset_out_id,
            commitment.owner_commitment,
            commitment.order_commitment,
            commitment.min_reveal_height,
            commitment.expires_height,
        )
        if commitment.commitment_id != expected_id:
            raise ValueError("sealed swap commitment id mismatch")
        if commitment.status == "active":
            if commitment.revealed_intent_hash or commitment.revealed_at_height:
                raise ValueError("active sealed swap commitment cannot be revealed")
        elif commitment.status == "revealed":
            if not commitment.revealed_intent_hash:
                raise ValueError("sealed swap commitment missing revealed intent")
            if commitment.revealed_at_height < commitment.min_reveal_height:
                raise ValueError("sealed swap commitment revealed too early")
        elif commitment.revealed_intent_hash or commitment.revealed_at_height:
            raise ValueError("expired sealed swap commitment cannot be revealed")
        if not verify_authorization(
            commitment.signer_label,
            "sealed_swap_order_commitment",
            commitment.unsigned_record(),
            commitment.auth_scheme,
            commitment.auth_public_key,
            commitment.auth_transcript_hash,
            commitment.auth_signature,
        ):
            raise ValueError("invalid sealed swap commitment authorization")
        self._verify_registered_signer(commitment.signer_label, commitment.auth_public_key)

    def _verify_sealed_swap_commitment_reveals(
        self,
        tx: AmmSealedBatchSwap,
    ) -> None:
        if not tx.commitment_ids:
            if tx.commitment_reveal_secrets:
                raise ValueError("sealed swap commitment secrets without commitments")
            return
        if len(tx.commitment_ids) != len(tx.fills):
            raise ValueError("sealed swap commitment count mismatch")
        if len(tx.commitment_reveal_secrets) != len(tx.fills):
            raise ValueError("sealed swap commitment secret count mismatch")
        if len(set(tx.commitment_ids)) != len(tx.commitment_ids):
            raise ValueError("sealed swap commitment ids must be distinct")
        current_height = len(self.blocks)
        for commitment_id, reveal_secret, fill in zip(
            tx.commitment_ids,
            tx.commitment_reveal_secrets,
            tx.fills,
        ):
            if commitment_id not in self.sealed_swap_order_commitments:
                raise ValueError("unknown sealed swap commitment")
            commitment = self.sealed_swap_order_commitments[commitment_id]
            self._verify_sealed_swap_order_commitment(commitment)
            if commitment.status != "active":
                raise ValueError("sealed swap commitment is not active")
            if current_height < commitment.min_reveal_height:
                raise ValueError("sealed swap commitment is not revealable yet")
            if current_height > commitment.expires_height:
                raise ValueError("sealed swap commitment has expired")
            intent = fill.intent
            if commitment.pool_id != intent.pool_id:
                raise ValueError("sealed swap commitment pool mismatch")
            if (
                commitment.asset_in_id != intent.asset_in_id
                or commitment.asset_out_id != intent.asset_out_id
            ):
                raise ValueError("sealed swap commitment asset mismatch")
            if commitment.owner_commitment != domain_hash(
                "SEALED-SWAP-COMMITTER",
                intent.signer_label,
            ):
                raise ValueError("sealed swap commitment signer mismatch")
            expected_order_commitment = self._sealed_swap_intent_order_commitment(
                intent,
                reveal_secret,
            )
            if not hmac.compare_digest(
                commitment.order_commitment,
                expected_order_commitment,
            ):
                raise ValueError("sealed swap commitment opening mismatch")

    def _pending_sealed_swap_commitment_ids(self) -> set[str]:
        pending_ids: set[str] = set()
        for tx in self.pending:
            if isinstance(tx, AmmSealedBatchSwap):
                pending_ids.update(tx.commitment_ids)
        return pending_ids

    def _mark_sealed_swap_commitments_revealed(
        self,
        tx: AmmSealedBatchSwap,
    ) -> None:
        if not tx.commitment_ids:
            return
        for commitment_id, fill in zip(tx.commitment_ids, tx.fills):
            commitment = self.sealed_swap_order_commitments[commitment_id]
            if commitment.status != "active":
                raise ValueError("sealed swap commitment is not active")
            self.sealed_swap_order_commitments[commitment_id] = replace(
                commitment,
                status="revealed",
                revealed_intent_hash=fill.intent.intent_hash(),
                revealed_at_height=len(self.blocks),
            )

    def _expire_sealed_swap_auctions_at_height(
        self,
        height: int,
    ) -> Tuple[Tuple[str, ...], Tuple[str, ...]]:
        expired_commitment_ids: List[str] = []
        for commitment_id, commitment in list(
            self.sealed_swap_order_commitments.items()
        ):
            if commitment.status == "active" and height > commitment.expires_height:
                expired = replace(commitment, status="expired")
                self._verify_sealed_swap_order_commitment(expired)
                self.sealed_swap_order_commitments[commitment_id] = expired
                expired_commitment_ids.append(commitment_id)

        expired_bid_ids: List[str] = []
        for bid_id, bid in list(self.sealed_swap_solver_bids.items()):
            if bid.status == "active" and height > bid.expires_height:
                expired = replace(bid, status="expired")
                self._verify_sealed_swap_solver_bid(expired)
                self.sealed_swap_solver_bids[bid_id] = expired
                expired_bid_ids.append(bid_id)

        return tuple(expired_commitment_ids), tuple(expired_bid_ids)

    def expire_sealed_swap_auctions(self) -> Dict[str, Any]:
        height = len(self.blocks)
        expired_commitment_ids, expired_bid_ids = (
            self._expire_sealed_swap_auctions_at_height(height)
        )
        return {
            "height": height,
            "expired_commitment_count": len(expired_commitment_ids),
            "expired_solver_bid_count": len(expired_bid_ids),
            "expired_commitments": [
                self.sealed_swap_order_commitments[commitment_id].public_record()
                for commitment_id in expired_commitment_ids
            ],
            "expired_solver_bids": [
                self.sealed_swap_solver_bids[bid_id].public_record()
                for bid_id in expired_bid_ids
            ],
            "sealed_swap_order_commitment_root": (
                self.sealed_swap_order_commitment_root()
            ),
            "sealed_swap_order_commitment_count": len(
                self.sealed_swap_order_commitments
            ),
            "sealed_swap_solver_bid_root": self.sealed_swap_solver_bid_root(),
            "sealed_swap_solver_bid_count": len(self.sealed_swap_solver_bids),
        }

    def submit_sealed_swap_solver_bid(
        self,
        pool_id: str,
        commitment_ids: Sequence[str],
        asset_in_id: str,
        asset_out_id: str,
        total_amount_in: int,
        quoted_amount_out: int,
        network_fee_total: int,
        solver_label: str,
        ttl_blocks: int = 10,
        expires_height: int | None = None,
    ) -> SealedSwapSolverBid:
        if not solver_label:
            raise ValueError("sealed swap solver label is required")
        if not commitment_ids:
            raise ValueError("sealed swap solver bid requires commitments")
        if total_amount_in <= 0:
            raise ValueError("sealed swap solver bid input must be positive")
        if quoted_amount_out <= 0:
            raise ValueError("sealed swap solver bid output must be positive")
        if network_fee_total < 0:
            raise ValueError("sealed swap solver bid fee must be non-negative")
        if ttl_blocks <= 0:
            raise ValueError("sealed swap solver bid ttl must be positive")
        pool = self._require_pool(pool_id)
        if asset_in_id not in {pool.asset_a_id, pool.asset_b_id}:
            raise ValueError("sealed swap solver bid asset does not match pool")
        expected_asset_out = self._sealed_swap_output_asset(pool, asset_in_id)
        if asset_out_id != expected_asset_out:
            raise ValueError("sealed swap solver bid output asset mismatch")
        for commitment_id in commitment_ids:
            if commitment_id not in self.sealed_swap_order_commitments:
                raise ValueError("unknown sealed swap commitment")
            commitment = self.sealed_swap_order_commitments[commitment_id]
            self._verify_sealed_swap_order_commitment(commitment)
            if commitment.status != "active":
                raise ValueError("sealed swap commitment is not active")
            if commitment.pool_id != pool_id:
                raise ValueError("sealed swap solver bid commitment pool mismatch")
            if (
                commitment.asset_in_id != asset_in_id
                or commitment.asset_out_id != asset_out_id
            ):
                raise ValueError("sealed swap solver bid commitment asset mismatch")
        expires = (
            len(self.blocks) + ttl_blocks
            if expires_height is None
            else int(expires_height)
        )
        if expires < len(self.blocks):
            raise ValueError("sealed swap solver bid expiry is in the past")
        batch_commitment_root = merkle_root(
            "SEALED-SWAP-COMMITMENT-ID",
            list(commitment_ids),
        )
        bid_id = domain_hash(
            "SEALED-SWAP-SOLVER-BID-ID",
            CHAIN_ID,
            pool_id,
            solver_label,
            batch_commitment_root,
            asset_in_id,
            asset_out_id,
            total_amount_in,
            quoted_amount_out,
            network_fee_total,
            expires,
        )
        if bid_id in self.sealed_swap_solver_bids:
            raise ValueError("sealed swap solver bid already exists")
        unsigned = SealedSwapSolverBid(
            bid_id=bid_id,
            pool_id=pool_id,
            solver_label=solver_label,
            batch_commitment_root=batch_commitment_root,
            asset_in_id=asset_in_id,
            asset_out_id=asset_out_id,
            total_amount_in=total_amount_in,
            quoted_amount_out=quoted_amount_out,
            network_fee_total=network_fee_total,
            expires_height=expires,
        )
        auth = sign_authorization(
            solver_label,
            "sealed_swap_solver_bid",
            unsigned.unsigned_record(),
        )
        bid = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_sealed_swap_solver_bid(bid)
        self.sealed_swap_solver_bids[bid.bid_id] = bid
        return bid

    def _verify_sealed_swap_solver_bid(self, bid: SealedSwapSolverBid) -> None:
        if bid.status not in {"active", "won", "lost", "expired"}:
            raise ValueError("sealed swap solver bid status is invalid")
        if bid.total_amount_in <= 0:
            raise ValueError("sealed swap solver bid input must be positive")
        if bid.quoted_amount_out <= 0:
            raise ValueError("sealed swap solver bid output must be positive")
        if bid.network_fee_total < 0:
            raise ValueError("sealed swap solver bid fee must be non-negative")
        if bid.expires_height < 0:
            raise ValueError("sealed swap solver bid expiry is invalid")
        if bid.status == "active" and (
            bid.settled_tx_public_hash or bid.settled_at_height
        ):
            raise ValueError("active sealed swap solver bid cannot be settled")
        if bid.status in {"won", "lost"}:
            if not bid.settled_tx_public_hash:
                raise ValueError("settled sealed swap solver bid missing transaction")
            if bid.settled_at_height < 0:
                raise ValueError("settled sealed swap solver bid height is invalid")
        if bid.status == "expired" and (
            bid.settled_tx_public_hash or bid.settled_at_height
        ):
            raise ValueError("expired sealed swap solver bid cannot be settled")
        expected_id = domain_hash(
            "SEALED-SWAP-SOLVER-BID-ID",
            CHAIN_ID,
            bid.pool_id,
            bid.solver_label,
            bid.batch_commitment_root,
            bid.asset_in_id,
            bid.asset_out_id,
            bid.total_amount_in,
            bid.quoted_amount_out,
            bid.network_fee_total,
            bid.expires_height,
        )
        if bid.bid_id != expected_id:
            raise ValueError("sealed swap solver bid id mismatch")
        if not verify_authorization(
            bid.solver_label,
            "sealed_swap_solver_bid",
            bid.unsigned_record(),
            bid.auth_scheme,
            bid.auth_public_key,
            bid.auth_transcript_hash,
            bid.auth_signature,
        ):
            raise ValueError("invalid sealed swap solver bid authorization")
        self._verify_registered_signer(bid.solver_label, bid.auth_public_key)

    def _sealed_swap_matching_bid_key(
        self,
        bid: SealedSwapSolverBid,
    ) -> Tuple[str, str, str, str, int, int]:
        return (
            bid.pool_id,
            bid.batch_commitment_root,
            bid.asset_in_id,
            bid.asset_out_id,
            bid.total_amount_in,
            bid.network_fee_total,
        )

    def _sealed_swap_tx_bid_key(
        self,
        tx: AmmSealedBatchSwap,
    ) -> Tuple[str, str, str, str, int, int]:
        return (
            tx.pool_id,
            tx.commitment_root(),
            tx.asset_in_id,
            tx.asset_out_id,
            tx.total_amount_in,
            tx.network_fee_total,
        )

    def _matching_active_solver_bids(
        self,
        tx: AmmSealedBatchSwap,
    ) -> List[SealedSwapSolverBid]:
        key = self._sealed_swap_tx_bid_key(tx)
        current_height = len(self.blocks)
        return [
            bid
            for bid in self.sealed_swap_solver_bids.values()
            if (
                bid.status == "active"
                and bid.expires_height >= current_height
                and self._sealed_swap_matching_bid_key(bid) == key
            )
        ]

    def _verify_sealed_swap_solver_bid_for_tx(
        self,
        tx: AmmSealedBatchSwap,
    ) -> None:
        if not tx.solver_bid_id:
            return
        if not tx.commitment_ids:
            raise ValueError("sealed swap solver bid requires commitments")
        if tx.solver_bid_id not in self.sealed_swap_solver_bids:
            raise ValueError("unknown sealed swap solver bid")
        bid = self.sealed_swap_solver_bids[tx.solver_bid_id]
        self._verify_sealed_swap_solver_bid(bid)
        if bid.status != "active":
            raise ValueError("sealed swap solver bid is not active")
        if bid.expires_height < len(self.blocks):
            raise ValueError("sealed swap solver bid has expired")
        if bid.solver_label != tx.solver_label:
            raise ValueError("sealed swap solver bid solver mismatch")
        if self._sealed_swap_matching_bid_key(bid) != self._sealed_swap_tx_bid_key(tx):
            raise ValueError("sealed swap solver bid batch mismatch")
        if tx.total_amount_out < bid.quoted_amount_out:
            raise ValueError("sealed swap output below solver bid")
        better_bids = [
            other
            for other in self._matching_active_solver_bids(tx)
            if (
                other.bid_id != bid.bid_id
                and other.quoted_amount_out > bid.quoted_amount_out
            )
        ]
        if better_bids:
            raise ValueError("better sealed swap solver bid is available")

    def _mark_sealed_swap_solver_bids_settled(
        self,
        tx: AmmSealedBatchSwap,
    ) -> None:
        if not tx.solver_bid_id:
            return
        tx_public_hash = domain_hash("TX-PUBLIC", tx.public_record())
        for bid in self._matching_active_solver_bids(tx):
            self.sealed_swap_solver_bids[bid.bid_id] = replace(
                bid,
                status=("won" if bid.bid_id == tx.solver_bid_id else "lost"),
                settled_tx_public_hash=tx_public_hash,
                settled_at_height=len(self.blocks),
            )

    def submit_sealed_amm_batch_swap(
        self,
        pool_id: str,
        note_in_ids: Sequence[str],
        amount_ins: Sequence[int],
        min_amount_outs: Sequence[int],
        recipient_view_keys: Sequence[str],
        network_fees: Sequence[int] | None = None,
        signer_labels: Sequence[str] | None = None,
        commitment_ids: Sequence[str] | None = None,
        commitment_reveal_secrets: Sequence[str] | None = None,
        solver_bid_id: str = "",
        solver_label: str = "sealed-swap-solver",
    ) -> AmmSealedBatchSwap:
        if not solver_label:
            raise ValueError("sealed swap solver label is required")
        if not note_in_ids:
            raise ValueError("sealed batch swap requires input notes")
        if len(set(note_in_ids)) != len(note_in_ids):
            raise ValueError("sealed batch swap notes must be distinct")
        if len(note_in_ids) != len(amount_ins):
            raise ValueError("sealed batch swap note and amount counts differ")
        if len(note_in_ids) != len(min_amount_outs):
            raise ValueError("sealed batch swap note and minimum counts differ")
        if len(note_in_ids) != len(recipient_view_keys):
            raise ValueError("sealed batch swap note and recipient counts differ")
        if any(amount <= 0 for amount in amount_ins):
            raise ValueError("sealed swap amounts must be positive")
        if any(amount < 0 for amount in min_amount_outs):
            raise ValueError("sealed swap minimums must be non-negative")
        if network_fees is None:
            network_fees = tuple(1 for _ in note_in_ids)
        if len(network_fees) != len(note_in_ids):
            raise ValueError("sealed batch swap note and fee counts differ")
        if any(fee < 0 for fee in network_fees):
            raise ValueError("sealed swap network fees must be non-negative")
        if signer_labels is not None and len(signer_labels) != len(note_in_ids):
            raise ValueError("sealed batch swap note and signer counts differ")
        commitment_ids = tuple(commitment_ids or ())
        commitment_reveal_secrets = tuple(commitment_reveal_secrets or ())
        if commitment_ids and len(commitment_ids) != len(note_in_ids):
            raise ValueError("sealed batch swap note and commitment counts differ")
        if commitment_reveal_secrets and len(commitment_reveal_secrets) != len(note_in_ids):
            raise ValueError("sealed batch swap note and commitment secret counts differ")

        pool = self._require_pool(pool_id)
        if any(note_id not in self.notes for note_id in note_in_ids):
            raise ValueError("unknown or already spent sealed swap note")
        input_notes = [self.notes[note_id] for note_id in note_in_ids]
        asset_in_id = input_notes[0].asset_id
        if any(note.asset_id != asset_in_id for note in input_notes):
            raise ValueError("sealed swap input notes must share one asset")
        if asset_in_id == pool.asset_a_id:
            reserve_in = pool.reserve_a
            reserve_out = pool.reserve_b
            asset_out_id = pool.asset_b_id
        elif asset_in_id == pool.asset_b_id:
            reserve_in = pool.reserve_b
            reserve_out = pool.reserve_a
            asset_out_id = pool.asset_a_id
        else:
            raise ValueError("sealed swap notes do not match pool assets")
        if reserve_in <= 0 or reserve_out <= 0:
            raise ValueError("pool has no liquidity")

        total_amount_in = sum(amount_ins)
        total_network_fee = sum(network_fees)
        for note, amount_in, network_fee in zip(input_notes, amount_ins, network_fees):
            if note.amount < amount_in + network_fee:
                raise ValueError("sealed swap note cannot cover amount plus network fee")

        total_amount_out = self._amm_output_amount(
            pool,
            reserve_in,
            reserve_out,
            total_amount_in,
        )
        if total_amount_out <= 0:
            raise ValueError("sealed batch swap outputs zero")

        amount_outs: List[int] = []
        remaining_out = total_amount_out
        for index, amount_in in enumerate(amount_ins):
            if index == len(amount_ins) - 1:
                amount_out = remaining_out
            else:
                amount_out = total_amount_out * amount_in // total_amount_in
                remaining_out -= amount_out
            amount_outs.append(amount_out)
        if any(out < minimum for out, minimum in zip(amount_outs, min_amount_outs)):
            raise ValueError("sealed swap output below minimum")

        nullifiers = tuple(self._note_nullifier(note) for note in input_notes)
        self._check_nullifier_available(*nullifiers)

        fills: List[SealedSwapFill] = []
        for index, (note, amount_in, minimum, recipient, network_fee) in enumerate(
            zip(input_notes, amount_ins, min_amount_outs, recipient_view_keys, network_fees)
        ):
            signer_label = (
                signer_labels[index] if signer_labels is not None else note.owner_view_key
            )
            if signer_label != note.owner_view_key:
                raise ValueError("sealed swap signer does not own note")
            unsigned_intent = SealedSwapIntent(
                pool_id=pool_id,
                spent_note_id=note.note_id,
                nullifier=nullifiers[index],
                asset_in_id=asset_in_id,
                asset_out_id=asset_out_id,
                amount_in=amount_in,
                min_amount_out=minimum,
                recipient_view_key=recipient,
                network_fee=network_fee,
            )
            auth = sign_authorization(
                signer_label,
                "sealed_amm_swap_intent",
                unsigned_intent.unsigned_record(),
            )
            intent = replace(
                unsigned_intent,
                signer_label=auth["signer_label"],
                auth_scheme=auth["auth_scheme"],
                auth_public_key=auth["auth_public_key"],
                auth_transcript_hash=auth["auth_transcript_hash"],
                auth_signature=auth["auth_signature"],
            )
            output_note = Note.create(
                recipient,
                asset_out_id,
                amount_outs[index],
                self._next_nonce(),
            )
            change_amount = note.amount - amount_in - network_fee
            change_note = (
                Note.create(note.owner_view_key, asset_in_id, change_amount, self._next_nonce())
                if change_amount
                else None
            )
            fills.append(
                SealedSwapFill(
                    intent=intent,
                    amount_out=amount_outs[index],
                    output_note=output_note,
                    change_note=change_note,
                )
            )

        encrypted_payload_hash = domain_hash(
            "SEALED-AMM-BATCH-SWAP-PAYLOAD",
            pool_id,
            [fill.intent.intent_hash() for fill in fills],
            asset_in_id,
            asset_out_id,
            total_amount_in,
            total_amount_out,
            total_network_fee,
            [
                note.commitment
                for fill in fills
                for note in ((fill.output_note,) + ((fill.change_note,) if fill.change_note else ()))
            ],
        )
        unsigned_tx = AmmSealedBatchSwap(
            pool_id=pool_id,
            fills=tuple(fills),
            asset_in_id=asset_in_id,
            asset_out_id=asset_out_id,
            total_amount_in=total_amount_in,
            total_amount_out=total_amount_out,
            network_fee_total=total_network_fee,
            encrypted_payload_hash=encrypted_payload_hash,
            commitment_ids=commitment_ids,
            commitment_reveal_secrets=commitment_reveal_secrets,
            solver_bid_id=solver_bid_id,
            solver_label=solver_label,
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        self._verify_transaction_auth(proved_tx)
        self._queue_transaction(proved_tx)
        return proved_tx

    def bridge_emergency_root(self) -> str:
        return merkle_root(
            "BRIDGE-EMERGENCY",
            [
                {
                    "paused": self.bridge_paused,
                    "pause_reason_hash": self.bridge_pause_reason_hash,
                    "pause_action_id": self.bridge_pause_action_id,
                    "actions": [
                        action.public_record()
                        for action in sorted(
                            self.bridge_emergency_actions.values(),
                            key=lambda item: item.action_id,
                        )
                    ],
                }
            ],
        )

    def _bridge_emergency_signers(self) -> Tuple[BridgeSignerSet, Tuple[str, ...]]:
        signer_set = self.active_bridge_signer_set()
        signers = tuple(signer_set.signer_labels[:signer_set.threshold])
        if len(signers) < signer_set.threshold:
            raise ValueError("bridge emergency signer quorum not met")
        return signer_set, signers

    def _bridge_emergency_signature_root(
        self,
        *,
        action_id: str,
        action: str,
        paused: bool,
        reason_hash: str,
        operator_label: str,
        effective_height: int,
        signer_set_id: str,
        signer_labels: Sequence[str],
    ) -> str:
        payload = {
            "action_id": action_id,
            "action": action,
            "paused": paused,
            "reason_hash": reason_hash,
            "operator_commitment": domain_hash(
                "BRIDGE-EMERGENCY-OPERATOR",
                operator_label,
            ),
            "effective_height": effective_height,
            "signer_set_id": signer_set_id,
        }
        return merkle_root(
            "BRIDGE-EMERGENCY-SIGNATURE",
            [
                sign_authorization(
                    signer_label,
                    "bridge_emergency_action_quorum",
                    payload,
                )
                for signer_label in signer_labels
            ],
        )

    def _verify_bridge_emergency_action(
        self,
        action: BridgeEmergencyAction,
    ) -> None:
        if action.action not in {"pause", "resume"}:
            raise ValueError("unsupported bridge emergency action")
        if action.effective_height < 0:
            raise ValueError("bridge emergency effective height is invalid")
        if not action.operator_label:
            raise ValueError("bridge emergency operator is required")
        if not action.emergency_signature_root:
            raise ValueError("bridge emergency signature root is required")
        if action.emergency_signer_set_id not in self.bridge_signer_sets:
            raise ValueError("bridge emergency signer set is missing")
        signer_set = self.bridge_signer_sets[action.emergency_signer_set_id]
        if action.emergency_signer_threshold != signer_set.threshold:
            raise ValueError("bridge emergency signer threshold mismatch")
        if action.emergency_signer_count < signer_set.threshold:
            raise ValueError("bridge emergency signer quorum not met")
        if action.emergency_signer_count > len(signer_set.signer_labels):
            raise ValueError("bridge emergency signer count exceeds signer set")
        signers = tuple(signer_set.signer_labels[:action.emergency_signer_count])
        expected_root = self._bridge_emergency_signature_root(
            action_id=action.action_id,
            action=action.action,
            paused=action.paused,
            reason_hash=action.reason_hash,
            operator_label=action.operator_label,
            effective_height=action.effective_height,
            signer_set_id=action.emergency_signer_set_id,
            signer_labels=signers,
        )
        if action.emergency_signature_root != expected_root:
            raise ValueError("bridge emergency signature root mismatch")
        expected_action_id = domain_hash(
            "BRIDGE-EMERGENCY-ACTION-ID",
            CHAIN_ID,
            action.action,
            action.paused,
            action.reason_hash,
            action.operator_label,
            action.emergency_signer_set_id,
            action.emergency_signer_threshold,
            action.effective_height,
            action.created_at_ms,
        )
        if action.action_id != expected_action_id:
            raise ValueError("bridge emergency action id mismatch")
        if not verify_authorization(
            action.operator_label,
            "bridge_emergency_action",
            action.unsigned_record(),
            action.auth_scheme,
            action.auth_public_key,
            action.auth_transcript_hash,
            action.auth_signature,
        ):
            raise ValueError("invalid bridge emergency action authorization")

    def _publish_bridge_emergency_action(
        self,
        action: str,
        paused: bool,
        reason: str,
        operator_label: str,
    ) -> BridgeEmergencyAction:
        if action not in {"pause", "resume"}:
            raise ValueError("unsupported bridge emergency action")
        if not operator_label:
            raise ValueError("bridge emergency operator is required")
        signer_set, signers = self._bridge_emergency_signers()
        reason_hash = domain_hash("BRIDGE-EMERGENCY-REASON", reason)
        effective_height = len(self.blocks)
        created_at_ms = int(time.time() * 1000)
        action_id = domain_hash(
            "BRIDGE-EMERGENCY-ACTION-ID",
            CHAIN_ID,
            action,
            paused,
            reason_hash,
            operator_label,
            signer_set.signer_set_id,
            signer_set.threshold,
            effective_height,
            created_at_ms,
        )
        emergency_signature_root = self._bridge_emergency_signature_root(
            action_id=action_id,
            action=action,
            paused=paused,
            reason_hash=reason_hash,
            operator_label=operator_label,
            effective_height=effective_height,
            signer_set_id=signer_set.signer_set_id,
            signer_labels=signers,
        )
        unsigned = BridgeEmergencyAction(
            action_id=action_id,
            action=action,
            paused=paused,
            reason_hash=reason_hash,
            operator_label=operator_label,
            effective_height=effective_height,
            created_at_ms=created_at_ms,
            emergency_signer_set_id=signer_set.signer_set_id,
            emergency_signer_threshold=signer_set.threshold,
            emergency_signer_count=len(signers),
            emergency_signature_root=emergency_signature_root,
        )
        auth = sign_authorization(
            operator_label,
            "bridge_emergency_action",
            unsigned.unsigned_record(),
        )
        record = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_bridge_emergency_action(record)
        self.bridge_emergency_actions[record.action_id] = record
        self.bridge_paused = paused
        self.bridge_pause_reason_hash = reason_hash if paused else ""
        self.bridge_pause_action_id = record.action_id if paused else ""
        return record

    def pause_bridge(
        self,
        reason: str,
        operator_label: str = "bridge-guardian",
    ) -> BridgeEmergencyAction:
        if self.bridge_paused:
            raise ValueError("bridge is already paused")
        if not reason:
            raise ValueError("bridge pause reason is required")
        return self._publish_bridge_emergency_action(
            action="pause",
            paused=True,
            reason=reason,
            operator_label=operator_label,
        )

    def resume_bridge(
        self,
        reason: str = "resume",
        operator_label: str = "bridge-guardian",
    ) -> BridgeEmergencyAction:
        if not self.bridge_paused:
            raise ValueError("bridge is not paused")
        return self._publish_bridge_emergency_action(
            action="resume",
            paused=False,
            reason=reason,
            operator_label=operator_label,
        )

    def _require_bridge_active(self) -> None:
        if self.bridge_paused:
            raise ValueError("bridge is paused")

    def request_bridge_deposit_address(self, recipient_view_key: str) -> BridgeDepositAddress:
        self._require_bridge_active()
        self.ensure_wrapped_xmr_asset()
        deposit_id = domain_hash(
            "BRIDGE-DEPOSIT-ID",
            recipient_view_key,
            len(self.bridge_deposit_addresses),
            self._next_nonce(),
        )
        monero_address = "xmr-devnet-" + domain_hash(
            "BRIDGE-MONERO-ADDRESS",
            deposit_id,
            recipient_view_key,
            out_len=48,
        )
        request = BridgeDepositAddress(
            deposit_id=deposit_id,
            recipient_view_key=recipient_view_key,
            monero_address=monero_address,
            address_hash=domain_hash("BRIDGE-MONERO-ADDRESS-HASH", monero_address),
            status="open",
            created_at_ms=int(time.time() * 1000),
        )
        self.bridge_deposit_addresses[deposit_id] = request
        return request

    def observe_bridge_deposit(
        self,
        deposit_id: str,
        monero_txid: str,
        amount: int,
        confirmations: int,
        watcher_labels: Sequence[str] | None,
    ) -> BridgeDepositObservation:
        if deposit_id not in self.bridge_deposit_addresses:
            raise ValueError("unknown bridge deposit id")
        if amount <= 0:
            raise ValueError("bridge deposit amount must be positive")
        if confirmations < 0:
            raise ValueError("confirmations must be non-negative")

        request = self.bridge_deposit_addresses[deposit_id]
        signer_set, signer_labels = self._bridge_deposit_signers(watcher_labels)
        observation = BridgeDepositObservation(
            deposit_id=deposit_id,
            monero_txid=monero_txid,
            amount=amount,
            confirmations=confirmations,
            watcher_labels=signer_labels,
            attestation_root=self._bridge_deposit_attestation_root(
                request,
                monero_txid,
                amount,
                confirmations,
                signer_set.signer_set_id,
                signer_labels,
            ),
            status="observed",
            signer_set_id=signer_set.signer_set_id,
            signer_threshold=signer_set.threshold,
        )
        self._verify_bridge_deposit_observation(observation)
        self.bridge_observations[deposit_id] = observation
        self.bridge_deposit_addresses[deposit_id] = replace(request, status="observed")
        return observation

    def submit_bridge_mint(self, deposit_id: str) -> BridgeMint:
        self._require_bridge_active()
        wxmr = self.ensure_wrapped_xmr_asset()
        if deposit_id not in self.bridge_deposit_addresses:
            raise ValueError("unknown bridge deposit id")
        if deposit_id not in self.bridge_observations:
            raise ValueError("bridge deposit has not been observed")
        request = self.bridge_deposit_addresses[deposit_id]
        observation = self.bridge_observations[deposit_id]
        if request.status == "minted" or observation.status == "minted":
            raise ValueError("bridge deposit already minted")

        self._verify_bridge_deposit_observation(observation)
        output_note = Note.create(
            request.recipient_view_key,
            wxmr.asset_id,
            observation.amount,
            self._next_nonce(),
        )
        tx = BridgeMint(
            deposit_id=deposit_id,
            monero_txid=observation.monero_txid,
            amount=observation.amount,
            output_note=output_note,
            attestation_root=observation.attestation_root,
            bridge_signature_root=self._bridge_mint_signature_root(observation),
            signer_set_id=observation.signer_set_id,
            signer_threshold=observation.signer_threshold,
            signer_count=len(observation.watcher_labels),
        )
        self._verify_bridge_mint(tx)
        self._queue_transaction(tx)
        self.bridge_deposit_addresses[deposit_id] = replace(request, status="mint_pending")
        self.bridge_observations[deposit_id] = replace(observation, status="mint_pending")
        return tx

    def submit_bridge_withdraw(
        self,
        spent_note_id: str,
        monero_address: str,
        amount: int,
        bridge_fee: int = 1,
        signer_label: str | None = None,
    ) -> BridgeWithdraw:
        self._require_bridge_active()
        wxmr = self.ensure_wrapped_xmr_asset()
        if amount <= 0:
            raise ValueError("withdraw amount must be positive")
        if bridge_fee < 0:
            raise ValueError("bridge_fee must be non-negative")
        if spent_note_id not in self.notes:
            raise ValueError("unknown or already spent withdrawal note")
        spent = self.notes[spent_note_id]
        if spent.asset_id != wxmr.asset_id:
            raise ValueError("withdrawal note must be wrapped XMR")
        signer_label = signer_label or spent.owner_view_key
        if signer_label != spent.owner_view_key:
            raise ValueError("signer does not own the withdrawal note")
        if spent.amount < amount + bridge_fee:
            raise ValueError("withdrawal note cannot cover amount plus bridge fee")

        nullifier = self._note_nullifier(spent)
        self._check_nullifier_available(nullifier)
        change = spent.amount - amount - bridge_fee
        output_notes: List[Note] = []
        if change:
            output_notes.append(
                Note.create(spent.owner_view_key, spent.asset_id, change, self._next_nonce())
            )
        monero_address_hash = domain_hash("WITHDRAW-MONERO-ADDRESS-HASH", monero_address)
        withdrawal_id = domain_hash(
            "BRIDGE-WITHDRAWAL-ID",
            spent_note_id,
            nullifier,
            amount,
            bridge_fee,
            monero_address_hash,
        )
        queue_signer_set, queue_signers = self._bridge_withdrawal_queue_signers()
        bridge_signature_root = self._bridge_withdrawal_queue_signature_root(
            withdrawal_id,
            amount,
            monero_address_hash,
            queue_signer_set.signer_set_id,
            queue_signers,
        )
        unsigned_tx = BridgeWithdraw(
            spent_note_id=spent_note_id,
            nullifier=nullifier,
            amount=amount,
            monero_address_hash=monero_address_hash,
            bridge_fee=bridge_fee,
            output_notes=tuple(output_notes),
            withdrawal_id=withdrawal_id,
            bridge_signature_root=bridge_signature_root,
            queue_signer_set_id=queue_signer_set.signer_set_id,
            queue_signer_threshold=queue_signer_set.threshold,
            queue_signer_count=len(queue_signers),
        )
        proved_tx = self._attach_privacy_proof(unsigned_tx)
        tx = self._authorize_transaction(proved_tx, signer_label)
        self._verify_transaction_auth(tx)
        self._queue_transaction(tx)
        return tx

    def _bridge_signer_public_key_root(self, signer_labels: Sequence[str]) -> str:
        return merkle_root(
            "BRIDGE-SIGNER-PUBLIC-KEY",
            [
                {
                    "signer_label": label,
                    "spend_public_key": account_record(label)["spend_public_key"],
                    "auth_scheme": ACCOUNT_SIGNATURE_SCHEME,
                }
                for label in signer_labels
            ],
        )

    def bridge_signer_set_root(self) -> str:
        return merkle_root(
            "BRIDGE-SIGNER-SET",
            [
                signer_set.public_record()
                for signer_set in sorted(
                    self.bridge_signer_sets.values(),
                    key=lambda item: item.signer_set_id,
                )
            ],
        )

    def active_bridge_signer_set(self) -> BridgeSignerSet:
        if self.active_bridge_signer_set_id not in self.bridge_signer_sets:
            raise ValueError("active bridge signer set is missing")
        signer_set = self.bridge_signer_sets[self.active_bridge_signer_set_id]
        if signer_set.status != "active":
            raise ValueError("active bridge signer set is not active")
        return signer_set

    def rotate_bridge_signer_set(
        self,
        signer_labels: Sequence[str],
        threshold: int = 0,
        operator_label: str = "bridge-guardian",
    ) -> BridgeSignerSet:
        labels = tuple(dict.fromkeys(signer_labels))
        if not labels:
            raise ValueError("bridge signer set requires signers")
        if len(labels) != len(tuple(signer_labels)):
            raise ValueError("bridge signer set contains duplicate signers")
        if threshold <= 0:
            threshold = max(1, ceil_div(len(labels) * 2, 3))
        if threshold > len(labels):
            raise ValueError("bridge signer threshold exceeds signer count")
        if not operator_label:
            raise ValueError("bridge signer set operator is required")
        previous_set_id = self.active_bridge_signer_set_id
        epoch = len(self.bridge_signer_sets)
        rotation_id = domain_hash(
            "BRIDGE-SIGNER-SET-ROTATION-ID",
            CHAIN_ID,
            previous_set_id,
            labels,
            threshold,
            len(self.blocks),
            operator_label,
        )
        signer_public_key_root = self._bridge_signer_public_key_root(labels)
        signer_set_id = domain_hash(
            "BRIDGE-SIGNER-SET-ID",
            CHAIN_ID,
            epoch,
            threshold,
            labels,
            signer_public_key_root,
            rotation_id,
        )
        unsigned = BridgeSignerSet(
            signer_set_id=signer_set_id,
            epoch=epoch,
            threshold=threshold,
            signer_labels=labels,
            signer_public_key_root=signer_public_key_root,
            active_from_height=len(self.blocks),
            retired_at_height=0,
            status="active",
            rotation_id=rotation_id,
            operator_label=operator_label,
        )
        auth = sign_authorization(
            operator_label,
            "bridge_signer_set_rotation",
            unsigned.unsigned_record(),
        )
        signer_set = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_bridge_signer_set(signer_set)
        if previous_set_id and previous_set_id in self.bridge_signer_sets:
            previous = self.bridge_signer_sets[previous_set_id]
            retired = replace(
                previous,
                status="retired",
                retired_at_height=len(self.blocks),
            )
            retired_auth = sign_authorization(
                retired.operator_label,
                "bridge_signer_set_rotation",
                retired.unsigned_record(),
            )
            self.bridge_signer_sets[previous_set_id] = replace(
                retired,
                auth_scheme=retired_auth["auth_scheme"],
                auth_public_key=retired_auth["auth_public_key"],
                auth_transcript_hash=retired_auth["auth_transcript_hash"],
                auth_signature=retired_auth["auth_signature"],
            )
        self.bridge_signer_sets[signer_set.signer_set_id] = signer_set
        self.active_bridge_signer_set_id = signer_set.signer_set_id
        return signer_set

    def _verify_bridge_signer_set(self, signer_set: BridgeSignerSet) -> None:
        labels = tuple(signer_set.signer_labels)
        if not labels:
            raise ValueError("bridge signer set requires signers")
        if len(set(labels)) != len(labels):
            raise ValueError("bridge signer set contains duplicate signers")
        if signer_set.threshold <= 0:
            raise ValueError("bridge signer threshold must be positive")
        if signer_set.threshold > len(labels):
            raise ValueError("bridge signer threshold exceeds signer count")
        if signer_set.active_from_height < 0:
            raise ValueError("bridge signer set active height is invalid")
        if signer_set.retired_at_height < 0:
            raise ValueError("bridge signer set retired height is invalid")
        if signer_set.status not in {"active", "retired"}:
            raise ValueError("invalid bridge signer set status")
        if signer_set.status == "retired" and signer_set.retired_at_height < signer_set.active_from_height:
            raise ValueError("bridge signer set retirement precedes activation")
        expected_public_key_root = self._bridge_signer_public_key_root(labels)
        if signer_set.signer_public_key_root != expected_public_key_root:
            raise ValueError("bridge signer public key root mismatch")
        expected_signer_set_id = domain_hash(
            "BRIDGE-SIGNER-SET-ID",
            CHAIN_ID,
            signer_set.epoch,
            signer_set.threshold,
            labels,
            signer_set.signer_public_key_root,
            signer_set.rotation_id,
        )
        if signer_set.signer_set_id != expected_signer_set_id:
            raise ValueError("bridge signer set id mismatch")
        if not verify_authorization(
            signer_set.operator_label,
            "bridge_signer_set_rotation",
            signer_set.unsigned_record(),
            signer_set.auth_scheme,
            signer_set.auth_public_key,
            signer_set.auth_transcript_hash,
            signer_set.auth_signature,
        ):
            raise ValueError("invalid bridge signer set authorization")

    def _bridge_release_signers(
        self,
        signer_labels: Sequence[str] | None,
    ) -> Tuple[BridgeSignerSet, Tuple[str, ...]]:
        signer_set = self.active_bridge_signer_set()
        if signer_labels is None:
            labels = tuple(signer_set.signer_labels[:signer_set.threshold])
        else:
            labels = tuple(dict.fromkeys(signer_labels))
        if not labels:
            raise ValueError("at least one bridge release signer is required")
        if len(labels) < signer_set.threshold:
            raise ValueError("bridge release signer quorum not met")
        signer_members = set(signer_set.signer_labels)
        for label in labels:
            if label not in signer_members:
                raise ValueError("bridge release signer is not in the active signer set")
        return signer_set, labels

    def _bridge_deposit_signers(
        self,
        signer_labels: Sequence[str] | None,
    ) -> Tuple[BridgeSignerSet, Tuple[str, ...]]:
        signer_set = self.active_bridge_signer_set()
        if signer_labels is None:
            labels = tuple(signer_set.signer_labels[:signer_set.threshold])
        else:
            labels = tuple(dict.fromkeys(signer_labels))
        if not labels:
            raise ValueError("at least one bridge deposit signer is required")
        if len(labels) < signer_set.threshold:
            raise ValueError("bridge deposit signer quorum not met")
        signer_members = set(signer_set.signer_labels)
        for label in labels:
            if label not in signer_members:
                raise ValueError("bridge deposit signer is not in the active signer set")
        return signer_set, labels

    def _bridge_deposit_observation_payload(
        self,
        request: BridgeDepositAddress,
        monero_txid: str,
        amount: int,
        confirmations: int,
        signer_set_id: str,
    ) -> Dict[str, Any]:
        return {
            "deposit_id": request.deposit_id,
            "address_hash": request.address_hash,
            "monero_txid_hash": domain_hash("MONERO-TXID-HASH", monero_txid),
            "amount": amount,
            "confirmations": confirmations,
            "signer_set_id": signer_set_id,
        }

    def _bridge_deposit_attestation_root(
        self,
        request: BridgeDepositAddress,
        monero_txid: str,
        amount: int,
        confirmations: int,
        signer_set_id: str,
        signer_labels: Sequence[str],
    ) -> str:
        payload = self._bridge_deposit_observation_payload(
            request,
            monero_txid,
            amount,
            confirmations,
            signer_set_id,
        )
        return merkle_root(
            "BRIDGE-DEPOSIT-ATTESTATION",
            [
                sign_authorization(
                    signer_label,
                    "bridge_deposit_observation",
                    payload,
                )
                for signer_label in signer_labels
            ],
        )

    def _bridge_mint_signature_root(
        self,
        observation: BridgeDepositObservation,
    ) -> str:
        return merkle_root(
            "BRIDGE-MINT-SIGNATURE",
            [
                sign_authorization(
                    signer_label,
                    "bridge_mint",
                    {
                        "deposit_id": observation.deposit_id,
                        "monero_txid_hash": domain_hash(
                            "MONERO-TXID-HASH",
                            observation.monero_txid,
                        ),
                        "amount": observation.amount,
                        "attestation_root": observation.attestation_root,
                        "signer_set_id": observation.signer_set_id,
                    },
                )
                for signer_label in observation.watcher_labels
            ],
        )

    def _bridge_withdrawal_queue_signers(self) -> Tuple[BridgeSignerSet, Tuple[str, ...]]:
        signer_set = self.active_bridge_signer_set()
        signers = tuple(signer_set.signer_labels[:signer_set.threshold])
        if len(signers) < signer_set.threshold:
            raise ValueError("bridge withdrawal queue signer quorum not met")
        return signer_set, signers

    def _bridge_withdrawal_queue_signature_root(
        self,
        withdrawal_id: str,
        amount: int,
        monero_address_hash: str,
        signer_set_id: str,
        signer_labels: Sequence[str],
    ) -> str:
        return merkle_root(
            "BRIDGE-WITHDRAWAL-QUEUE-SIGNATURE",
            [
                sign_authorization(
                    signer_label,
                    "bridge_withdrawal_queue",
                    {
                        "withdrawal_id": withdrawal_id,
                        "amount": amount,
                        "monero_address_hash": monero_address_hash,
                        "signer_set_id": signer_set_id,
                    },
                )
                for signer_label in signer_labels
            ],
        )

    def _bridge_withdrawal_release_signature_root(
        self,
        withdrawal: BridgeWithdrawalRecord,
        monero_txid_hash: str,
        signer_labels: Sequence[str],
        signer_set_id: str,
    ) -> str:
        return merkle_root(
            "BRIDGE-WITHDRAWAL-RELEASE-SIGNATURE",
            [
                sign_authorization(
                    signer_label,
                    "bridge_withdrawal_release",
                    {
                        "withdrawal_id": withdrawal.withdrawal_id,
                        "amount": withdrawal.amount,
                        "monero_address_hash": withdrawal.monero_address_hash,
                        "monero_txid_hash": monero_txid_hash,
                        "signer_set_id": signer_set_id,
                    },
                )
                for signer_label in signer_labels
            ],
        )

    def bridge_withdrawal_challenge_root(self) -> str:
        return merkle_root(
            "BRIDGE-WITHDRAWAL-CHALLENGE",
            [
                challenge.public_record()
                for challenge in sorted(
                    self.bridge_withdrawal_challenges.values(),
                    key=lambda item: item.challenge_id,
                )
            ],
        )

    def _active_bridge_withdrawal_challenges(
        self,
        withdrawal_id: str,
    ) -> Tuple[BridgeWithdrawalChallenge, ...]:
        current_height = len(self.blocks)
        return tuple(
            challenge
            for challenge in sorted(
                self.bridge_withdrawal_challenges.values(),
                key=lambda item: item.challenge_id,
            )
            if (
                challenge.withdrawal_id == withdrawal_id
                and challenge.status == "active"
                and current_height < challenge.hold_until_height
            )
        )

    def bridge_withdrawal_release_rate_limit(
        self,
        release_height: int | None = None,
    ) -> Dict[str, Any]:
        if release_height is None:
            release_height = len(self.blocks)
        if release_height < 0:
            raise ValueError("release height must be non-negative")
        released = [
            withdrawal
            for withdrawal in self.bridge_withdrawals.values()
            if (
                withdrawal.released_at_height == release_height
                and withdrawal.status in {"submitted", "completed"}
            )
        ]
        released_amount = sum(withdrawal.amount for withdrawal in released)
        remaining_amount = max(
            0,
            BRIDGE_WITHDRAWAL_RELEASE_RATE_LIMIT_AMOUNT - released_amount,
        )
        return {
            "release_height": release_height,
            "release_amount_limit": BRIDGE_WITHDRAWAL_RELEASE_RATE_LIMIT_AMOUNT,
            "released_amount": released_amount,
            "remaining_amount": remaining_amount,
            "released_withdrawal_count": len(released),
            "released_withdrawal_ids": sorted(
                withdrawal.withdrawal_id for withdrawal in released
            ),
            "status": "available" if remaining_amount else "exhausted",
        }

    def _check_bridge_withdrawal_release_rate_limit(
        self,
        withdrawal: BridgeWithdrawalRecord,
    ) -> None:
        report = self.bridge_withdrawal_release_rate_limit()
        if withdrawal.amount > int(report["remaining_amount"]):
            raise ValueError("bridge withdrawal release rate limit exceeded")

    def challenge_bridge_withdrawal(
        self,
        withdrawal_id: str,
        challenge_type: str = "watchtower-hold",
        evidence: str = "",
        reporter_label: str = "watchtower",
        hold_blocks: int = BRIDGE_WITHDRAWAL_CHALLENGE_HOLD_BLOCKS,
    ) -> BridgeWithdrawalChallenge:
        if withdrawal_id not in self.bridge_withdrawals:
            raise ValueError("unknown bridge withdrawal")
        if not reporter_label:
            raise ValueError("reporter label is required")
        if hold_blocks <= 0:
            raise ValueError("hold_blocks must be positive")
        challenge_type = challenge_type.replace("_", "-").lower()
        if challenge_type not in BRIDGE_WITHDRAWAL_CHALLENGE_TYPES:
            raise ValueError("unsupported bridge withdrawal challenge type")
        withdrawal = self.bridge_withdrawals[withdrawal_id]
        if withdrawal.status != "queued":
            raise ValueError("bridge withdrawal challenge only applies to queued withdrawals")

        evidence_root = domain_hash(
            "BRIDGE-WITHDRAWAL-CHALLENGE-EVIDENCE",
            CHAIN_ID,
            withdrawal_id,
            challenge_type,
            domain_hash("BRIDGE-WITHDRAWAL-CHALLENGE-DETAIL", evidence),
        )
        challenge_id = domain_hash(
            "BRIDGE-WITHDRAWAL-CHALLENGE-ID",
            CHAIN_ID,
            withdrawal_id,
            challenge_type,
            evidence_root,
            reporter_label,
        )
        if challenge_id in self.bridge_withdrawal_challenges:
            raise ValueError("bridge withdrawal challenge already reported")
        hold_until_height = max(
            withdrawal.release_not_before_height,
            len(self.blocks) + hold_blocks,
        )
        unsigned = BridgeWithdrawalChallenge(
            challenge_id=challenge_id,
            withdrawal_id=withdrawal_id,
            nullifier=withdrawal.nullifier,
            amount_bucket=withdrawal.amount_bucket,
            challenge_type=challenge_type,
            evidence_root=evidence_root,
            reporter_label=reporter_label,
            reported_at_height=len(self.blocks),
            hold_until_height=hold_until_height,
            status="active",
        )
        auth = sign_authorization(
            reporter_label,
            "bridge_withdrawal_challenge",
            unsigned.unsigned_record(),
        )
        challenge = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_bridge_withdrawal_challenge(challenge)
        self.bridge_withdrawal_challenges[challenge.challenge_id] = challenge
        self.bridge_withdrawals[withdrawal_id] = replace(
            withdrawal,
            release_not_before_height=hold_until_height,
        )
        return challenge

    def _verify_bridge_withdrawal_challenge(
        self,
        challenge: BridgeWithdrawalChallenge,
    ) -> None:
        if challenge.withdrawal_id not in self.bridge_withdrawals:
            raise ValueError("bridge withdrawal challenge references unknown withdrawal")
        if challenge.challenge_type not in BRIDGE_WITHDRAWAL_CHALLENGE_TYPES:
            raise ValueError("unsupported bridge withdrawal challenge type")
        if challenge.status != "active":
            raise ValueError("invalid bridge withdrawal challenge status")
        if challenge.reported_at_height < 0:
            raise ValueError("invalid bridge withdrawal challenge height")
        if challenge.reported_at_height > len(self.blocks):
            raise ValueError("bridge withdrawal challenge is above chain height")
        if challenge.hold_until_height <= challenge.reported_at_height:
            raise ValueError("bridge withdrawal challenge hold must extend release")
        withdrawal = self.bridge_withdrawals[challenge.withdrawal_id]
        if challenge.nullifier != withdrawal.nullifier:
            raise ValueError("bridge withdrawal challenge nullifier mismatch")
        if challenge.amount_bucket != withdrawal.amount_bucket:
            raise ValueError("bridge withdrawal challenge amount bucket mismatch")
        expected_challenge_id = domain_hash(
            "BRIDGE-WITHDRAWAL-CHALLENGE-ID",
            CHAIN_ID,
            challenge.withdrawal_id,
            challenge.challenge_type,
            challenge.evidence_root,
            challenge.reporter_label,
        )
        if challenge.challenge_id != expected_challenge_id:
            raise ValueError("bridge withdrawal challenge id mismatch")
        if not verify_authorization(
            challenge.reporter_label,
            "bridge_withdrawal_challenge",
            challenge.unsigned_record(),
            challenge.auth_scheme,
            challenge.auth_public_key,
            challenge.auth_transcript_hash,
            challenge.auth_signature,
        ):
            raise ValueError("invalid bridge withdrawal challenge authorization")

    def release_bridge_withdrawal(
        self,
        withdrawal_id: str,
        monero_txid: str,
        signer_labels: Sequence[str] | None = None,
    ) -> BridgeWithdrawalRecord:
        self._require_bridge_active()
        if withdrawal_id not in self.bridge_withdrawals:
            raise ValueError("unknown bridge withdrawal")
        if not monero_txid:
            raise ValueError("monero_txid is required")
        withdrawal = self.bridge_withdrawals[withdrawal_id]
        if withdrawal.status != "queued":
            raise ValueError("withdrawal release already submitted")
        active_challenges = self._active_bridge_withdrawal_challenges(withdrawal_id)
        if active_challenges:
            raise ValueError("withdrawal challenge hold has not elapsed")
        if len(self.blocks) < withdrawal.release_not_before_height:
            raise ValueError("withdrawal release delay has not elapsed")
        self._check_bridge_withdrawal_release_rate_limit(withdrawal)
        signer_set, signers = self._bridge_release_signers(signer_labels)

        monero_txid_hash = domain_hash("MONERO-TXID-HASH", monero_txid)
        updated = replace(
            withdrawal,
            status="submitted",
            release_monero_txid_hash=monero_txid_hash,
            release_signer_count=len(signers),
            release_signer_set_id=signer_set.signer_set_id,
            release_signature_root=self._bridge_withdrawal_release_signature_root(
                withdrawal,
                monero_txid_hash,
                signers,
                signer_set.signer_set_id,
            ),
            release_confirmations=0,
            released_at_height=len(self.blocks),
            released_at_ms=int(time.time() * 1000),
            completed_at_ms=0,
        )
        self.bridge_withdrawals[withdrawal_id] = updated
        return updated

    def confirm_bridge_withdrawal(
        self,
        withdrawal_id: str,
        confirmations: int,
        finality_depth: int = 10,
    ) -> BridgeWithdrawalRecord:
        if withdrawal_id not in self.bridge_withdrawals:
            raise ValueError("unknown bridge withdrawal")
        if confirmations < 0:
            raise ValueError("confirmations must be non-negative")
        if finality_depth <= 0:
            raise ValueError("finality_depth must be positive")
        withdrawal = self.bridge_withdrawals[withdrawal_id]
        if withdrawal.status == "queued":
            raise ValueError("withdrawal release not submitted")
        if confirmations < withdrawal.release_confirmations:
            raise ValueError("withdrawal confirmations cannot decrease")

        status = "completed" if confirmations >= finality_depth else "submitted"
        completed_at_ms = withdrawal.completed_at_ms
        if status == "completed" and completed_at_ms == 0:
            completed_at_ms = int(time.time() * 1000)
        updated = replace(
            withdrawal,
            status=status,
            release_confirmations=confirmations,
            completed_at_ms=completed_at_ms,
        )
        self.bridge_withdrawals[withdrawal_id] = updated
        return updated

    def bridge_reserve_report_root(self) -> str:
        return merkle_root(
            "BRIDGE-RESERVE-REPORT",
            [
                report.public_record()
                for report in sorted(
                    self.bridge_reserve_reports.values(),
                    key=lambda item: item.report_id,
                )
            ],
        )

    def bridge_reserve_liabilities(self) -> Dict[str, int | str]:
        if not self.wrapped_xmr_asset_id or self.wrapped_xmr_asset_id not in self.assets:
            return {
                "reserve_asset_id": "",
                "circulating_amount": 0,
                "queued_withdrawal_amount": 0,
                "submitted_withdrawal_amount": 0,
                "completed_withdrawal_amount": 0,
                "outstanding_liability": 0,
            }
        circulating_amount = self._asset_supply(self.wrapped_xmr_asset_id).circulating_amount
        queued_withdrawal_amount = sum(
            withdrawal.amount
            for withdrawal in self.bridge_withdrawals.values()
            if withdrawal.status == "queued"
        )
        submitted_withdrawal_amount = sum(
            withdrawal.amount
            for withdrawal in self.bridge_withdrawals.values()
            if withdrawal.status == "submitted"
        )
        completed_withdrawal_amount = sum(
            withdrawal.amount
            for withdrawal in self.bridge_withdrawals.values()
            if withdrawal.status == "completed"
        )
        outstanding_liability = (
            circulating_amount
            + queued_withdrawal_amount
            + submitted_withdrawal_amount
        )
        return {
            "reserve_asset_id": self.wrapped_xmr_asset_id,
            "circulating_amount": circulating_amount,
            "queued_withdrawal_amount": queued_withdrawal_amount,
            "submitted_withdrawal_amount": submitted_withdrawal_amount,
            "completed_withdrawal_amount": completed_withdrawal_amount,
            "outstanding_liability": outstanding_liability,
        }

    def publish_bridge_reserve_report(
        self,
        reserve_amount: int,
        reserve_address: str,
        reporter_labels: Sequence[str] | None = None,
    ) -> BridgeReserveReport:
        if reserve_amount < 0:
            raise ValueError("reserve_amount must be non-negative")
        if not reserve_address:
            raise ValueError("reserve address is required")
        reporters = tuple(dict.fromkeys(reporter_labels or ("reserve-auditor-1",)))
        if not reporters:
            raise ValueError("at least one reserve reporter is required")

        self.ensure_wrapped_xmr_asset()
        liabilities = self.bridge_reserve_liabilities()
        outstanding_liability = int(liabilities["outstanding_liability"])
        surplus_amount = reserve_amount - outstanding_liability
        coverage_bps = (
            reserve_amount * 10_000 // outstanding_liability
            if outstanding_liability
            else 10_000
        )
        status = "healthy" if reserve_amount >= outstanding_liability else "underreserved"
        reserve_address_hash = domain_hash(
            "BRIDGE-RESERVE-ADDRESS-HASH",
            reserve_address,
        )
        report_id = domain_hash(
            "BRIDGE-RESERVE-REPORT-ID",
            CHAIN_ID,
            liabilities["reserve_asset_id"],
            reserve_address_hash,
            reserve_amount,
            outstanding_liability,
            len(self.bridge_reserve_reports),
            len(self.blocks),
            reporters,
        )
        unsigned_payload = {
            "report_id": report_id,
            "reserve_asset_id": liabilities["reserve_asset_id"],
            "reserve_address_hash": reserve_address_hash,
            "reported_reserve_amount": reserve_amount,
            "circulating_amount": liabilities["circulating_amount"],
            "queued_withdrawal_amount": liabilities["queued_withdrawal_amount"],
            "submitted_withdrawal_amount": liabilities["submitted_withdrawal_amount"],
            "completed_withdrawal_amount": liabilities["completed_withdrawal_amount"],
            "outstanding_liability": outstanding_liability,
            "surplus_amount": surplus_amount,
            "coverage_bps": coverage_bps,
            "status": status,
            "reported_at_height": len(self.blocks),
        }
        attestations = [
            sign_authorization(
                reporter,
                "bridge_reserve_report",
                unsigned_payload,
            )
            for reporter in reporters
        ]
        report = BridgeReserveReport(
            report_id=report_id,
            reserve_asset_id=str(liabilities["reserve_asset_id"]),
            reserve_address_hash=reserve_address_hash,
            reported_reserve_amount=reserve_amount,
            circulating_amount=int(liabilities["circulating_amount"]),
            queued_withdrawal_amount=int(liabilities["queued_withdrawal_amount"]),
            submitted_withdrawal_amount=int(liabilities["submitted_withdrawal_amount"]),
            completed_withdrawal_amount=int(liabilities["completed_withdrawal_amount"]),
            outstanding_liability=outstanding_liability,
            surplus_amount=surplus_amount,
            coverage_bps=coverage_bps,
            status=status,
            reporter_count=len(reporters),
            attestation_root=merkle_root(
                "BRIDGE-RESERVE-REPORT-ATTESTATION",
                attestations,
            ),
            reported_at_height=len(self.blocks),
            reported_at_ms=int(time.time() * 1000),
        )
        self.bridge_reserve_reports[report.report_id] = report
        return report

    def _sealed_swap_pool_view_root(
        self,
        pool_id: str,
        asset_in_id: str,
        asset_out_id: str,
        reserve_in: int,
        reserve_out: int,
        fee_bps: int,
        curve: str = "constant_product",
    ) -> str:
        return domain_hash(
            "SEALED-SWAP-POOL-VIEW",
            {
                "pool_id": pool_id,
                "asset_in_id": asset_in_id,
                "asset_out_id": asset_out_id,
                "reserve_in": reserve_in,
                "reserve_out": reserve_out,
                "fee_bps": fee_bps,
                "curve": curve,
            },
        )

    def _sealed_swap_receipt_roots(
        self,
        tx: AmmSealedBatchSwap,
    ) -> Tuple[str, str, str, int]:
        fill_items = []
        minimum_items = []
        surplus_items = []
        total_surplus = 0
        for fill in tx.fills:
            intent_hash = fill.intent.intent_hash()
            surplus = fill.amount_out - fill.intent.min_amount_out
            if surplus < 0:
                raise ValueError("sealed swap settlement receipt below minimum")
            total_surplus += surplus
            fill_items.append({
                "intent_hash": intent_hash,
                "output_commitment": fill.output_note.commitment,
                "change_commitment": (
                    fill.change_note.commitment if fill.change_note else ""
                ),
            })
            minimum_items.append({
                "intent_hash": intent_hash,
                "minimum_output_commitment": domain_hash(
                    "SEALED-SWAP-MINIMUM-OUTPUT",
                    fill.intent.min_amount_out,
                ),
            })
            surplus_items.append({
                "intent_hash": intent_hash,
                "surplus_commitment": domain_hash(
                    "SEALED-SWAP-SURPLUS",
                    surplus,
                ),
            })
        return (
            merkle_root("SEALED-SWAP-FILL-COMMITMENT", fill_items),
            merkle_root("SEALED-SWAP-MINIMUM-OUTPUT", minimum_items),
            merkle_root("SEALED-SWAP-SURPLUS", surplus_items),
            total_surplus,
        )

    def _build_sealed_swap_settlement_receipt(
        self,
        tx: AmmSealedBatchSwap,
        pool_before: AmmPool,
        pool_after: AmmPool,
        block_height: int,
    ) -> SealedSwapSettlementReceipt:
        if not tx.solver_label:
            raise ValueError("sealed swap solver label is required")
        if tx.asset_in_id == pool_before.asset_a_id:
            before_in = pool_before.reserve_a
            before_out = pool_before.reserve_b
            after_in = pool_after.reserve_a
            after_out = pool_after.reserve_b
        elif tx.asset_in_id == pool_before.asset_b_id:
            before_in = pool_before.reserve_b
            before_out = pool_before.reserve_a
            after_in = pool_after.reserve_b
            after_out = pool_after.reserve_a
        else:
            raise ValueError("sealed swap receipt asset mismatch")
        pool_before_root = self._sealed_swap_pool_view_root(
            pool_before.pool_id,
            tx.asset_in_id,
            tx.asset_out_id,
            before_in,
            before_out,
            pool_before.fee_bps,
            pool_before.curve,
        )
        pool_after_root = self._sealed_swap_pool_view_root(
            pool_after.pool_id,
            tx.asset_in_id,
            tx.asset_out_id,
            after_in,
            after_out,
            pool_after.fee_bps,
            pool_after.curve,
        )
        fill_root, minimum_root, surplus_root, total_surplus = (
            self._sealed_swap_receipt_roots(tx)
        )
        tx_public_hash = domain_hash("TX-PUBLIC", tx.public_record())
        route_commitment = domain_hash(
            "SEALED-SWAP-ROUTE",
            tx.pool_id,
            tx.asset_in_id,
            tx.asset_out_id,
            pool_before_root,
            pool_after_root,
        )
        receipt_id = domain_hash(
            "SEALED-SWAP-SETTLEMENT-RECEIPT-ID",
            CHAIN_ID,
            block_height,
            tx_public_hash,
            tx.intent_root(),
            tx.solver_label,
        )
        unsigned = SealedSwapSettlementReceipt(
            receipt_id=receipt_id,
            block_height=block_height,
            tx_public_hash=tx_public_hash,
            pool_id=tx.pool_id,
            solver_label=tx.solver_label,
            intent_count=len(tx.fills),
            intent_root=tx.intent_root(),
            route_commitment=route_commitment,
            asset_in_id=tx.asset_in_id,
            asset_out_id=tx.asset_out_id,
            total_amount_in=tx.total_amount_in,
            total_amount_out=tx.total_amount_out,
            network_fee_total=tx.network_fee_total,
            pool_fee_bps=pool_before.fee_bps,
            pool_curve=pool_before.curve,
            pool_before_root=pool_before_root,
            pool_after_root=pool_after_root,
            pool_before_reserve_in=before_in,
            pool_before_reserve_out=before_out,
            pool_after_reserve_in=after_in,
            pool_after_reserve_out=after_out,
            fill_commitment_root=fill_root,
            minimum_output_root=minimum_root,
            surplus_commitment_root=surplus_root,
            total_surplus_amount=total_surplus,
            clearing_price_numerator=tx.total_amount_out,
            clearing_price_denominator=tx.total_amount_in,
            solver_bid_id=tx.solver_bid_id,
        )
        unsigned = replace(
            unsigned,
            clearing_price_commitment_root=(
                unsigned.expected_clearing_price_commitment_root()
            ),
            aggregate_surplus_commitment_root=(
                unsigned.expected_aggregate_surplus_commitment_root()
            ),
        )
        auth = sign_authorization(
            tx.solver_label,
            "sealed_swap_settlement_receipt",
            unsigned.unsigned_record(),
        )
        return replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )

    def _verify_sealed_swap_settlement_receipt(
        self,
        receipt: SealedSwapSettlementReceipt,
    ) -> None:
        if receipt.block_height < 0 or receipt.block_height >= len(self.blocks):
            raise ValueError("sealed swap receipt references unknown block")
        matches = [
            tx
            for tx in self.blocks[receipt.block_height].transactions
            if (
                isinstance(tx, AmmSealedBatchSwap)
                and domain_hash("TX-PUBLIC", tx.public_record()) == receipt.tx_public_hash
            )
        ]
        if len(matches) != 1:
            raise ValueError("sealed swap receipt transaction mismatch")
        tx = matches[0]
        if receipt.pool_id != tx.pool_id:
            raise ValueError("sealed swap receipt pool mismatch")
        if receipt.solver_label != tx.solver_label:
            raise ValueError("sealed swap receipt solver mismatch")
        if receipt.solver_bid_id != tx.solver_bid_id:
            raise ValueError("sealed swap receipt solver bid mismatch")
        if receipt.intent_count != len(tx.fills):
            raise ValueError("sealed swap receipt intent count mismatch")
        if receipt.intent_root != tx.intent_root():
            raise ValueError("sealed swap receipt intent root mismatch")
        if receipt.asset_in_id != tx.asset_in_id or receipt.asset_out_id != tx.asset_out_id:
            raise ValueError("sealed swap receipt asset mismatch")
        if receipt.total_amount_in != tx.total_amount_in:
            raise ValueError("sealed swap receipt input amount mismatch")
        if receipt.total_amount_out != tx.total_amount_out:
            raise ValueError("sealed swap receipt output amount mismatch")
        if receipt.network_fee_total != tx.network_fee_total:
            raise ValueError("sealed swap receipt fee mismatch")
        if receipt.solver_bid_id:
            if receipt.solver_bid_id not in self.sealed_swap_solver_bids:
                raise ValueError("sealed swap receipt missing solver bid")
            bid = self.sealed_swap_solver_bids[receipt.solver_bid_id]
            self._verify_sealed_swap_solver_bid(bid)
            if bid.status != "won":
                raise ValueError("sealed swap receipt solver bid was not won")
            if bid.settled_tx_public_hash != receipt.tx_public_hash:
                raise ValueError("sealed swap receipt solver bid tx mismatch")
            if bid.settled_at_height != receipt.block_height:
                raise ValueError("sealed swap receipt solver bid height mismatch")
            if self._sealed_swap_matching_bid_key(bid) != self._sealed_swap_tx_bid_key(tx):
                raise ValueError("sealed swap receipt solver bid batch mismatch")
            if bid.quoted_amount_out > receipt.total_amount_out:
                raise ValueError("sealed swap receipt below solver bid")
        if receipt.pool_before_reserve_in < 0 or receipt.pool_before_reserve_out < 0:
            raise ValueError("sealed swap receipt invalid before reserves")
        if receipt.pool_after_reserve_in < 0 or receipt.pool_after_reserve_out < 0:
            raise ValueError("sealed swap receipt invalid after reserves")
        if receipt.pool_after_reserve_in != receipt.pool_before_reserve_in + tx.total_amount_in:
            raise ValueError("sealed swap receipt reserve-in mismatch")
        if receipt.pool_after_reserve_out != receipt.pool_before_reserve_out - tx.total_amount_out:
            raise ValueError("sealed swap receipt reserve-out mismatch")
        if receipt.pool_curve != self._require_pool(receipt.pool_id).curve:
            raise ValueError("sealed swap receipt pool curve mismatch")
        effective_in = (
            receipt.total_amount_in
            * (10_000 - receipt.pool_fee_bps)
            // 10_000
        )
        if receipt.pool_curve == "stable":
            expected_total_out = min(effective_in, receipt.pool_before_reserve_out)
        else:
            expected_total_out = (
                receipt.pool_before_reserve_out
                * effective_in
                // (receipt.pool_before_reserve_in + effective_in)
            )
        if receipt.total_amount_out != expected_total_out:
            raise ValueError("sealed swap receipt clearing amount mismatch")
        expected_before_root = self._sealed_swap_pool_view_root(
            receipt.pool_id,
            receipt.asset_in_id,
            receipt.asset_out_id,
            receipt.pool_before_reserve_in,
            receipt.pool_before_reserve_out,
            receipt.pool_fee_bps,
            receipt.pool_curve,
        )
        expected_after_root = self._sealed_swap_pool_view_root(
            receipt.pool_id,
            receipt.asset_in_id,
            receipt.asset_out_id,
            receipt.pool_after_reserve_in,
            receipt.pool_after_reserve_out,
            receipt.pool_fee_bps,
            receipt.pool_curve,
        )
        if receipt.pool_before_root != expected_before_root:
            raise ValueError("sealed swap receipt pool before root mismatch")
        if receipt.pool_after_root != expected_after_root:
            raise ValueError("sealed swap receipt pool after root mismatch")
        expected_route = domain_hash(
            "SEALED-SWAP-ROUTE",
            receipt.pool_id,
            receipt.asset_in_id,
            receipt.asset_out_id,
            receipt.pool_before_root,
            receipt.pool_after_root,
        )
        if receipt.route_commitment != expected_route:
            raise ValueError("sealed swap receipt route mismatch")
        fill_root, minimum_root, surplus_root, total_surplus = (
            self._sealed_swap_receipt_roots(tx)
        )
        if receipt.fill_commitment_root != fill_root:
            raise ValueError("sealed swap receipt fill root mismatch")
        if receipt.minimum_output_root != minimum_root:
            raise ValueError("sealed swap receipt minimum root mismatch")
        if receipt.surplus_commitment_root != surplus_root:
            raise ValueError("sealed swap receipt surplus root mismatch")
        if receipt.total_surplus_amount != total_surplus:
            raise ValueError("sealed swap receipt surplus mismatch")
        if receipt.clearing_price_numerator != tx.total_amount_out:
            raise ValueError("sealed swap receipt clearing numerator mismatch")
        if receipt.clearing_price_denominator != tx.total_amount_in:
            raise ValueError("sealed swap receipt clearing denominator mismatch")
        if (
            receipt.clearing_price_commitment_root
            != receipt.expected_clearing_price_commitment_root()
        ):
            raise ValueError("sealed swap receipt clearing price commitment mismatch")
        if (
            receipt.aggregate_surplus_commitment_root
            != receipt.expected_aggregate_surplus_commitment_root()
        ):
            raise ValueError("sealed swap receipt aggregate surplus commitment mismatch")
        expected_receipt_id = domain_hash(
            "SEALED-SWAP-SETTLEMENT-RECEIPT-ID",
            CHAIN_ID,
            receipt.block_height,
            receipt.tx_public_hash,
            receipt.intent_root,
            receipt.solver_label,
        )
        if receipt.receipt_id != expected_receipt_id:
            raise ValueError("sealed swap receipt id mismatch")
        if not verify_authorization(
            receipt.solver_label,
            "sealed_swap_settlement_receipt",
            receipt.unsigned_record(),
            receipt.auth_scheme,
            receipt.auth_public_key,
            receipt.auth_transcript_hash,
            receipt.auth_signature,
        ):
            raise ValueError("invalid sealed swap settlement receipt authorization")

    def sealed_swap_settlement_receipt_root(self) -> str:
        return merkle_root(
            "SEALED-SWAP-SETTLEMENT-RECEIPT",
            [
                receipt.public_record()
                for receipt in sorted(
                    self.sealed_swap_settlement_receipts.values(),
                    key=lambda item: item.receipt_id,
                )
            ],
        )

    def produce_block(
        self,
        proposer_id: str = "devnet-proposer",
        include_pending: bool = True,
    ) -> L2Block:
        proposer = self._require_validator_label(proposer_id)
        txs = tuple(self.pending) if include_pending else ()
        if include_pending and not txs and self.pending_admissions:
            self.pending_admissions.clear()
        mempool_admissions = tuple(self.pending_admissions) if include_pending else ()
        mempool_admission_root = merkle_root(
            "MEMPOOL-ADMISSION",
            [admission.public_record() for admission in mempool_admissions],
        )
        mempool_admission_count = len(mempool_admissions)
        execution_profile = self._block_execution_profile(txs)
        for tx in txs:
            self._verify_transaction_auth(tx)
        if include_pending:
            self._verify_pending_mempool_admissions(txs)
        self._expire_sealed_swap_auctions_at_height(len(self.blocks))
        for tx_index, tx in enumerate(txs):
            self._apply_transaction(tx, tx_index)

        height = len(self.blocks)
        epoch = height // self.epoch_size
        prev_block_hash = self.blocks[-1].header.block_hash() if self.blocks else "GENESIS"
        previous_state_root = self.blocks[-1].header.state_root if self.blocks else "GENESIS"
        tx_root = merkle_root("TX", [tx.public_record() for tx in txs])
        note_root = merkle_root("NOTE", sorted(note.commitment for note in self.notes.values()))
        nullifier_root = merkle_root("NULLIFIER", sorted(self.spent_nullifiers))
        contract_root = self.contract_root()
        account_root = self.account_root()
        asset_root = self.asset_root()
        bridge_root = self.bridge_root()
        fee_root = merkle_root("FEE", sorted(self.fees_collected.items()))
        policy_root = crypto_policy_root()
        active_validators = self._active_validators()
        da_record = self._build_data_availability_record(
            height,
            tx_root,
            txs,
            mempool_admissions,
            execution_profile,
            active_validators,
        )
        da_root = da_record.da_root()
        state_root = domain_hash(
            "STATE",
            note_root,
            nullifier_root,
            contract_root,
            account_root,
            asset_root,
            bridge_root,
            fee_root,
            policy_root,
        )
        validator_set_root = merkle_root(
            "VALIDATOR-SET",
            [validator.public_record() for validator in active_validators],
        )
        vote_payload = {
            "chain_id": CHAIN_ID,
            "height": height,
            "epoch": epoch,
            "prev_block_hash": prev_block_hash,
            "tx_root": tx_root,
            "mempool_admission_root": mempool_admission_root,
            "mempool_admission_count": mempool_admission_count,
            "state_root": state_root,
            "note_root": note_root,
            "nullifier_root": nullifier_root,
            "contract_root": contract_root,
            "account_root": account_root,
            "asset_root": asset_root,
            "bridge_root": bridge_root,
            "da_root": da_root,
            "fee_root": fee_root,
            "crypto_policy_root": policy_root,
            "execution_profile": execution_profile.public_record(),
            "proposer_id": proposer.validator_id,
            "validator_set_root": validator_set_root,
        }
        votes = [
            {
                "validator_id": validator.validator_id,
                "stake": validator.stake,
                **sign_authorization(validator.label, "validator_vote", vote_payload),
            }
            for validator in active_validators
        ]
        pq_vote_root = merkle_root("PQ-VOTE", votes)
        validator_stake_weight = sum(vote["stake"] for vote in votes)
        total_stake = sum(validator.stake for validator in active_validators)
        soft_finality = total_stake > 0 and validator_stake_weight * 3 > total_stake * 2

        header = L2BlockHeader(
            version=1,
            chain_id=CHAIN_ID,
            height=height,
            epoch=epoch,
            timestamp_ms=int(time.time() * 1000),
            prev_block_hash=prev_block_hash,
            tx_root=tx_root,
            mempool_admission_root=mempool_admission_root,
            mempool_admission_count=mempool_admission_count,
            state_root=state_root,
            note_root=note_root,
            nullifier_root=nullifier_root,
            contract_root=contract_root,
            account_root=account_root,
            asset_root=asset_root,
            bridge_root=bridge_root,
            da_root=da_root,
            fee_root=fee_root,
            crypto_policy_root=policy_root,
            execution_profile=execution_profile,
            proposer_id=proposer.validator_id,
            validator_set_root=validator_set_root,
            pq_vote_root=pq_vote_root,
            validator_vote_count=len(votes),
            validator_stake_weight=validator_stake_weight,
            soft_finality=soft_finality,
        )
        block = L2Block(header=header, transactions=txs)
        self.blocks.append(block)
        self.da_records[height] = da_record
        privacy_aggregate = self._build_privacy_proof_aggregate(block)
        self._verify_privacy_proof_aggregate(privacy_aggregate)
        self.privacy_proof_aggregates[height] = privacy_aggregate
        certificate = self._build_validity_certificate(
            block,
            previous_state_root=previous_state_root,
            prover_label=proposer.label,
        )
        self._verify_validity_certificate(certificate)
        self.validity_certificates[height] = certificate
        if include_pending:
            self.pending.clear()
            self.pending_admissions.clear()
        return block

    def _apply_transaction(self, tx: DevnetTransaction, tx_index: int = 0) -> None:
        if isinstance(tx, AssetMint):
            self.notes[tx.output_note.note_id] = tx.output_note
            self._update_asset_supply(tx.asset_id, minted_delta=tx.amount)
            return

        if isinstance(tx, AssetBurn):
            self.notes.pop(tx.spent_note_id)
            self.spent_nullifiers.add(tx.nullifier)
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            self._update_asset_supply(tx.asset_id, burned_delta=tx.amount)
            return

        if isinstance(tx, PrivateTransfer):
            spent = self.notes.pop(tx.spent_note_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[spent.asset_id] += tx.fee
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, PrivateTransferBatch):
            input_notes = [self.notes.pop(note_id) for note_id in tx.spent_note_ids]
            for nullifier in tx.nullifiers:
                self.spent_nullifiers.add(nullifier)
            self.fees_collected[input_notes[0].asset_id] += tx.fee
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, AmmLiquidityAdd):
            note_a = self.notes.pop(tx.spent_note_a_id)
            note_b = self.notes.pop(tx.spent_note_b_id)
            pool = self._require_pool(tx.pool_id)
            self.spent_nullifiers.add(tx.nullifier_a)
            self.spent_nullifiers.add(tx.nullifier_b)
            self.fees_collected[note_a.asset_id] += tx.network_fee
            self.pools[tx.pool_id] = AmmPool(
                pool_id=pool.pool_id,
                asset_a_id=pool.asset_a_id,
                asset_b_id=pool.asset_b_id,
                lp_asset_id=pool.lp_asset_id,
                reserve_a=pool.reserve_a + tx.amount_a,
                reserve_b=pool.reserve_b + tx.amount_b,
                total_lp=pool.total_lp + tx.lp_minted,
                fee_bps=pool.fee_bps,
                curve=pool.curve,
            )
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            self._update_asset_supply(pool.lp_asset_id, minted_delta=tx.lp_minted)
            return

        if isinstance(tx, AmmSwap):
            note_in = self.notes.pop(tx.spent_note_id)
            pool = self._require_pool(tx.pool_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[note_in.asset_id] += tx.network_fee
            if tx.asset_in_id == pool.asset_a_id:
                updated_pool = AmmPool(
                    pool_id=pool.pool_id,
                    asset_a_id=pool.asset_a_id,
                    asset_b_id=pool.asset_b_id,
                    lp_asset_id=pool.lp_asset_id,
                    reserve_a=pool.reserve_a + tx.amount_in,
                    reserve_b=pool.reserve_b - tx.amount_out,
                    total_lp=pool.total_lp,
                    fee_bps=pool.fee_bps,
                    curve=pool.curve,
                )
            else:
                updated_pool = AmmPool(
                    pool_id=pool.pool_id,
                    asset_a_id=pool.asset_a_id,
                    asset_b_id=pool.asset_b_id,
                    lp_asset_id=pool.lp_asset_id,
                    reserve_a=pool.reserve_a - tx.amount_out,
                    reserve_b=pool.reserve_b + tx.amount_in,
                    total_lp=pool.total_lp,
                    fee_bps=pool.fee_bps,
                    curve=pool.curve,
                )
            if updated_pool.reserve_a < 0 or updated_pool.reserve_b < 0:
                raise ValueError("AMM swap would make a negative reserve")
            self.pools[tx.pool_id] = updated_pool
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, AmmBatchSwap):
            input_notes = [self.notes.pop(note_id) for note_id in tx.spent_note_ids]
            pool = self._require_pool(tx.pool_id)
            for nullifier in tx.nullifiers:
                self.spent_nullifiers.add(nullifier)
            self.fees_collected[input_notes[0].asset_id] += tx.network_fee
            if tx.asset_in_id == pool.asset_a_id:
                updated_pool = AmmPool(
                    pool_id=pool.pool_id,
                    asset_a_id=pool.asset_a_id,
                    asset_b_id=pool.asset_b_id,
                    lp_asset_id=pool.lp_asset_id,
                    reserve_a=pool.reserve_a + tx.total_amount_in,
                    reserve_b=pool.reserve_b - tx.total_amount_out,
                    total_lp=pool.total_lp,
                    fee_bps=pool.fee_bps,
                    curve=pool.curve,
                )
            else:
                updated_pool = AmmPool(
                    pool_id=pool.pool_id,
                    asset_a_id=pool.asset_a_id,
                    asset_b_id=pool.asset_b_id,
                    lp_asset_id=pool.lp_asset_id,
                    reserve_a=pool.reserve_a - tx.total_amount_out,
                    reserve_b=pool.reserve_b + tx.total_amount_in,
                    total_lp=pool.total_lp,
                    fee_bps=pool.fee_bps,
                    curve=pool.curve,
                )
            if updated_pool.reserve_a < 0 or updated_pool.reserve_b < 0:
                raise ValueError("AMM batch swap would make a negative reserve")
            self.pools[tx.pool_id] = updated_pool
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, AmmRouteSwap):
            simulation = self._simulate_amm_route(
                tx.pool_ids,
                tx.asset_in_id,
                tx.amount_in,
            )
            if tuple(tx.asset_path) != simulation["asset_path"]:
                raise ValueError("route swap asset path mismatch")
            if tuple(tx.hop_amounts) != simulation["hop_amounts"]:
                raise ValueError("route swap hop amount mismatch")
            if tx.amount_out != simulation["amount_out"]:
                raise ValueError("invalid route swap output amount")
            note_in = self.notes.pop(tx.spent_note_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[note_in.asset_id] += tx.network_fee
            for pool_id, updated_pool in simulation["updated_pools"].items():
                self.pools[pool_id] = updated_pool
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, DarkPoolSwap):
            note_a = self.notes.pop(tx.spent_note_a_id)
            note_b = self.notes.pop(tx.spent_note_b_id)
            self.spent_nullifiers.add(tx.nullifier_a)
            self.spent_nullifiers.add(tx.nullifier_b)
            self.fees_collected[note_a.asset_id] += tx.network_fee_a
            self.fees_collected[note_b.asset_id] += tx.network_fee_b
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, AmmSealedBatchSwap):
            input_notes = [
                self.notes.pop(fill.intent.spent_note_id)
                for fill in tx.fills
            ]
            pool = self._require_pool(tx.pool_id)
            for fill in tx.fills:
                self.spent_nullifiers.add(fill.intent.nullifier)
            self.fees_collected[input_notes[0].asset_id] += tx.network_fee_total
            if tx.asset_in_id == pool.asset_a_id:
                updated_pool = AmmPool(
                    pool_id=pool.pool_id,
                    asset_a_id=pool.asset_a_id,
                    asset_b_id=pool.asset_b_id,
                    lp_asset_id=pool.lp_asset_id,
                    reserve_a=pool.reserve_a + tx.total_amount_in,
                    reserve_b=pool.reserve_b - tx.total_amount_out,
                    total_lp=pool.total_lp,
                    fee_bps=pool.fee_bps,
                    curve=pool.curve,
                )
            else:
                updated_pool = AmmPool(
                    pool_id=pool.pool_id,
                    asset_a_id=pool.asset_a_id,
                    asset_b_id=pool.asset_b_id,
                    lp_asset_id=pool.lp_asset_id,
                    reserve_a=pool.reserve_a - tx.total_amount_out,
                    reserve_b=pool.reserve_b + tx.total_amount_in,
                    total_lp=pool.total_lp,
                    fee_bps=pool.fee_bps,
                    curve=pool.curve,
                )
            if updated_pool.reserve_a < 0 or updated_pool.reserve_b < 0:
                raise ValueError("sealed AMM batch swap would make a negative reserve")
            self.pools[tx.pool_id] = updated_pool
            receipt = self._build_sealed_swap_settlement_receipt(
                tx,
                pool_before=pool,
                pool_after=updated_pool,
                block_height=len(self.blocks),
            )
            self.sealed_swap_settlement_receipts[receipt.receipt_id] = receipt
            self._mark_sealed_swap_commitments_revealed(tx)
            self._mark_sealed_swap_solver_bids_settled(tx)
            for output in tx.output_notes():
                self.notes[output.note_id] = output
            return

        if isinstance(tx, BridgeMint):
            self._require_bridge_active()
            self.notes[tx.output_note.note_id] = tx.output_note
            self._update_asset_supply(tx.output_note.asset_id, minted_delta=tx.amount)
            request = self.bridge_deposit_addresses[tx.deposit_id]
            observation = self.bridge_observations[tx.deposit_id]
            self.bridge_deposit_addresses[tx.deposit_id] = replace(request, status="minted")
            self.bridge_observations[tx.deposit_id] = replace(observation, status="minted")
            return

        if isinstance(tx, BridgeWithdraw):
            self._require_bridge_active()
            spent = self.notes.pop(tx.spent_note_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[spent.asset_id] += tx.bridge_fee
            self._update_asset_supply(spent.asset_id, burned_delta=tx.amount)
            record = BridgeWithdrawalRecord(
                withdrawal_id=tx.withdrawal_id,
                nullifier=tx.nullifier,
                amount=tx.amount,
                monero_address_hash=tx.monero_address_hash,
                bridge_fee=tx.bridge_fee,
                status="queued",
                bridge_signature_root=tx.bridge_signature_root,
                queue_signer_set_id=tx.queue_signer_set_id,
                queue_signer_threshold=tx.queue_signer_threshold,
                queue_signer_count=tx.queue_signer_count,
                requested_at_height=len(self.blocks),
                amount_bucket=(
                    ceil_div(tx.amount, BRIDGE_WITHDRAWAL_AMOUNT_BUCKET)
                    * BRIDGE_WITHDRAWAL_AMOUNT_BUCKET
                ),
                privacy_delay_blocks=BRIDGE_WITHDRAWAL_RELEASE_DELAY_BLOCKS,
                release_not_before_height=(
                    len(self.blocks) + BRIDGE_WITHDRAWAL_RELEASE_DELAY_BLOCKS
                ),
            )
            self.bridge_withdrawals[tx.withdrawal_id] = record
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            return

        if isinstance(tx, PaymasterDeposit):
            self.notes.pop(tx.spent_note_id)
            self.spent_nullifiers.add(tx.nullifier)
            paymaster = self._require_paymaster(tx.paymaster_id)
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            self.paymasters[tx.paymaster_id] = replace(
                paymaster,
                balance=paymaster.balance + tx.amount,
                deposit_count=paymaster.deposit_count + 1,
            )
            return

        if isinstance(tx, ContractCall):
            contract = self._require_contract(tx.contract_id)
            updated, _ = self._execute_contract_call(
                contract,
                tx,
                tx.signer_label,
                dry_run=False,
            )
            tx_hash = domain_hash("CONTRACT-CALL-TX", tx.public_record())
            event = self._record_contract_event(contract, tx, updated, tx_hash=tx_hash)
            self._append_contract_execution_receipt(
                contract,
                tx,
                updated,
                event,
                tx_hash,
                tx_index=tx_index,
                call_index=0,
            )
            if tx.fee_asset_id:
                if tx.paymaster_id:
                    self._debit_paymaster_fee(
                        tx.paymaster_id,
                        signer_label=tx.signer_label,
                        fee=tx.fee,
                    )
                else:
                    self.notes.pop(tx.fee_note_id)
                    self.spent_nullifiers.add(tx.fee_nullifier)
                    if tx.fee_change_note:
                        self.notes[tx.fee_change_note.note_id] = tx.fee_change_note
                self.fees_collected.setdefault(tx.fee_asset_id, 0)
                self.fees_collected[tx.fee_asset_id] += tx.fee
            return

        if isinstance(tx, ContractCallBatch):
            batch_public_record = tx.public_record()
            for index, action in enumerate(tx.calls):
                contract = self._require_contract(action.contract_id)
                call_tx = self._contract_call_from_action(action, tx.signer_label)
                updated, _ = self._execute_contract_call(
                    contract,
                    call_tx,
                    tx.signer_label,
                    dry_run=False,
                )
                event = self._record_contract_event(
                    contract,
                    call_tx,
                    updated,
                    tx_hash=domain_hash(
                        "CONTRACT-CALL-BATCH-TX",
                        batch_public_record,
                        index,
                    ),
                )
                self._append_contract_execution_receipt(
                    contract,
                    call_tx,
                    updated,
                    event,
                    event.tx_hash,
                    tx_index=tx_index,
                    call_index=index,
                )
            if tx.fee_asset_id:
                if tx.paymaster_id:
                    self._debit_paymaster_fee(
                        tx.paymaster_id,
                        signer_label=tx.signer_label,
                        fee=tx.fee,
                    )
                else:
                    self.notes.pop(tx.fee_note_id)
                    self.spent_nullifiers.add(tx.fee_nullifier)
                    if tx.fee_change_note:
                        self.notes[tx.fee_change_note.note_id] = tx.fee_change_note
                self.fees_collected.setdefault(tx.fee_asset_id, 0)
                self.fees_collected[tx.fee_asset_id] += tx.fee
            return

        if isinstance(tx, ContractDeposit):
            self.notes.pop(tx.spent_note_id)
            self.spent_nullifiers.add(tx.nullifier)
            contract = self._require_contract(tx.contract_id)
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            updated = self._update_contract_asset_balance(contract, tx.asset_id, tx.amount)
            self.fees_collected.setdefault(tx.asset_id, 0)
            self.fees_collected[tx.asset_id] += tx.network_fee
            self._append_contract_event(
                contract_id=updated.contract_id,
                event_name="contract.deposited",
                tx_hash=domain_hash("CONTRACT-DEPOSIT-TX", tx.public_record()),
                contract_storage_root=updated.storage_root(),
                public_data={
                    "asset_id": tx.asset_id,
                    "amount": tx.amount,
                    "network_fee": tx.network_fee,
                    "new_asset_balance": (updated.asset_balances or {}).get(tx.asset_id, 0),
                    "asset_balance_root": updated.asset_balance_root(),
                    "caller_commitment": domain_hash("CONTRACT-CALLER", tx.signer_label),
                },
            )
            return

        if isinstance(tx, ContractWithdraw):
            contract = self._require_contract(tx.contract_id)
            allowance_spender_commitment = ""
            remaining_allowance_commitment = ""
            if tx.signer_label != contract.owner_label and contract.template == "vault":
                allowance_spender_commitment = domain_hash("CONTRACT-CALLER", tx.signer_label)
                contract = self._spend_vault_allowance(
                    contract,
                    tx.asset_id,
                    allowance_spender_commitment,
                    tx.amount + tx.network_fee,
                )
                allowance_key = self._vault_allowance_key(
                    tx.asset_id,
                    allowance_spender_commitment,
                )
                remaining_record = dict(
                    contract.storage.get("allowances", {}).get(allowance_key, {})
                )
                remaining_allowance_commitment = remaining_record.get(
                    "allowance_commitment",
                    "",
                )
            updated = self._update_contract_asset_balance(
                contract,
                tx.asset_id,
                -(tx.amount + tx.network_fee),
            )
            self.notes[tx.output_note.note_id] = tx.output_note
            self.fees_collected.setdefault(tx.asset_id, 0)
            self.fees_collected[tx.asset_id] += tx.network_fee
            self._append_contract_event(
                contract_id=updated.contract_id,
                event_name="contract.withdrawn",
                tx_hash=domain_hash("CONTRACT-WITHDRAW-TX", tx.public_record()),
                contract_storage_root=updated.storage_root(),
                public_data={
                    "asset_id": tx.asset_id,
                    "amount": tx.amount,
                    "network_fee": tx.network_fee,
                    "remaining_asset_balance": (updated.asset_balances or {}).get(tx.asset_id, 0),
                    "asset_balance_root": updated.asset_balance_root(),
                    "caller_commitment": domain_hash("CONTRACT-CALLER", tx.signer_label),
                    "allowance_spender_commitment": allowance_spender_commitment,
                    "remaining_allowance_commitment": remaining_allowance_commitment,
                    "allowance_root": updated.storage.get("allowance_root", ""),
                    "recipient_commitment": tx.public_record()["recipient_commitment"],
                },
            )
            return

        if isinstance(tx, LendingBorrow):
            spent = self.notes.pop(tx.spent_collateral_note_id)
            market = self._require_lending_market(tx.market_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[market.collateral_asset_id] += tx.borrow_fee
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            debt_outputs = [
                note for note in tx.output_notes if note.asset_id == market.debt_asset_id
            ]
            position = LendingPosition(
                position_id=tx.position_id,
                market_id=tx.market_id,
                owner_view_key=spent.owner_view_key,
                collateral_asset_id=market.collateral_asset_id,
                debt_asset_id=market.debt_asset_id,
                collateral_amount=tx.collateral_amount,
                debt_amount=tx.borrow_amount,
                collateral_commitment=spent.commitment,
                debt_commitment=debt_outputs[0].commitment,
                status="active",
                created_at_height=len(self.blocks),
            )
            self.lending_positions[tx.position_id] = position
            self.lending_markets[tx.market_id] = replace(
                market,
                total_collateral=market.total_collateral + tx.collateral_amount,
                total_debt=market.total_debt + tx.borrow_amount,
            )
            return

        if isinstance(tx, LendingRepay):
            spent = self.notes.pop(tx.spent_debt_note_id)
            position = self.lending_positions[tx.position_id]
            market = self._require_lending_market(position.market_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[position.debt_asset_id] += tx.repay_fee
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            self.lending_positions[tx.position_id] = replace(
                position,
                status="repaid",
                closed_at_height=len(self.blocks),
            )
            self.lending_markets[position.market_id] = replace(
                market,
                total_collateral=market.total_collateral - position.collateral_amount,
                total_debt=market.total_debt - position.debt_amount,
            )
            return

        if isinstance(tx, LendingLiquidation):
            self.notes.pop(tx.spent_debt_note_id)
            position = self.lending_positions[tx.position_id]
            market = self._require_lending_market(position.market_id)
            self.spent_nullifiers.add(tx.nullifier)
            self.fees_collected[position.debt_asset_id] += tx.liquidation_fee
            for output in tx.output_notes:
                self.notes[output.note_id] = output
            self.lending_positions[tx.position_id] = replace(
                position,
                status="liquidated",
                closed_at_height=len(self.blocks),
            )
            self.lending_markets[position.market_id] = replace(
                market,
                total_collateral=market.total_collateral - position.collateral_amount,
                total_debt=market.total_debt - position.debt_amount,
            )
            return

        if isinstance(tx, AccountRotation):
            account = self.accounts[tx.account_id]
            self.retired_account_labels.add(account.current_label)
            self.accounts[tx.account_id] = AccountState(
                account_id=account.account_id,
                current_label=tx.new_label,
                spend_public_key=tx.new_spend_public_key,
                recovery_public_key=tx.new_recovery_public_key,
                network_public_key=tx.new_network_public_key,
                rotation_nonce=tx.rotation_nonce,
                status=account.status,
            )
            for session_id, session in list(self.wallet_sessions.items()):
                if session.account_id == tx.account_id and session.status == "active":
                    self.wallet_sessions[session_id] = replace(session, status="revoked")
            return

        raise ValueError("unsupported transaction type")

    def anchor_commitment(self) -> str:
        if not self.blocks:
            return domain_hash("ANCHOR", CHAIN_ID, "GENESIS")

        return self._anchor_commitment_for_block(len(self.blocks) - 1)

    def anchor_submission_root(self) -> str:
        return merkle_root(
            "ANCHOR-SUBMISSION",
            [
                submission.public_record()
                for submission in sorted(
                    self.anchor_submissions.values(),
                    key=lambda item: item.anchor_id,
                )
            ],
        )

    def settlement_status(self, block_height: int | None = None) -> Dict[str, Any]:
        if not self.blocks:
            raise ValueError("cannot compute settlement status before the first L2 block")
        if block_height is None:
            block_height = len(self.blocks) - 1
        if block_height < 0 or block_height >= len(self.blocks):
            raise ValueError("unknown block height")

        header = self.blocks[block_height].header
        local_checkpoint = self.epoch_checkpoint_for_block(block_height)
        covering_submissions: List[AnchorSubmission] = []
        for submission in self.anchor_submissions.values():
            if submission.epoch != header.epoch:
                continue
            if submission.checkpoint_root:
                epoch_start_height = submission.epoch_start_height
                epoch_end_height = submission.epoch_end_height
            else:
                epoch_start_height = submission.epoch * self.epoch_size
                epoch_end_height = submission.block_height
            if epoch_start_height <= block_height <= epoch_end_height:
                covering_submissions.append(submission)

        covering_submissions.sort(
            key=lambda item: (
                item.status != "final",
                -item.confirmations,
                -item.epoch_end_height,
                item.anchor_id,
            )
        )
        best_anchor = covering_submissions[0] if covering_submissions else None
        anchored = best_anchor is not None
        monero_final = any(item.status == "final" for item in covering_submissions)
        if monero_final:
            status = "monero_final"
        elif anchored:
            status = "anchored"
        elif header.soft_finality:
            status = "soft_final"
        else:
            status = "produced"

        return {
            "status": status,
            "block_height": block_height,
            "epoch": header.epoch,
            "block_hash": header.block_hash(),
            "soft_finality": header.soft_finality,
            "validator_vote_count": header.validator_vote_count,
            "validator_stake_weight": header.validator_stake_weight,
            "checkpointed": True,
            "local_checkpoint_root": local_checkpoint.checkpoint_root(),
            "local_checkpoint": local_checkpoint.anchor_record(),
            "anchored": anchored,
            "monero_final": monero_final,
            "best_anchor": best_anchor.public_record() if best_anchor else None,
            "covering_anchor_count": len(covering_submissions),
            "covering_anchors": [
                submission.public_record()
                for submission in covering_submissions
            ],
            "anchor_submission_root": self.anchor_submission_root(),
        }

    def submit_anchor(
        self,
        block_height: int | None = None,
        submitter_label: str = "anchor-submitter",
        monero_txid: str | None = None,
    ) -> AnchorSubmission:
        if not self.blocks:
            raise ValueError("cannot submit an anchor before the first L2 block")
        if not submitter_label:
            raise ValueError("submitter label is required")
        if block_height is None:
            block_height = len(self.blocks) - 1
        if block_height < 0 or block_height >= len(self.blocks):
            raise ValueError("unknown block height")

        header = self.blocks[block_height].header
        anchor_commitment = self._anchor_commitment_for_block(block_height)
        for existing in self.anchor_submissions.values():
            if (
                existing.block_height == block_height
                and hmac.compare_digest(existing.anchor_commitment, anchor_commitment)
            ):
                raise ValueError("anchor already submitted for block")

        checkpoint = self.epoch_checkpoint_for_block(block_height)
        if monero_txid is None:
            monero_txid = "xmr-anchor-devnet-" + domain_hash(
                "MONERO-ANCHOR-TXID",
                block_height,
                anchor_commitment,
                submitter_label,
                len(self.anchor_submissions),
                out_len=32,
            )
        monero_txid_hash = domain_hash("MONERO-TXID-HASH", monero_txid)
        anchor_id = domain_hash(
            "ANCHOR-SUBMISSION-ID",
            block_height,
            anchor_commitment,
            submitter_label,
            monero_txid_hash,
        )
        unsigned = AnchorSubmission(
            anchor_id=anchor_id,
            block_height=block_height,
            epoch=header.epoch,
            anchor_commitment=anchor_commitment,
            checkpoint_root=checkpoint.checkpoint_root(),
            epoch_start_height=checkpoint.start_height,
            epoch_end_height=checkpoint.end_height,
            epoch_block_count=checkpoint.block_count,
            block_hash=header.block_hash(),
            state_root=header.state_root,
            bridge_root=header.bridge_root,
            submitter_label=submitter_label,
            monero_txid=monero_txid,
            confirmations=0,
            status="submitted",
            submitted_at_ms=int(time.time() * 1000),
        )
        auth = sign_authorization(
            submitter_label,
            "monero_anchor_submission",
            unsigned.unsigned_record(),
        )
        submission = replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )
        self._verify_anchor_submission(submission)
        self.anchor_submissions[anchor_id] = submission
        return submission

    def confirm_anchor(
        self,
        anchor_id: str,
        confirmations: int,
        finality_depth: int = 10,
    ) -> AnchorSubmission:
        if anchor_id not in self.anchor_submissions:
            raise ValueError("unknown anchor submission")
        if confirmations < 0:
            raise ValueError("confirmations must be non-negative")
        if finality_depth <= 0:
            raise ValueError("finality_depth must be positive")
        submission = self.anchor_submissions[anchor_id]
        if confirmations < submission.confirmations:
            raise ValueError("anchor confirmations cannot decrease")

        status = "final" if confirmations >= finality_depth else "submitted"
        finalized_at_ms = submission.finalized_at_ms
        if status == "final" and finalized_at_ms == 0:
            finalized_at_ms = int(time.time() * 1000)
        updated = replace(
            submission,
            confirmations=confirmations,
            status=status,
            finalized_at_ms=finalized_at_ms,
        )
        self._verify_anchor_submission(updated)
        self.anchor_submissions[anchor_id] = updated
        return updated

    def _verify_anchor_submission(self, submission: AnchorSubmission) -> None:
        if submission.block_height < 0 or submission.block_height >= len(self.blocks):
            raise ValueError("unknown block height")
        if submission.confirmations < 0:
            raise ValueError("confirmations must be non-negative")
        if submission.status not in {"submitted", "final"}:
            raise ValueError("invalid anchor status")
        if submission.status == "submitted" and submission.finalized_at_ms:
            raise ValueError("submitted anchor cannot have finalized timestamp")
        if submission.status == "final" and submission.finalized_at_ms <= 0:
            raise ValueError("final anchor requires finalized timestamp")

        header = self.blocks[submission.block_height].header
        expected_anchor = self._anchor_commitment_for_block(submission.block_height)
        checkpoint = self.epoch_checkpoint_for_block(submission.block_height)
        if submission.epoch != header.epoch:
            raise ValueError("anchor epoch mismatch")
        if not hmac.compare_digest(submission.anchor_commitment, expected_anchor):
            raise ValueError("anchor commitment mismatch")
        if submission.checkpoint_root:
            if not hmac.compare_digest(submission.checkpoint_root, checkpoint.checkpoint_root()):
                raise ValueError("anchor checkpoint root mismatch")
            if submission.epoch_start_height != checkpoint.start_height:
                raise ValueError("anchor checkpoint start mismatch")
            if submission.epoch_end_height != checkpoint.end_height:
                raise ValueError("anchor checkpoint end mismatch")
            if submission.epoch_block_count != checkpoint.block_count:
                raise ValueError("anchor checkpoint block count mismatch")
        if not hmac.compare_digest(submission.block_hash, header.block_hash()):
            raise ValueError("anchor block hash mismatch")
        if not hmac.compare_digest(submission.state_root, header.state_root):
            raise ValueError("anchor state root mismatch")
        if not hmac.compare_digest(submission.bridge_root, header.bridge_root):
            raise ValueError("anchor bridge root mismatch")
        if not verify_authorization(
            submission.submitter_label,
            "monero_anchor_submission",
            submission.unsigned_record(),
            submission.auth_scheme,
            submission.auth_public_key,
            submission.auth_transcript_hash,
            submission.auth_signature,
        ):
            raise ValueError("invalid anchor authorization")

    def epoch_checkpoint_for_block(self, block_height: int) -> EpochCheckpoint:
        if block_height < 0 or block_height >= len(self.blocks):
            raise ValueError("unknown block height")
        return self.epoch_checkpoint(
            epoch=self.blocks[block_height].header.epoch,
            up_to_height=block_height,
        )

    def epoch_checkpoint(
        self,
        epoch: int | None = None,
        up_to_height: int | None = None,
    ) -> EpochCheckpoint:
        if not self.blocks:
            raise ValueError("cannot build an epoch checkpoint before the first L2 block")
        if up_to_height is None:
            if epoch is None:
                up_to_height = len(self.blocks) - 1
                epoch = self.blocks[up_to_height].header.epoch
            else:
                if epoch < 0:
                    raise ValueError("epoch must be non-negative")
                up_to_height = min(
                    len(self.blocks) - 1,
                    (epoch + 1) * self.epoch_size - 1,
                )
        if up_to_height < 0 or up_to_height >= len(self.blocks):
            raise ValueError("unknown block height")
        header = self.blocks[up_to_height].header
        epoch = header.epoch if epoch is None else epoch
        if epoch < 0:
            raise ValueError("epoch must be non-negative")
        if header.epoch != epoch:
            raise ValueError("block height is outside requested epoch")
        start_height = epoch * self.epoch_size
        if start_height >= len(self.blocks):
            raise ValueError("unknown epoch")
        headers = [
            block.header
            for block in self.blocks[start_height:up_to_height + 1]
            if block.header.epoch == epoch
        ]
        if not headers:
            raise ValueError("unknown epoch")
        end_height = headers[-1].height
        block_count = len(headers)
        return EpochCheckpoint(
            epoch=epoch,
            start_height=start_height,
            end_height=end_height,
            block_count=block_count,
            complete=block_count == self.epoch_size,
            block_hash_root=merkle_root(
                "EPOCH-BLOCK-HASH",
                [header.block_hash() for header in headers],
            ),
            tx_root=merkle_root("EPOCH-TX", [header.tx_root for header in headers]),
            state_root=headers[-1].state_root,
            da_root=merkle_root("EPOCH-DA", [header.da_root for header in headers]),
            validity_root=merkle_root(
                "EPOCH-VALIDITY",
                [
                    self.validity_certificates[header.height].certificate_root()
                    for header in headers
                    if header.height in self.validity_certificates
                ],
            ),
            privacy_proof_aggregate_root=merkle_root(
                "EPOCH-PRIVACY-PROOF-AGGREGATE",
                [
                    self.privacy_proof_aggregates[header.height].aggregate_root()
                    for header in headers
                    if header.height in self.privacy_proof_aggregates
                ],
            ),
            bridge_root=headers[-1].bridge_root,
            mempool_admission_root=merkle_root(
                "EPOCH-MEMPOOL-ADMISSION",
                [header.mempool_admission_root for header in headers],
            ),
            validator_set_root=headers[-1].validator_set_root,
            soft_finality_count=sum(int(header.soft_finality) for header in headers),
        )

    def _anchor_commitment_for_block(self, block_index: int) -> str:
        checkpoint = self.epoch_checkpoint_for_block(block_index)
        previous_anchor_root = "GENESIS"
        previous_epoch = checkpoint.epoch - 1
        if previous_epoch >= 0 and previous_epoch * self.epoch_size < len(self.blocks):
            previous_anchor_root = self.epoch_checkpoint(
                epoch=previous_epoch,
            ).checkpoint_root()
        return domain_hash(
            "NEBULA-L2-EPOCH-ANCHOR",
            CHAIN_ID,
            checkpoint.epoch,
            previous_anchor_root,
            checkpoint.anchor_record(),
        )

    def bridge_root(self) -> str:
        return merkle_root(
            "BRIDGE",
            [
                {
                    "wrapped_xmr_asset_id": self.wrapped_xmr_asset_id,
                    "deposits": [
                        item.public_record()
                        for item in sorted(
                            self.bridge_deposit_addresses.values(),
                            key=lambda value: value.deposit_id,
                        )
                    ],
                    "observations": [
                        item.public_record()
                        for item in sorted(
                            self.bridge_observations.values(),
                            key=lambda value: value.deposit_id,
                        )
                    ],
                    "withdrawals": [
                        item.public_record()
                        for item in sorted(
                            self.bridge_withdrawals.values(),
                            key=lambda value: value.withdrawal_id,
                        )
                    ],
                    "withdrawal_challenge_root": self.bridge_withdrawal_challenge_root(),
                    "withdrawal_challenges": [
                        item.public_record()
                        for item in sorted(
                            self.bridge_withdrawal_challenges.values(),
                            key=lambda value: value.challenge_id,
                        )
                    ],
                    "signer_set_root": self.bridge_signer_set_root(),
                    "active_signer_set_id": self.active_bridge_signer_set_id,
                    "signer_sets": [
                        item.public_record()
                        for item in sorted(
                            self.bridge_signer_sets.values(),
                            key=lambda value: value.signer_set_id,
                        )
                    ],
                    "emergency_root": self.bridge_emergency_root(),
                    "paused": self.bridge_paused,
                    "pause_reason_hash": self.bridge_pause_reason_hash,
                    "pause_action_id": self.bridge_pause_action_id,
                    "reserve_report_root": self.bridge_reserve_report_root(),
                    "reserve_reports": [
                        item.public_record()
                        for item in sorted(
                            self.bridge_reserve_reports.values(),
                            key=lambda value: value.report_id,
                        )
                    ],
                }
            ],
        )

    def wallet_notes(self, owner_view_key: str) -> List[Dict[str, Any]]:
        return [
            note.wallet_record()
            for note in sorted(self.notes.values(), key=lambda item: item.note_id)
            if note.owner_view_key == owner_view_key
        ]

    def _transaction_output_notes(self, tx: DevnetTransaction) -> tuple[Note, ...]:
        if isinstance(tx, AssetMint):
            return (tx.output_note,)
        if isinstance(tx, BridgeMint):
            return (tx.output_note,)
        if isinstance(tx, ContractWithdraw):
            return (tx.output_note,)
        if isinstance(tx, AmmSealedBatchSwap):
            return tx.output_notes()
        notes = tuple(getattr(tx, "output_notes", ()) or ())
        if isinstance(tx, (ContractCall, ContractCallBatch)) and tx.fee_change_note:
            notes = notes + (tx.fee_change_note,)
        return notes

    def _wallet_received_events(
        self,
        owner_view_key: str,
        tx: DevnetTransaction,
        source: Dict[str, Any],
        current_note_ids: set[str],
    ) -> List[Dict[str, Any]]:
        events: List[Dict[str, Any]] = []
        for note in self._transaction_output_notes(tx):
            if note.owner_view_key != owner_view_key:
                continue
            record = note.wallet_record()
            if note.note_id in current_note_ids:
                status = "current"
            elif source["status"] == "confirmed":
                status = "spent"
            else:
                status = source["status"]
            events.append({
                "event": "received",
                "status": status,
                "source": dict(source),
                "note_id": record["note_id"],
                "asset_id": record["asset_id"],
                "amount": record["amount"],
                "commitment": record["commitment"],
            })
        return events

    def _wallet_spend_events(
        self,
        owner_view_key: str,
        tx: DevnetTransaction,
        source: Dict[str, Any],
    ) -> List[Dict[str, Any]]:
        events: List[Dict[str, Any]] = []

        def add_spend(
            kind: str,
            note_ids: Sequence[str],
            asset_amounts: Dict[str, int],
            fee_asset_id: str = "",
            fee_units: int = 0,
            extra: Dict[str, Any] | None = None,
        ) -> None:
            if not note_ids and not asset_amounts and not fee_units:
                return
            event = {
                "event": "spent",
                "kind": kind,
                "status": source["status"],
                "source": dict(source),
                "note_ids": list(note_ids),
                "asset_amounts": {
                    asset_id: amount
                    for asset_id, amount in sorted(asset_amounts.items())
                    if amount
                },
                "fee_asset_id": fee_asset_id,
                "fee_units": fee_units,
            }
            if extra:
                event.update(extra)
            events.append(event)

        if isinstance(tx, AssetBurn) and tx.signer_label == owner_view_key:
            add_spend(
                "asset_burn",
                (tx.spent_note_id,),
                {tx.asset_id: tx.amount},
            )
        elif isinstance(tx, PrivateTransfer) and tx.signer_label == owner_view_key:
            asset_id = tx.output_notes[0].asset_id if tx.output_notes else ""
            total = sum(note.amount for note in tx.output_notes) + tx.fee
            add_spend(
                "private_transfer",
                (tx.spent_note_id,),
                {asset_id: total} if asset_id else {},
                fee_asset_id=asset_id,
                fee_units=tx.fee,
            )
        elif isinstance(tx, PrivateTransferBatch) and tx.signer_label == owner_view_key:
            asset_id = tx.output_notes[0].asset_id if tx.output_notes else ""
            total = sum(note.amount for note in tx.output_notes) + tx.fee
            add_spend(
                "private_transfer_batch",
                tx.spent_note_ids,
                {asset_id: total} if asset_id else {},
                fee_asset_id=asset_id,
                fee_units=tx.fee,
            )
        elif isinstance(tx, AmmLiquidityAdd) and tx.signer_label == owner_view_key:
            add_spend(
                "amm_liquidity_add",
                (tx.spent_note_a_id, tx.spent_note_b_id),
                {
                    self.pools[tx.pool_id].asset_a_id if tx.pool_id in self.pools else "asset_a": tx.amount_a + tx.network_fee,
                    self.pools[tx.pool_id].asset_b_id if tx.pool_id in self.pools else "asset_b": tx.amount_b,
                },
                fee_asset_id=(self.pools[tx.pool_id].asset_a_id if tx.pool_id in self.pools else ""),
                fee_units=tx.network_fee,
            )
        elif isinstance(tx, AmmSwap) and tx.signer_label == owner_view_key:
            add_spend(
                "amm_swap",
                (tx.spent_note_id,),
                {tx.asset_in_id: tx.amount_in + tx.network_fee},
                fee_asset_id=tx.asset_in_id,
                fee_units=tx.network_fee,
            )
        elif isinstance(tx, AmmBatchSwap) and tx.signer_label == owner_view_key:
            add_spend(
                "amm_batch_swap",
                tx.spent_note_ids,
                {tx.asset_in_id: tx.total_amount_in + tx.network_fee},
                fee_asset_id=tx.asset_in_id,
                fee_units=tx.network_fee,
            )
        elif isinstance(tx, AmmRouteSwap) and tx.signer_label == owner_view_key:
            add_spend(
                "amm_route_swap",
                (tx.spent_note_id,),
                {tx.asset_in_id: tx.amount_in + tx.network_fee},
                fee_asset_id=tx.asset_in_id,
                fee_units=tx.network_fee,
                extra={"route_root": tx.route_root(), "route_hop_count": len(tx.pool_ids)},
            )
        elif isinstance(tx, DarkPoolSwap):
            if tx.signer_a_label == owner_view_key:
                add_spend(
                    "dark_pool_swap",
                    (tx.spent_note_a_id,),
                    {tx.asset_a_id: tx.amount_a + tx.network_fee_a},
                    fee_asset_id=tx.asset_a_id,
                    fee_units=tx.network_fee_a,
                    extra={"trade_commitment": tx.trade_commitment(), "side": "a"},
                )
            if tx.signer_b_label == owner_view_key:
                add_spend(
                    "dark_pool_swap",
                    (tx.spent_note_b_id,),
                    {tx.asset_b_id: tx.amount_b + tx.network_fee_b},
                    fee_asset_id=tx.asset_b_id,
                    fee_units=tx.network_fee_b,
                    extra={"trade_commitment": tx.trade_commitment(), "side": "b"},
                )
        elif isinstance(tx, AmmSealedBatchSwap):
            for fill in tx.fills:
                intent = fill.intent
                if intent.signer_label != owner_view_key:
                    continue
                add_spend(
                    "sealed_amm_swap",
                    (intent.spent_note_id,),
                    {intent.asset_in_id: intent.amount_in + intent.network_fee},
                    fee_asset_id=intent.asset_in_id,
                    fee_units=intent.network_fee,
                    extra={"intent_hash": intent.intent_hash()},
                )
        elif isinstance(tx, BridgeWithdraw) and tx.signer_label == owner_view_key:
            add_spend(
                "bridge_withdraw",
                (tx.spent_note_id,),
                {tx.output_notes[0].asset_id if tx.output_notes else "wrapped_xmr": tx.amount + tx.bridge_fee},
                fee_asset_id=(tx.output_notes[0].asset_id if tx.output_notes else ""),
                fee_units=tx.bridge_fee,
                extra={"withdrawal_id": tx.withdrawal_id},
            )
        elif isinstance(tx, PaymasterDeposit) and tx.signer_label == owner_view_key:
            asset_id = tx.output_notes[0].asset_id if tx.output_notes else ""
            add_spend(
                "paymaster_deposit",
                (tx.spent_note_id,),
                {asset_id: tx.amount} if asset_id else {},
                extra={"paymaster_id": tx.paymaster_id},
            )
        elif isinstance(tx, ContractCall) and tx.signer_label == owner_view_key and tx.fee_note_id:
            add_spend(
                "contract_call_fee",
                (tx.fee_note_id,),
                {tx.fee_asset_id: tx.fee},
                fee_asset_id=tx.fee_asset_id,
                fee_units=tx.fee,
                extra={"contract_id": tx.contract_id, "entrypoint": tx.entrypoint},
            )
        elif isinstance(tx, ContractCallBatch) and tx.signer_label == owner_view_key and tx.fee_note_id:
            add_spend(
                "contract_call_batch_fee",
                (tx.fee_note_id,),
                {tx.fee_asset_id: tx.fee},
                fee_asset_id=tx.fee_asset_id,
                fee_units=tx.fee,
                extra={
                    "call_count": len(tx.calls),
                    "call_root": tx.call_root(),
                },
            )
        elif isinstance(tx, ContractDeposit) and tx.signer_label == owner_view_key:
            add_spend(
                "contract_deposit",
                (tx.spent_note_id,),
                {tx.asset_id: tx.amount + tx.network_fee},
                fee_asset_id=tx.asset_id,
                fee_units=tx.network_fee,
                extra={"contract_id": tx.contract_id},
            )
        elif isinstance(tx, LendingBorrow) and tx.signer_label == owner_view_key:
            market = self.lending_markets.get(tx.market_id)
            asset_id = market.collateral_asset_id if market else ""
            add_spend(
                "lending_borrow",
                (tx.spent_collateral_note_id,),
                {asset_id: tx.collateral_amount + tx.borrow_fee} if asset_id else {},
                fee_asset_id=asset_id,
                fee_units=tx.borrow_fee,
                extra={"position_id": tx.position_id},
            )
        elif isinstance(tx, LendingRepay) and tx.signer_label == owner_view_key:
            position = self.lending_positions.get(tx.position_id)
            asset_id = position.debt_asset_id if position else ""
            amount = (position.debt_amount if position else 0) + tx.repay_fee
            add_spend(
                "lending_repay",
                (tx.spent_debt_note_id,),
                {asset_id: amount} if asset_id else {},
                fee_asset_id=asset_id,
                fee_units=tx.repay_fee,
                extra={"position_id": tx.position_id},
            )
        elif isinstance(tx, LendingLiquidation) and tx.signer_label == owner_view_key:
            position = self.lending_positions.get(tx.position_id)
            asset_id = position.debt_asset_id if position else ""
            amount = (position.debt_amount if position else 0) + tx.liquidation_fee
            add_spend(
                "lending_liquidation",
                (tx.spent_debt_note_id,),
                {asset_id: amount} if asset_id else {},
                fee_asset_id=asset_id,
                fee_units=tx.liquidation_fee,
                extra={"position_id": tx.position_id},
            )
        return events

    def wallet_history(self, owner_view_key: str) -> Dict[str, Any]:
        current_note_ids = set(self.notes)
        events: List[Dict[str, Any]] = []
        indexed_received_note_ids: set[str] = set()

        for block in self.blocks:
            source = {
                "status": "confirmed",
                "height": block.header.height,
                "block_hash": block.header.block_hash(),
            }
            for tx_index, tx in enumerate(block.transactions):
                tx_source = dict(source)
                tx_source["tx_index"] = tx_index
                tx_source["tx_kind"] = tx.public_record().get("kind", "unknown")
                received = self._wallet_received_events(
                    owner_view_key,
                    tx,
                    tx_source,
                    current_note_ids,
                )
                indexed_received_note_ids.update(event["note_id"] for event in received)
                events.extend(received)
                events.extend(self._wallet_spend_events(owner_view_key, tx, tx_source))

        for tx_index, tx in enumerate(self.pending):
            source = {
                "status": "pending",
                "height": None,
                "block_hash": "",
                "tx_index": tx_index,
                "tx_kind": tx.public_record().get("kind", "unknown"),
            }
            received = self._wallet_received_events(
                owner_view_key,
                tx,
                source,
                current_note_ids,
            )
            indexed_received_note_ids.update(event["note_id"] for event in received)
            events.extend(received)
            events.extend(self._wallet_spend_events(owner_view_key, tx, source))

        unindexed_current_notes = [
            note.wallet_record()
            for note in sorted(self.notes.values(), key=lambda item: item.note_id)
            if note.owner_view_key == owner_view_key
            and note.note_id not in indexed_received_note_ids
        ]
        for note in unindexed_current_notes:
            events.append({
                "event": "current_unindexed",
                "status": "current",
                "source": {
                    "status": "state",
                    "height": len(self.blocks),
                    "tx_kind": "state_note",
                },
                "note_id": note["note_id"],
                "asset_id": note["asset_id"],
                "amount": note["amount"],
                "commitment": note["commitment"],
            })

        current_notes = self.wallet_notes(owner_view_key)
        current_totals: Dict[str, int] = {}
        received_totals: Dict[str, int] = {}
        spent_totals: Dict[str, int] = {}
        fee_totals: Dict[str, int] = {}
        for note in current_notes:
            current_totals[note["asset_id"]] = current_totals.get(note["asset_id"], 0) + int(note["amount"])
        for event in events:
            if event["event"] in {"received", "current_unindexed"}:
                received_totals[event["asset_id"]] = received_totals.get(event["asset_id"], 0) + int(event["amount"])
            elif event["event"] == "spent":
                for asset_id, amount in event["asset_amounts"].items():
                    spent_totals[asset_id] = spent_totals.get(asset_id, 0) + int(amount)
                if event["fee_asset_id"] and event["fee_units"]:
                    fee_totals[event["fee_asset_id"]] = fee_totals.get(event["fee_asset_id"], 0) + int(event["fee_units"])

        history = {
            "owner_commitment": domain_hash("VIEW-KEY-COMMITMENT", owner_view_key),
            "height": len(self.blocks),
            "event_count": len(events),
            "current_notes": current_notes,
            "current_totals": dict(sorted(current_totals.items())),
            "received_totals": dict(sorted(received_totals.items())),
            "spent_totals": dict(sorted(spent_totals.items())),
            "fee_totals": dict(sorted(fee_totals.items())),
            "unindexed_current_note_count": len(unindexed_current_notes),
            "events": events,
        }
        history["history_root"] = merkle_root("WALLET-HISTORY", events)
        return history

    def view_key_disclosure(
        self,
        owner_view_key: str,
        audience_label: str,
        asset_id: str = "",
        expires_in_blocks: int = 100,
    ) -> ViewKeyDisclosure:
        if not owner_view_key:
            raise ValueError("owner view key is required")
        if not audience_label:
            raise ValueError("audience label is required")
        if expires_in_blocks <= 0:
            raise ValueError("expires_in_blocks must be positive")
        if asset_id:
            self._require_asset(asset_id)

        notes = [
            note.wallet_record()
            for note in sorted(self.notes.values(), key=lambda item: item.note_id)
            if note.owner_view_key == owner_view_key
            and (not asset_id or note.asset_id == asset_id)
        ]
        asset_totals: Dict[str, int] = {}
        for note in notes:
            asset_totals[note["asset_id"]] = asset_totals.get(note["asset_id"], 0) + int(note["amount"])

        disclosed_at_height = len(self.blocks)
        expires_at_height = disclosed_at_height + expires_in_blocks
        owner_commitment = domain_hash("VIEW-KEY-COMMITMENT", owner_view_key)
        note_commitment_root = merkle_root("VIEW-DISCLOSURE-NOTE", notes)
        disclosure_id = domain_hash(
            "VIEW-KEY-DISCLOSURE-ID",
            CHAIN_ID,
            audience_label,
            owner_commitment,
            asset_id,
            disclosed_at_height,
            expires_at_height,
            note_commitment_root,
            asset_totals,
        )
        unsigned = ViewKeyDisclosure(
            disclosure_id=disclosure_id,
            audience_label=audience_label,
            owner_commitment=owner_commitment,
            asset_id=asset_id,
            disclosed_at_height=disclosed_at_height,
            expires_at_height=expires_at_height,
            note_count=len(notes),
            note_commitment_root=note_commitment_root,
            asset_totals=asset_totals,
            notes=tuple(notes),
        )
        auth = sign_authorization(
            owner_view_key,
            "view_key_disclosure",
            unsigned.unsigned_record(),
        )
        return replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )

    def verify_view_key_disclosure(self, record: Dict[str, Any]) -> bool:
        owner_view_key = record.get("disclosed_view_key", "")
        if not owner_view_key:
            raise ValueError("view key disclosure is missing disclosed view key")
        disclosure = ViewKeyDisclosure.from_record(record)
        if len(self.blocks) > disclosure.expires_at_height:
            raise ValueError("view key disclosure expired")
        if disclosure.owner_commitment != domain_hash("VIEW-KEY-COMMITMENT", owner_view_key):
            raise ValueError("view key disclosure owner mismatch")
        notes = list(disclosure.notes)
        if disclosure.note_count != len(notes):
            raise ValueError("view key disclosure note count mismatch")
        if disclosure.note_commitment_root != merkle_root("VIEW-DISCLOSURE-NOTE", notes):
            raise ValueError("view key disclosure note root mismatch")
        totals: Dict[str, int] = {}
        for item in notes:
            note_id = item["note_id"]
            if note_id not in self.notes:
                raise ValueError("view key disclosure note is not current")
            note = self.notes[note_id]
            if note.owner_view_key != owner_view_key:
                raise ValueError("view key disclosure note owner mismatch")
            if disclosure.asset_id and note.asset_id != disclosure.asset_id:
                raise ValueError("view key disclosure asset mismatch")
            if note.wallet_record() != item:
                raise ValueError("view key disclosure note mismatch")
            totals[item["asset_id"]] = totals.get(item["asset_id"], 0) + int(item["amount"])
        if dict(sorted(totals.items())) != dict(sorted(disclosure.asset_totals.items())):
            raise ValueError("view key disclosure totals mismatch")
        if not verify_authorization(
            owner_view_key,
            "view_key_disclosure",
            disclosure.unsigned_record(),
            disclosure.auth_scheme,
            disclosure.auth_public_key,
            disclosure.auth_transcript_hash,
            disclosure.auth_signature,
        ):
            raise ValueError("invalid view key disclosure authorization")
        return True

    def _contract_storage_path_value(
        self,
        storage: Dict[str, Any],
        path: str,
    ) -> Any:
        if not path:
            raise ValueError("contract storage disclosure path is required")
        current: Any = storage
        for part in path.split("."):
            if not part:
                raise ValueError("contract storage disclosure path is invalid")
            if isinstance(current, dict) and part in current:
                current = current[part]
            else:
                raise ValueError("unknown contract storage path")
        return current

    def _contract_storage_opening(
        self,
        contract_id: str,
        storage: Dict[str, Any],
        path: str,
    ) -> Dict[str, Any]:
        value = self._contract_storage_path_value(storage, path)
        return {
            "path": path,
            "path_hash": domain_hash("CONTRACT-STORAGE-PATH", contract_id, path),
            "value_hash": domain_hash("CONTRACT-STORAGE-VALUE", value),
            "value": value,
        }

    def contract_storage_disclosure(
        self,
        contract_id: str,
        owner_label: str,
        audience_label: str,
        paths: Sequence[str],
        expires_in_blocks: int = 100,
    ) -> ContractStorageDisclosure:
        contract = self._require_contract(contract_id)
        if owner_label != contract.owner_label:
            raise ValueError("only the contract owner can disclose storage")
        if not audience_label:
            raise ValueError("audience label is required")
        if not paths:
            raise ValueError("contract storage disclosure requires at least one path")
        if len(set(paths)) != len(paths):
            raise ValueError("duplicate contract storage disclosure path")
        if expires_in_blocks <= 0:
            raise ValueError("expires_in_blocks must be positive")

        openings = tuple(
            self._contract_storage_opening(contract_id, contract.storage, path)
            for path in paths
        )
        disclosed_at_height = len(self.blocks)
        expires_at_height = disclosed_at_height + expires_in_blocks
        owner_commitment = domain_hash("CONTRACT-STORAGE-DISCLOSER", owner_label)
        opening_root = merkle_root("CONTRACT-STORAGE-OPENING", openings)
        disclosure_id = domain_hash(
            "CONTRACT-STORAGE-DISCLOSURE-ID",
            CHAIN_ID,
            audience_label,
            contract_id,
            owner_commitment,
            contract.storage_root(),
            disclosed_at_height,
            expires_at_height,
            opening_root,
        )
        unsigned = ContractStorageDisclosure(
            disclosure_id=disclosure_id,
            audience_label=audience_label,
            contract_id=contract_id,
            owner_commitment=owner_commitment,
            storage_root=contract.storage_root(),
            disclosed_at_height=disclosed_at_height,
            expires_at_height=expires_at_height,
            path_count=len(openings),
            opening_root=opening_root,
            openings=openings,
        )
        auth = sign_authorization(
            owner_label,
            "contract_storage_disclosure",
            unsigned.unsigned_record(),
        )
        return replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )

    def verify_contract_storage_disclosure(self, record: Dict[str, Any]) -> bool:
        owner_label = record.get("disclosed_owner_label", "")
        if not owner_label:
            raise ValueError("contract storage disclosure is missing disclosed owner")
        disclosure = ContractStorageDisclosure.from_record(record)
        if len(self.blocks) > disclosure.expires_at_height:
            raise ValueError("contract storage disclosure expired")
        contract = self._require_contract(disclosure.contract_id)
        if owner_label != contract.owner_label:
            raise ValueError("contract storage disclosure owner mismatch")
        if disclosure.owner_commitment != domain_hash("CONTRACT-STORAGE-DISCLOSER", owner_label):
            raise ValueError("contract storage disclosure owner mismatch")
        if disclosure.storage_root != contract.storage_root():
            raise ValueError("contract storage disclosure root mismatch")
        openings = list(disclosure.openings)
        if disclosure.path_count != len(openings):
            raise ValueError("contract storage disclosure path count mismatch")
        if disclosure.opening_root != merkle_root("CONTRACT-STORAGE-OPENING", openings):
            raise ValueError("contract storage disclosure opening root mismatch")
        for opening in openings:
            expected = self._contract_storage_opening(
                disclosure.contract_id,
                contract.storage,
                opening["path"],
            )
            if opening != expected:
                raise ValueError("contract storage disclosure opening mismatch")
        if not verify_authorization(
            owner_label,
            "contract_storage_disclosure",
            disclosure.unsigned_record(),
            disclosure.auth_scheme,
            disclosure.auth_public_key,
            disclosure.auth_transcript_hash,
            disclosure.auth_signature,
        ):
            raise ValueError("invalid contract storage disclosure authorization")
        return True

    def _private_contract_event_source(self, event: ContractEvent) -> Dict[str, Any]:
        for block in self.blocks:
            for tx in block.transactions:
                if isinstance(tx, ContractCall):
                    tx_hash = domain_hash("CONTRACT-CALL-TX", tx.public_record())
                    if tx_hash != event.tx_hash:
                        continue
                    if tx.contract_id != event.contract_id:
                        raise ValueError("contract event source contract mismatch")
                    if not tx.private_args:
                        raise ValueError("contract event has no private args to disclose")
                    return {
                        "kind": "contract_call",
                        "block_height": block.header.height,
                        "call_index": 0,
                        "signer_label": tx.signer_label,
                        "contract_id": tx.contract_id,
                        "entrypoint": tx.entrypoint,
                        "args": dict(tx.args),
                        "args_commitment": tx.args_commitment(),
                    }
                if isinstance(tx, ContractCallBatch):
                    batch_public_record = tx.public_record()
                    for index, action in enumerate(tx.calls):
                        tx_hash = domain_hash(
                            "CONTRACT-CALL-BATCH-TX",
                            batch_public_record,
                            index,
                        )
                        if tx_hash != event.tx_hash:
                            continue
                        if action.contract_id != event.contract_id:
                            raise ValueError("contract event source contract mismatch")
                        if not action.private_args:
                            raise ValueError("contract event has no private args to disclose")
                        return {
                            "kind": "contract_call_batch",
                            "block_height": block.header.height,
                            "call_index": index,
                            "signer_label": tx.signer_label,
                            "contract_id": action.contract_id,
                            "entrypoint": action.entrypoint,
                            "args": dict(action.args),
                            "args_commitment": action.args_commitment(),
                        }
        raise ValueError("contract event source transaction not found")

    def contract_event_disclosure(
        self,
        event_id: str,
        signer_label: str,
        audience_label: str,
        expires_in_blocks: int = 100,
    ) -> ContractEventDisclosure:
        if event_id not in self.contract_events:
            raise ValueError("unknown contract event")
        if not audience_label:
            raise ValueError("audience label is required")
        if expires_in_blocks <= 0:
            raise ValueError("expires_in_blocks must be positive")
        event = self.contract_events[event_id]
        public_data = dict(event.public_data)
        if not public_data.get("private_args"):
            raise ValueError("contract event has no private args to disclose")
        source = self._private_contract_event_source(event)
        if signer_label != source["signer_label"]:
            raise ValueError("only the event signer can disclose private event args")
        caller_commitment = domain_hash("CONTRACT-CALLER", signer_label)
        if public_data.get("caller_commitment") != caller_commitment:
            raise ValueError("contract event caller commitment mismatch")
        if public_data.get("args_commitment") != source["args_commitment"]:
            raise ValueError("contract event args commitment mismatch")

        opening = {
            "kind": source["kind"],
            "block_height": source["block_height"],
            "call_index": source["call_index"],
            "entrypoint": source["entrypoint"],
            "args": source["args"],
            "args_commitment": source["args_commitment"],
            "caller_commitment": caller_commitment,
            "private_args": True,
        }
        opening_root = domain_hash("CONTRACT-EVENT-OPENING", event.event_id, opening)
        expires_at_height = len(self.blocks) + expires_in_blocks
        disclosure_id = domain_hash(
            "CONTRACT-EVENT-DISCLOSURE-ID",
            CHAIN_ID,
            audience_label,
            event.event_id,
            event.contract_id,
            event.tx_hash,
            event.data_hash,
            caller_commitment,
            expires_at_height,
            opening_root,
        )
        unsigned = ContractEventDisclosure(
            disclosure_id=disclosure_id,
            audience_label=audience_label,
            event_id=event.event_id,
            contract_id=event.contract_id,
            event_name=event.event_name,
            tx_hash=event.tx_hash,
            data_hash=event.data_hash,
            emitted_at_height=event.emitted_at_height,
            expires_at_height=expires_at_height,
            caller_commitment=caller_commitment,
            args_commitment=source["args_commitment"],
            opening_root=opening_root,
            opening=opening,
        )
        auth = sign_authorization(
            signer_label,
            "contract_event_disclosure",
            unsigned.unsigned_record(),
        )
        return replace(
            unsigned,
            auth_scheme=auth["auth_scheme"],
            auth_public_key=auth["auth_public_key"],
            auth_transcript_hash=auth["auth_transcript_hash"],
            auth_signature=auth["auth_signature"],
        )

    def verify_contract_event_disclosure(self, record: Dict[str, Any]) -> bool:
        signer_label = record.get("disclosed_signer_label", "")
        if not signer_label:
            raise ValueError("contract event disclosure is missing disclosed signer")
        disclosure = ContractEventDisclosure.from_record(record)
        if len(self.blocks) > disclosure.expires_at_height:
            raise ValueError("contract event disclosure expired")
        if disclosure.event_id not in self.contract_events:
            raise ValueError("unknown contract event")
        event = self.contract_events[disclosure.event_id]
        if disclosure.contract_id != event.contract_id:
            raise ValueError("contract event disclosure contract mismatch")
        if disclosure.event_name != event.event_name:
            raise ValueError("contract event disclosure event name mismatch")
        if disclosure.tx_hash != event.tx_hash:
            raise ValueError("contract event disclosure tx mismatch")
        if disclosure.data_hash != event.data_hash:
            raise ValueError("contract event disclosure data mismatch")
        if disclosure.emitted_at_height != event.emitted_at_height:
            raise ValueError("contract event disclosure height mismatch")

        public_data = dict(event.public_data)
        if not public_data.get("private_args"):
            raise ValueError("contract event has no private args to disclose")
        caller_commitment = domain_hash("CONTRACT-CALLER", signer_label)
        if disclosure.caller_commitment != caller_commitment:
            raise ValueError("contract event disclosure caller mismatch")
        if public_data.get("caller_commitment") != disclosure.caller_commitment:
            raise ValueError("contract event caller commitment mismatch")
        if public_data.get("args_commitment") != disclosure.args_commitment:
            raise ValueError("contract event args commitment mismatch")

        opening = dict(disclosure.opening)
        if disclosure.opening_root != domain_hash(
            "CONTRACT-EVENT-OPENING",
            event.event_id,
            opening,
        ):
            raise ValueError("contract event disclosure opening root mismatch")
        source = self._private_contract_event_source(event)
        if signer_label != source["signer_label"]:
            raise ValueError("contract event disclosure signer mismatch")
        expected_opening = {
            "kind": source["kind"],
            "block_height": source["block_height"],
            "call_index": source["call_index"],
            "entrypoint": source["entrypoint"],
            "args": source["args"],
            "args_commitment": source["args_commitment"],
            "caller_commitment": caller_commitment,
            "private_args": True,
        }
        if opening != expected_opening:
            raise ValueError("contract event disclosure opening mismatch")
        if disclosure.args_commitment != source["args_commitment"]:
            raise ValueError("contract event disclosure args mismatch")
        if not verify_authorization(
            signer_label,
            "contract_event_disclosure",
            disclosure.unsigned_record(),
            disclosure.auth_scheme,
            disclosure.auth_public_key,
            disclosure.auth_transcript_hash,
            disclosure.auth_signature,
        ):
            raise ValueError("invalid contract event disclosure authorization")
        return True

