    if args.command == "anchor":
        net = load_state(args.state)
        print_json({
            "anchor_commitment": net.anchor_commitment(),
            "anchor_submission_count": len(net.anchor_submissions),
            "anchor_submission_root": net.anchor_submission_root(),
        })
        return

    if args.command == "settlement":
        net = load_state(args.state)
        print_json(net.settlement_status(args.block_height))
        return

    if args.command == "epoch-checkpoint":
        net = load_state(args.state)
        if args.block_height is not None:
            checkpoint = net.epoch_checkpoint_for_block(args.block_height)
        else:
            checkpoint = net.epoch_checkpoint(epoch=args.epoch)
        print_json(checkpoint.anchor_record())
        return

    if args.command == "anchor-submit":
        net = load_state(args.state)
        submission = net.submit_anchor(
            block_height=args.block_height,
            submitter_label=args.submitter,
            monero_txid=args.monero_txid,
        )
        save_state(args.state, net)
        print_json(submission.public_record())
        return

    if args.command == "anchor-confirm":
        net = load_state(args.state)
        submission = net.confirm_anchor(
            anchor_id=args.anchor_id,
            confirmations=args.confirmations,
            finality_depth=args.finality_depth,
        )
        save_state(args.state, net)
        print_json(submission.public_record())
        return

